import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export async function getFinancialMotivation(balance: number, goal: string, target: number): Promise<string> {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a friendly financial coach for a gamified savings app called Piggybanko. 
      A user named Valentina has $${balance} saved towards her goal: "${goal}" (Target: $${target}). 
      Give her a short, 1-sentence motivational message in Spanish about how her small change is making a big difference. 
      Keep it energetic and mention her "Piggy".`,
    });
    return response.text || "¡Sigue ahorrando, tu Piggy está muy feliz hoy!";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "¡Cada moneda cuenta! Estás más cerca de tu meta.";
  }
}

export async function getMerchantInsight(earnings: number, sales: number): Promise<string> {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a business consultant for a shop owner named Don Roberto. 
      He earned $${earnings} in commissions and had $${sales} in sales via the Piggybanko app. 
      Write a 1-sentence congratulatory message in Spanish about how this digital system is improving his business cash flow.`,
    });
    return response.text || "¡Excelente cierre! Tu flujo de caja es más sano con Piggybanko.";
  } catch (error) {
    return "Tu negocio está creciendo con el ecosistema digital.";
  }
}

import React from 'react';
import { LEVELS } from '../constants';

interface MascotProps {
  level: number;
  isHappy: boolean;
}

const Mascot: React.FC<MascotProps> = ({ level, isHappy }) => {
  const currentLevel = LEVELS[Math.min(level, LEVELS.length - 1)];

  return (
    <div className="flex flex-col items-center justify-center p-8 bg-white rounded-3xl shadow-sm border border-pink-50 relative overflow-hidden">
      <div className="absolute top-0 right-0 p-2 text-xs font-bold text-pink-400 opacity-20 rotate-12">
        8-BIT STYLE
      </div>

      <div className={`text-8xl transition-transform duration-500 ${isHappy ? 'scale-110 animate-bounce' : 'scale-100'}`}>
        {currentLevel.visual}
      </div>

      <div className="mt-4 text-center">
        <h3 className="text-xl font-bold text-slate-800">{currentLevel.name}</h3>
        <p className="text-sm text-slate-500">Nivel {level + 1}</p>
      </div>

      {level >= 1 && (
        <div className="absolute top-1/4 left-1/4 animate-pulse">
            <span className="text-2xl">✨</span>
        </div>
      )}
    </div>
  );
};

export default Mascot;

import React, { useState, useEffect } from 'react';
import { UserAccount, Transaction } from '../types';
import Mascot from './Mascot';
import { getFinancialMotivation } from '../services/geminiService';
import { COLORS } from '../constants';

interface UserViewProps {
  user: UserAccount;
}

const UserView: React.FC<UserViewProps> = ({ user }) => {
  const [motivation, setMotivation] = useState("Cargando motivación...");
  const [history] = useState<Transaction[]>([
    { id: '1', type: 'SAVING', amount: 350, description: 'Cambio Tienda Don Roberto', timestamp: '2024-05-10 12:00' },
    { id: '2', type: 'YIELD', amount: 5, description: 'Rendimiento diario (50%)', timestamp: '2024-05-10 00:00' },
    { id: '3', type: 'PAYMENT', amount: -2000, description: 'Pago Panadería El Trigal', timestamp: '2024-05-09 18:30' },
  ]);

  useEffect(() => {
    async function fetchMotivation() {
      const msg = await getFinancialMotivation(user.balance, user.goalName, user.goalTarget);
      setMotivation(msg);
    }
    fetchMotivation();
  }, [user.balance, user.goalName, user.goalTarget]);

  const progress = (user.balance / user.goalTarget) * 100;

  return (
    <div className="max-w-md mx-auto space-y-6 pb-24 px-4">
      {/* Balance Card */}
      <div className="bg-[#1A1A40] text-white p-6 rounded-3xl shadow-xl relative overflow-hidden">
        <div className="absolute -top-10 -right-10 w-40 h-40 bg-pink-500 rounded-full blur-3xl opacity-20"></div>
        <p className="text-sm opacity-70 mb-1">Saldo disponible</p>
        <h2 className="text-4xl font-bold mb-4">${user.balance.toLocaleString()} <span className="text-lg font-normal opacity-60">COP</span></h2>
        <div className="flex items-center gap-2 bg-white/10 p-2 rounded-xl text-xs">
          <span className="text-[#CCFF00] font-bold">📈 Rendimiento hoy: +${user.lastYield}</span>
          <span className="opacity-60">(Tu 50% del total)</span>
        </div>
      </div>

      {/* Mascot Section */}
      <Mascot level={user.level} isHappy={true} />

      {/* Motivation Bubble */}
      <div className="bg-pink-50 border-l-4 border-[#FF007F] p-4 rounded-r-xl">
        <p className="text-sm text-[#1A1A40] italic">"{motivation}"</p>
      </div>

      {/* Goal Progress */}
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
        <div className="flex justify-between items-center mb-4">
          <h3 className="font-bold text-slate-800">Meta: {user.goalName}</h3>
          <span className="text-[#FF007F] font-bold">{Math.round(progress)}%</span>
        </div>
        <div className="w-full bg-slate-100 h-3 rounded-full overflow-hidden">
          <div 
            className="bg-gradient-to-r from-pink-500 to-rose-400 h-full transition-all duration-1000"
            style={{ width: `${Math.min(progress, 100)}%` }}
          ></div>
        </div>
        <p className="text-xs text-slate-500 mt-2">Faltan ${(user.goalTarget - user.balance).toLocaleString()} para tu meta</p>
      </div>

      {/* Action Buttons */}
      <div className="grid grid-cols-2 gap-4">
        <button className="flex flex-col items-center justify-center gap-2 p-4 bg-[#CCFF00] text-[#1A1A40] rounded-2xl font-bold shadow-md active:scale-95 transition-transform">
          <i className="fa-solid fa-qrcode text-xl"></i>
          PAGAR
        </button>
        <button className="flex flex-col items-center justify-center gap-2 p-4 bg-white text-[#1A1A40] border border-slate-200 rounded-2xl font-bold shadow-sm active:scale-95 transition-transform">
          <i className="fa-solid fa-building-columns text-xl"></i>
          RECARGAR
        </button>
      </div>

      {/* History */}
      <div className="space-y-3">
        <h3 className="font-bold text-slate-800">Movimientos recientes</h3>
        {history.map(tx => (
          <div key={tx.id} className="bg-white p-4 rounded-2xl flex items-center justify-between border border-slate-50">
            <div className="flex items-center gap-3">
              <div className={`w-10 h-10 rounded-full flex items-center justify-center ${
                tx.type === 'SAVING' ? 'bg-green-100 text-green-600' : 
                tx.type === 'PAYMENT' ? 'bg-red-100 text-red-600' : 'bg-blue-100 text-blue-600'
              }`}>
                <i className={`fa-solid ${
                  tx.type === 'SAVING' ? 'fa-arrow-down' : 
                  tx.type === 'PAYMENT' ? 'fa-arrow-up' : 'fa-chart-line'
                }`}></i>
              </div>
              <div>
                <p className="text-sm font-semibold">{tx.description}</p>
                <p className="text-[10px] text-slate-400">{tx.timestamp}</p>
              </div>
            </div>
            <span className={`font-bold ${tx.amount > 0 ? 'text-green-600' : 'text-slate-800'}`}>
              {tx.amount > 0 ? '+' : ''}${Math.abs(tx.amount).toLocaleString()}
            </span>
          </div>
        ))}
      </div>
    </div>
  );
};

export default UserView;

import React, { useState, useEffect } from 'react';
import { MerchantAccount } from '../types';
import { getMerchantInsight } from '../services/geminiService';
