      setInsight(msg);
    }
    fetchInsight();
  }, [merchant.earnings, merchant.cashCollected]);

  const totalToTransfer = merchant.cashCollected - merchant.piggyPayments;
  const quotaPercentage = (merchant.quotaUsed / merchant.quotaLimit) * 100;

  const data = [
    { name: 'Recaudo', value: merchant.cashCollected, color: '#10b981' },
    { name: 'Pagos', value: merchant.piggyPayments, color: '#ef4444' },
    { name: 'Neto', value: totalToTransfer, color: '#3b82f6' }
