  return (
    <div className="max-w-md mx-auto space-y-6 pb-24 px-4">
      {/* Header */}
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-xl font-bold text-slate-800">Hola, Don Roberto</h2>
          <span className="text-xs bg-amber-100 text-amber-700 px-2 py-0.5 rounded-full font-bold">SOCIO ORO 🌟</span>
        </div>
        <div className="text-right">
          <p className="text-xs text-slate-400">Viernes, 02 Ene</p>
        </div>
      </div>

      {/* Main Stats */}
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 space-y-4">
        <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider">Resumen de Caja (Hoy)</h3>

        <div className="space-y-4">
          <div className="flex justify-between items-center">
            <span className="text-slate-600">1. Tu Recaudo en Efectivo</span>
            <span className="font-bold text-lg">${merchant.cashCollected.toLocaleString()}</span>
