          <div className="h-px bg-slate-100 w-full"></div>
          <div className="flex justify-between items-center bg-slate-50 p-4 rounded-2xl">
            <span className="font-bold text-slate-800">Total a transferir</span>
            <span className="font-extrabold text-2xl text-[#1A1A40]">${totalToTransfer.toLocaleString()}</span>
          </div>
        </div>

        <div className="bg-red-50 text-red-600 p-3 rounded-xl flex items-center gap-3 text-sm">
          <i className="fa-solid fa-circle-exclamation"></i>
          <span>Estado: Pendiente de cierre</span>
        </div>
      </div>

      {/* Earnings Card */}
      <div className="bg-emerald-600 text-white p-6 rounded-3xl shadow-lg relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4 opacity-10 text-6xl">
           <i className="fa-solid fa-coins"></i>
        </div>
        <p className="text-sm opacity-80">Tus ganancias del mes</p>
        <h2 className="text-3xl font-bold mt-1">${merchant.earnings.toLocaleString()}</h2>
        <div className="mt-4 pt-4 border-t border-white/20 grid grid-cols-2 gap-2 text-[10px]">
          <div>
            <p className="opacity-70">Ahorro Operativo</p>
            <p className="font-bold">$45.000</p>
          </div>
          <div>
            <p className="opacity-70">Regalías Financieras</p>
            <p className="font-bold text-[#CCFF00]">$12.500</p>
