import React from 'react';
import { Product } from '../types';

interface MarketplaceViewProps {
  products: Product[];
  userBalance: number;
}

const MarketplaceView: React.FC<MarketplaceViewProps> = ({ products, userBalance }) => {
  return (
    <div className="max-w-md mx-auto space-y-6 pb-24 px-4">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800">Marketplace</h2>
        <div className="bg-white px-3 py-1 rounded-full shadow-sm border border-slate-100 flex items-center gap-2">
          <i className="fa-solid fa-filter text-slate-400 text-xs"></i>
          <span className="text-xs font-bold text-slate-600">Filtros</span>
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4">
        {products.map((product) => {
          const canAfford = userBalance >= product.price;
          return (
            <div key={product.id} className="bg-white rounded-3xl p-3 shadow-sm border border-slate-100 flex flex-col h-full relative overflow-hidden">
