import React, { useState } from 'react';
import { Product } from '../types';

interface MerchantInventoryProps {
  products: Product[];
  onAddProduct: (product: Omit<Product, 'id' | 'merchantId' | 'merchantName'>) => void;
}

const MerchantInventory: React.FC<MerchantInventoryProps> = ({ products, onAddProduct }) => {
  const [showForm, setShowForm] = useState(false);
  const [name, setName] = useState('');
  const [price, setPrice] = useState('');
  const [category, setCategory] = useState('Alimentos');
  const [emoji, setEmoji] = useState('📦');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !price) return;

    onAddProduct({
      name,
      price: parseFloat(price),
      category,
      imageUrl: emoji,
    });

    // Reset form
    setName('');
    setPrice('');
    setCategory('Alimentos');
    setEmoji('📦');
    setShowForm(false);
  };

  return (
    <div className="max-w-md mx-auto space-y-6 pb-24 px-4">
      <div className="flex justify-between items-center">
        <h2 className="text-xl font-bold text-slate-800">Mis Productos</h2>
        <button 
          onClick={() => setShowForm(!showForm)}
          className="bg-[#FF007F] text-white px-4 py-2 rounded-xl text-xs font-bold shadow-md flex items-center gap-2 transition-all active:scale-95"
        >
          <i className={`fa-solid ${showForm ? 'fa-times' : 'fa-plus'}`}></i>
          {showForm ? 'Cerrar' : 'Publicar Nuevo'}
        </button>
      </div>

      {showForm && (
        <form onSubmit={handleSubmit} className="bg-white p-6 rounded-3xl shadow-xl border border-pink-100 space-y-4 animate-fadeIn">
          <h3 className="font-bold text-slate-800">Detalles del Producto</h3>
          <div className="space-y-3">
            <div>
              <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Nombre</label>
              <input 
                type="text" 
                placeholder="Ej. Pan Tajado" 
                value={name}
                onChange={(e) => setName(e.target.value)}
                className="w-full p-3 bg-slate-50 rounded-xl text-sm border-none focus:ring-2 focus:ring-pink-400 transition-all outline-none" 
                required
              />
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Precio ($)</label>
                <input 
                  type="number" 
                  placeholder="0.00" 
                  value={price}
                  onChange={(e) => setPrice(e.target.value)}
                  className="w-full p-3 bg-slate-50 rounded-xl text-sm border-none focus:ring-2 focus:ring-pink-400 transition-all outline-none" 
                  required
                />
              </div>
              <div>
                <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Categoría</label>
                <select 
                  value={category}
                  onChange={(e) => setCategory(e.target.value)}
                  className="w-full p-3 bg-slate-50 rounded-xl text-sm border-none focus:ring-2 focus:ring-pink-400 transition-all outline-none"
                >
                  <option>Alimentos</option>
                  <option>Aseo</option>
                  <option>Snacks</option>
                  <option>Tecno</option>
                </select>
              </div>
            </div>

            <div>
              <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Icono/Emoji representativo</label>
              <input 
                type="text" 
                placeholder="Ej. 🍞" 
                value={emoji}
                onChange={(e) => setEmoji(e.target.value)}
                className="w-full p-3 bg-slate-50 rounded-xl text-sm border-none focus:ring-2 focus:ring-pink-400 transition-all outline-none" 
                maxLength={2}
              />
            </div>

            <button type="submit" className="w-full py-3 bg-[#1A1A40] text-white rounded-xl font-bold shadow-lg shadow-blue-900/20 active:scale-95 transition-all">
              PUBLICAR EN MARKETPLACE
            </button>
          </div>
        </form>
      )}

      <div className="space-y-3">
