          <div className="text-center py-10 text-slate-400 italic text-sm">
            No has publicado productos todavía.
          </div>
        ) : (
          products.map(p => (
            <div key={p.id} className="bg-white p-4 rounded-3xl shadow-sm border border-slate-100 flex items-center justify-between">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-slate-50 rounded-2xl flex items-center justify-center text-2xl">
                  {p.imageUrl}
                </div>
                <div>
