interface MerchantViewProps {
  merchant: MerchantAccount;
}

const MerchantView: React.FC<MerchantViewProps> = ({ merchant }) => {
  const [insight, setInsight] = useState("Analizando tu crecimiento...");
  const [isConciliating, setIsConciliating] = useState(false);
  const [isCashierMode, setIsCashierMode] = useState(false);

  // Constants for math (simulated)
  const COMMISSION_RATE = 0.035; // 3.5% fee for digital sales
  const COLLECTION_INCENTIVE = 0.01; // 1% merchant earns for collecting cash

  useEffect(() => {
    async function fetchInsight() {
      const msg = await getMerchantInsight(merchant.earnings, merchant.cashCollected);
      setInsight(msg);
    }
    fetchInsight();
  }, [merchant.earnings, merchant.cashCollected]);

  if (isCashierMode) {
    return (
      <div className="animate-fadeIn">
        <button 
          onClick={() => setIsCashierMode(false)}
          className="absolute top-8 right-8 z-[110] bg-white w-10 h-10 rounded-full shadow-lg flex items-center justify-center text-[#1A1A40]"
        >
          <i className="fa-solid fa-xmark"></i>
        </button>
        <CashierView merchantName={merchant.name} />
      </div>
    );
  }

  // Calculations for "Cruce de Cuentas"
  const grossDigitalSales = merchant.piggyPayments;
  const systemCommission = grossDigitalSales * COMMISSION_RATE;
  const netDigitalSales = grossDigitalSales - systemCommission;

  const grossCashCollected = merchant.cashCollected;
  const collectionIncentiveAmount = grossCashCollected * COLLECTION_INCENTIVE;
  const netCashToPiggy = grossCashCollected - collectionIncentiveAmount;

  // Final Settlement: What actually moves between bank accounts
  const finalBalance = netCashToPiggy - netDigitalSales;
  const merchantOwesPiggy = finalBalance > 0;

  // Data for visual charts
  const settlementData = [
    { name: 'Ventas Netas', value: netDigitalSales, color: '#FF007F' },
    { name: 'Recaudo Neto', value: netCashToPiggy, color: '#CCFF00' },
  ];

  const handleConciliate = () => {
    setIsConciliating(true);
    setTimeout(() => {
      setIsConciliating(false);
      alert("Cierre de caja enviado. Esperando validación del sistema.");
    }, 2000);
  };

  return (
    <div className="max-w-md mx-auto space-y-6 pb-32 px-4 animate-fadeIn">
      {/* Quick Access to Cashier Mode */}
      <button 
        onClick={() => setIsCashierMode(true)}
        className="w-full p-6 bg-[#CCFF00] text-[#1A1A40] rounded-[2.5rem] font-black shadow-xl flex items-center justify-between border-b-8 border-[#99CC00] active:scale-95 transition-all"
      >
        <div className="flex items-center gap-4">
           <div className="w-12 h-12 bg-[#1A1A40] rounded-2xl flex items-center justify-center text-white text-xl">
             <i className="fa-solid fa-cash-register"></i>
           </div>
           <div className="text-left">
             <span className="text-xs uppercase tracking-tight block">Terminal de Caja</span>
             <span className="text-[10px] opacity-60">Captura nuevos clientes hoy</span>
           </div>
        </div>
        <i className="fa-solid fa-chevron-right text-sm"></i>
      </button>

      {/* Header */}
      <div className="flex justify-between items-start">
        <div>
          <h2 className="text-2xl font-black text-[#1A1A40] tracking-tighter uppercase italic">Panel de Control</h2>
          <div className="flex items-center gap-2 mt-1">
             <span className="text-[10px] bg-[#1A1A40] text-[#CCFF00] px-2 py-0.5 rounded-full font-black uppercase">TIENDA ACTIVA ⚡</span>
             <span className="text-[10px] text-slate-400 font-bold uppercase">{merchant.name}</span>
          </div>
        </div>
        <button className="w-10 h-10 bg-white rounded-2xl shadow-sm flex items-center justify-center text-slate-400 border border-slate-100">
          <i className="fa-solid fa-bell"></i>
        </button>
