          <i className="fa-solid fa-scale-balanced text-7xl text-white"></i>
        </div>

        <div className="relative z-10 space-y-6">
          <div className="flex justify-between items-center">
             <h3 className="text-xs font-black text-white/60 uppercase tracking-[0.2em]">Cruce de Cuentas</h3>
             <span className="text-[9px] font-black text-[#CCFF00] bg-white/5 px-3 py-1 rounded-full border border-white/10">CORTE: HOY 23:59</span>
          </div>

          <div className="grid grid-cols-2 gap-4">
