import React, { useState } from 'react';

interface CashierViewProps {
  merchantName: string;
  onProcessSaving: (phone: string, amount: number) => void;
}

type Step = 'PHONE' | 'OTP' | 'AMOUNT' | 'SUCCESS';

const CashierView: React.FC<CashierViewProps> = ({ merchantName, onProcessSaving }) => {
  const [step, setStep] = useState<Step>('PHONE');
  const [phone, setPhone] = useState('');
  const [otp, setOtp] = useState('');
  const [amount, setAmount] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleKeypad = (val: string) => {
    if (step === 'PHONE' && phone.length < 10) setPhone(prev => prev + val);
    if (step === 'OTP' && otp.length < 4) setOtp(prev => prev + val);
    if (step === 'AMOUNT') setAmount(prev => prev + val);
  };

  const handleBackspace = () => {
    if (step === 'PHONE') setPhone(prev => prev.slice(0, -1));
    if (step === 'OTP') setOtp(prev => prev.slice(0, -1));
    if (step === 'AMOUNT') setAmount(prev => prev.slice(0, -1));
  };

  const nextStep = () => {
    setIsLoading(true);
    setTimeout(() => {
      setIsLoading(false);

      if (step === 'PHONE') {
        setStep('OTP');
      } else if (step === 'OTP') {
        setStep('AMOUNT');
      } else if (step === 'AMOUNT') {
        // PROCESAR TRANSACCIÓN REAL ANTES DE ÉXITO
        onProcessSaving(phone, parseInt(amount));
        setStep('SUCCESS');
      }
    }, 1200);
  };

  const reset = () => {
    setStep('PHONE');
    setPhone('');
    setOtp('');
    setAmount('');
  };

  return (
    <div className="max-w-md mx-auto min-h-[80vh] bg-[#f8fafc] flex flex-col animate-fadeIn">
      {/* Header Fijo para el Cajero */}
      <div className="p-6 bg-[#1A1A40] text-white flex justify-between items-center rounded-b-[2.5rem] shadow-xl">
        <div>
          <p className="text-[10px] font-black uppercase tracking-widest text-[#CCFF00]">Terminal de Caja</p>
          <h2 className="text-xl font-black italic uppercase tracking-tighter">{merchantName}</h2>
        </div>
        <div className="w-10 h-10 bg-white/10 rounded-xl flex items-center justify-center">
          <i className="fa-solid fa-calculator text-[#CCFF00]"></i>
        </div>
      </div>

      <div className="flex-1 p-6 flex flex-col">
        {step !== 'SUCCESS' && (
          <div className="flex justify-between mb-8">
            {['PHONE', 'OTP', 'AMOUNT'].map((s, idx) => (
              <div key={s} className="flex flex-col items-center gap-2">
                <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-black border-2 transition-all ${
                  step === s ? 'bg-[#FF007F] border-[#FF007F] text-white' : 'bg-white border-slate-200 text-slate-300'
                }`}>
                  {idx + 1}
                </div>
                <span className={`text-[8px] font-black uppercase tracking-widest ${step === s ? 'text-[#1A1A40]' : 'text-slate-300'}`}>
                  {s === 'PHONE' ? 'Celular' : s === 'OTP' ? 'Validar' : 'Vueltas'}
                </span>
              </div>
            ))}
          </div>
        )}

        <div className="flex-1 flex flex-col justify-center">
          {step === 'PHONE' && (
            <div className="space-y-6 animate-fadeIn">
              <div className="text-center space-y-2">
                <h3 className="text-2xl font-black text-[#1A1A40] italic uppercase">Nuevo Registro</h3>
                <p className="text-xs text-slate-400 font-medium">Ingresa el celular del cliente para digitalizar su cambio.</p>
              </div>
              <div className="bg-white p-6 rounded-[2.5rem] border-2 border-slate-100 shadow-sm">
                <div className="flex items-center gap-4 text-3xl font-black text-[#1A1A40]">
                  <span className="text-slate-200">+57</span>
                  <div className="flex-1 h-12 flex items-center tracking-[0.2em]">
                    {phone || <span className="text-slate-100">3XX XXX XXXX</span>}
                  </div>
                </div>
              </div>
            </div>
          )}

          {step === 'OTP' && (
            <div className="space-y-6 animate-fadeIn">
              <div className="text-center space-y-2">
                <h3 className="text-2xl font-black text-[#1A1A40] italic uppercase">Verificación SMS</h3>
                <p className="text-xs text-slate-400 font-medium">Enviamos un código al celular <b>{phone}</b></p>
              </div>
              <div className="flex justify-center gap-4">
                {[0, 1, 2, 3].map(i => (
                  <div key={i} className={`w-14 h-16 bg-white rounded-2xl border-2 flex items-center justify-center text-2xl font-black transition-all ${
                    otp[i] ? 'border-[#FF007F] text-[#FF007F] shadow-lg scale-110' : 'border-slate-100 text-slate-200'
                  }`}>
                    {otp[i] || '•'}
                  </div>
                ))}
              </div>
              <p className="text-center text-[10px] text-slate-400 font-bold uppercase tracking-widest cursor-pointer">Reenviar Código en 30s</p>
            </div>
          )}

          {step === 'AMOUNT' && (
            <div className="space-y-6 animate-fadeIn">
              <div className="text-center space-y-2">
                <h3 className="text-2xl font-black text-[#1A1A40] italic uppercase">Cargar Vueltas</h3>
                <p className="text-xs text-slate-400 font-medium">Monto que el cliente entrega para ahorrar.</p>
              </div>
              <div className="bg-[#CCFF00] p-8 rounded-[3rem] border-4 border-[#1A1A40] shadow-xl text-center">
                <p className="text-[10px] font-black text-[#1A1A40] uppercase tracking-widest mb-1 opacity-60">Valor Digitalizado</p>
                <div className="text-5xl font-black text-[#1A1A40] italic">
                  ${amount ? parseInt(amount).toLocaleString() : '0'}
                </div>
              </div>
            </div>
          )}

          {step === 'SUCCESS' && (
            <div className="text-center space-y-8 animate-fadeIn">
              <div className="w-32 h-32 bg-[#CCFF00] rounded-full flex items-center justify-center mx-auto shadow-2xl border-8 border-white">
                <i className="fa-solid fa-check text-5xl text-[#1A1A40]"></i>
              </div>
              <div className="space-y-2">
                <h3 className="text-3xl font-black text-[#1A1A40] italic uppercase">¡Vueltas Cargadas!</h3>
                <p className="text-sm text-slate-500 font-medium px-8">El cliente ha recibido <b>${parseInt(amount).toLocaleString()}</b> y <b>+50 XP</b> en su cuenta de <b>Piggybanko</b>.</p>
              </div>
              <button 
                onClick={reset}
                className="w-full py-6 bg-[#1A1A40] text-white rounded-[2.5rem] font-black shadow-2xl active:scale-95 transition-all text-xs tracking-widest border-b-8 border-black"
              >
                NUEVA CAPTURA
              </button>
            </div>
          )}
        </div>

        {step !== 'SUCCESS' && (
          <div className="mt-8 space-y-6">
            <div className="grid grid-cols-3 gap-3">
              {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(n => (
                <button 
                  key={n} 
                  onClick={() => handleKeypad(n.toString())}
                  className="h-16 bg-white rounded-2xl font-black text-xl text-[#1A1A40] shadow-sm active:bg-slate-50 active:scale-90 transition-all border border-slate-100"
                >
                  {n}
                </button>
              ))}
              <button onClick={handleBackspace} className="h-16 bg-white rounded-2xl font-black text-[#FF007F] shadow-sm active:scale-90 transition-all border border-slate-100">
                <i className="fa-solid fa-backspace"></i>
              </button>
              <button onClick={() => handleKeypad('0')} className="h-16 bg-white rounded-2xl font-black text-xl text-[#1A1A40] shadow-sm active:scale-90 transition-all border border-slate-100">0</button>
              <button 
                onClick={nextStep}
                disabled={isLoading || (step === 'PHONE' && phone.length < 10) || (step === 'OTP' && otp.length < 4) || (step === 'AMOUNT' && !amount)}
                className={`h-16 rounded-2xl font-black text-white shadow-xl transition-all flex items-center justify-center ${
                  isLoading ? 'bg-slate-300' : 'bg-[#1A1A40] active:scale-95 shadow-[#1A1A40]/20'
                }`}
              >
                {isLoading ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-chevron-right"></i>}
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

