    }
  };

  const handleBackspace = () => {
    if (step === 'PHONE') setPhone(prev => prev.slice(0, -1));
    if (step === 'OTP') setOtp(prev => prev.slice(0, -1));
    if (step === 'AMOUNT') setAmount(prev => prev.slice(0, -1));
  };

  const nextStep = () => {
    setIsLoading(true);
    // Simulación de latencia de red para seguridad
    setTimeout(() => {
      setIsLoading(false);

      if (step === 'PHONE') {
        setStep('OTP');
      } else if (step === 'OTP') {
        setStep('AMOUNT');
      } else if (step === 'AMOUNT') {
        onProcessSaving(phone, parseInt(amount));
        setStep('SUCCESS');
      }
    }, 1000);
  };

  const reset = () => {
    setStep('PHONE');
    setPhone('');
    setOtp('');
    setAmount('');
    setIsExistingUser(false);
  };

  return (
    <div className="max-w-md mx-auto min-h-[85vh] bg-[#f8fafc] flex flex-col animate-fadeIn border-x border-slate-200 shadow-2xl">
      {/* Header Estilo Terminal POS */}
      <div className="p-6 bg-[#1A1A40] text-white flex justify-between items-center rounded-b-[2.5rem] shadow-2xl border-b-4 border-[#000]">
        <div className="space-y-1">
          <div className="flex items-center gap-2">
            <span className="w-2 h-2 bg-emerald-400 rounded-full animate-pulse"></span>
            <p className="text-[10px] font-black uppercase tracking-widest text-emerald-400">Terminal de Recaudo v2.0</p>
          </div>
          <h2 className="text-xl font-black italic uppercase tracking-tighter">{merchantName}</h2>
        </div>
        <div className="w-12 h-12 bg-[#CCFF00] rounded-2xl flex items-center justify-center shadow-lg transform rotate-3">
          <i className="fa-solid fa-cash-register text-[#1A1A40] text-xl"></i>
        </div>
      </div>

      <div className="flex-1 p-6 flex flex-col">
        {/* Progress Stepper */}
        {step !== 'SUCCESS' && (
          <div className="flex justify-between mb-10 px-4">
            {['PHONE', 'OTP', 'AMOUNT'].map((s, idx) => (
              <div key={s} className="flex flex-col items-center gap-2 relative">
                <div className={`w-10 h-10 rounded-2xl flex items-center justify-center text-sm font-black border-2 transition-all duration-500 shadow-sm ${
                  step === s ? 'bg-[#FF007F] border-[#FF007F] text-white scale-110 rotate-3' : 'bg-white border-slate-100 text-slate-200'
                }`}>
                  {idx + 1}
                </div>
                <span className={`text-[8px] font-black uppercase tracking-widest ${step === s ? 'text-[#1A1A40]' : 'text-slate-300'}`}>
                  {s === 'PHONE' ? 'Cliente' : s === 'OTP' ? 'Seguridad' : 'Vueltas'}
                </span>
              </div>
            ))}
          </div>
        )}

        <div className="flex-1 flex flex-col justify-center">
          {step === 'PHONE' && (
            <div className="space-y-6 animate-fadeIn">
              <div className="text-center space-y-2">
                <h3 className="text-2xl font-black text-[#1A1A40] italic uppercase tracking-tighter">Identificar Cliente</h3>
                <p className="text-xs text-slate-400 font-medium">Ingresa el celular para abono o registro.</p>
              </div>

              <div className="relative group">
                <div className="absolute -top-3 left-6 bg-white px-3 py-0.5 rounded-full border border-slate-100 z-10">
                  <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Celular Ahorrador</span>
                </div>
                <div className="bg-white p-8 rounded-[2.5rem] border-2 border-slate-100 shadow-sm group-focus-within:border-[#FF007F] transition-all">
                  <div className="flex items-center gap-4 text-4xl font-black text-[#1A1A40]">
                    <span className="text-slate-200">+57</span>
                    <div className="flex-1 h-12 flex items-center tracking-[0.1em]">
                      {phone || <span className="text-slate-100">3XX...</span>}
                    </div>
                  </div>
                </div>

                {phone.length === 10 && (
                  <div className={`mt-4 p-4 rounded-2xl flex items-center gap-3 animate-slideUp border-2 ${isExistingUser ? 'bg-emerald-50 border-emerald-100' : 'bg-blue-50 border-blue-100'}`}>
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center text-white ${isExistingUser ? 'bg-emerald-500' : 'bg-blue-500'}`}>
                      <i className={`fa-solid ${isExistingUser ? 'fa-user-check' : 'fa-user-plus'}`}></i>
                    </div>
                    <div>
                      <p className={`text-[10px] font-black uppercase tracking-widest ${isExistingUser ? 'text-emerald-700' : 'text-blue-700'}`}>
                        {isExistingUser ? 'Usuario Registrado' : 'Usuario Nuevo'}
                      </p>
                      <p className="text-xs font-bold text-slate-600">
                        {isExistingUser ? 'Valentina Sanchez' : 'Se creará cuenta al finalizar'}
                      </p>
                    </div>
                  </div>
                )}
              </div>
            </div>
          )}

          {step === 'OTP' && (
            <div className="space-y-8 animate-fadeIn text-center">
              <div className="space-y-2">
                <h3 className="text-2xl font-black text-[#1A1A40] italic uppercase tracking-tighter">Validación de Identidad</h3>
                <p className="text-xs text-slate-400 font-medium px-12">Solicita el código de 4 dígitos enviado por SMS al terminal del cliente.</p>
              </div>

              <div className="flex justify-center gap-4">
                {[0, 1, 2, 3].map(i => (
                  <div key={i} className={`w-14 h-18 bg-white rounded-2xl border-2 flex items-center justify-center text-3xl font-black transition-all ${
                    otp[i] ? 'border-[#FF007F] text-[#FF007F] shadow-xl scale-110' : 'border-slate-100 text-slate-200'
                  }`}>
                    {otp[i] || '•'}
                  </div>
                ))}
              </div>

              <div className="inline-flex items-center gap-2 bg-slate-100 px-4 py-2 rounded-full cursor-pointer hover:bg-slate-200 transition-colors">
                <i className="fa-solid fa-rotate-right text-[10px] text-slate-400"></i>
                <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Reenviar SMS</span>
              </div>
            </div>
          )}

          {step === 'AMOUNT' && (
            <div className="space-y-8 animate-fadeIn">
              <div className="text-center space-y-2">
                <h3 className="text-2xl font-black text-[#1A1A40] italic uppercase tracking-tighter">Cargar Vueltas</h3>
                <p className="text-xs text-slate-400 font-medium italic">"Tus monedas hoy, tus sueños mañana"</p>
              </div>

              <div className="bg-[#CCFF00] p-10 rounded-[3rem] border-b-[12px] border-[#1A1A40] shadow-2xl text-center relative overflow-hidden group">
                <div className="absolute -top-6 -right-6 w-24 h-24 bg-white/20 rounded-full blur-2xl group-hover:scale-150 transition-transform"></div>
                <p className="text-[10px] font-black text-[#1A1A40] uppercase tracking-[0.3em] mb-4 opacity-60">Digitalizar Valor</p>
                <div className="flex items-center justify-center gap-2">
                  <span className="text-3xl font-black text-[#1A1A40]/40">$</span>
                  <div className="text-6xl font-black text-[#1A1A40] tracking-tighter italic">
                    {amount ? parseInt(amount).toLocaleString() : '0'}
                  </div>
                </div>
              </div>
            </div>
          )}

          {step === 'SUCCESS' && (
            <div className="text-center space-y-8 animate-fadeIn p-4">
              <div className="relative inline-block">
                <div className="w-32 h-32 bg-[#CCFF00] rounded-[2.5rem] flex items-center justify-center mx-auto shadow-2xl border-4 border-white rotate-6">
                  <i className="fa-solid fa-piggy-bank text-5xl text-[#1A1A40]"></i>
                </div>
                <div className="absolute -bottom-2 -right-2 bg-[#FF007F] w-12 h-12 rounded-full border-4 border-white flex items-center justify-center text-white shadow-lg animate-bounce">
                  <i className="fa-solid fa-check"></i>
                </div>
              </div>

              <div className="space-y-3">
                <h3 className="text-3xl font-black text-[#1A1A40] italic uppercase tracking-tighter leading-none">¡Vueltas en Camino!</h3>
                <p className="text-sm text-slate-500 font-bold px-4">
                  Se han abonado <span className="text-[#FF007F] font-black">${parseInt(amount).toLocaleString()}</span> a la cuenta de <span className="text-[#1A1A40] font-black">{phone}</span>.
                </p>
                <div className="bg-emerald-50 py-3 px-6 rounded-2xl inline-block border border-emerald-100">
                  <p className="text-[9px] font-black text-emerald-600 uppercase tracking-widest">+50 XP POR TRANSACCIÓN</p>
                </div>
              </div>

              <button 
                onClick={reset}
                className="w-full py-6 bg-[#1A1A40] text-white rounded-[2rem] font-black shadow-2xl active:scale-95 transition-all text-xs tracking-[0.2em] border-b-8 border-black flex items-center justify-center gap-3"
              >
                <i className="fa-solid fa-plus-circle"></i>
                NUEVO ABONO
              </button>
            </div>
          )}
        </div>

        {/* Teclado Numérico Universal */}
        {step !== 'SUCCESS' && (
          <div className="mt-8 space-y-6">
            <div className="grid grid-cols-3 gap-3">
              {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(n => (
                <button 
                  key={n} 
                  onClick={() => handleKeypad(n.toString())}
                  className="h-16 bg-white rounded-2xl font-black text-2xl text-[#1A1A40] shadow-sm active:bg-[#CCFF00] active:scale-90 transition-all border border-slate-100 border-b-4 border-slate-200"
                >
                  {n}
                </button>
              ))}
              <button onClick={handleBackspace} className="h-16 bg-white rounded-2xl font-black text-[#FF007F] shadow-sm active:scale-90 transition-all border border-slate-100 border-b-4 border-slate-200">
                <i className="fa-solid fa-backspace"></i>
              </button>
              <button onClick={() => handleKeypad('0')} className="h-16 bg-white rounded-2xl font-black text-2xl text-[#1A1A40] shadow-sm active:scale-90 transition-all border border-slate-100 border-b-4 border-slate-200">0</button>
              <button 
                onClick={nextStep}
                disabled={isLoading || (step === 'PHONE' && phone.length < 10) || (step === 'OTP' && otp.length < 4) || (step === 'AMOUNT' && !amount)}
                className={`h-16 rounded-2xl font-black text-white shadow-2xl transition-all flex items-center justify-center text-xl ${
                  isLoading ? 'bg-slate-300' : 'bg-[#FF007F] active:scale-95 border-b-8 border-pink-900 shadow-pink-200'
                }`}
              >
                {isLoading ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-chevron-right"></i>}
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Footer Info POS */}
      <div className="p-4 bg-slate-100 text-center">
        <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">
          Transacción Segura Piggybanko POS • ID: {Math.random().toString(36).substr(2, 9).toUpperCase()}
        </p>
      </div>
    </div>
  );
};

export default CashierView;

import React, { useState } from 'react';
import { AppRole, UserAccount, MerchantAccount, Product, Promotion, Transaction } from './types';
import { Logo, COLORS } from './constants';
import UserView from './components/UserView';
import MerchantView from './components/MerchantView';
import AdminView from './components/AdminView';
import MarketplaceView from './components/MarketplaceView';
import MerchantInventory from './components/MerchantInventory';
import MerchantPromotions from './components/MerchantPromotions';
import PromotionsView from './components/PromotionsView';
import MapView from './components/MapView';
import CashierView from './components/CashierView';

type SubView = 'HOME' | 'MARKETPLACE' | 'PROMOTIONS' | 'MAP';

const App: React.FC = () => {
  const [role, setRole] = useState<AppRole>(AppRole.USER);
  const [isLogged, setIsLogged] = useState(false);
  const [phoneNumber, setPhoneNumber] = useState('');
  const [activeTab, setActiveTab] = useState<SubView>('HOME');
  const [marketplaceMerchantFilter, setMarketplaceMerchantFilter] = useState('Todos');

  // Mock Data con State para permitir actualizaciones
  const [user, setUser] = useState<UserAccount>({
    id: 'valen-001',
    phone: '3001234567',
    balance: 45350,
    xp: 650,
    level: 2,
    goalName: 'Tenis Nike Air',
    goalTarget: 70000,
    lastYield: 5
  });

  const [merchants, setMerchants] = useState<MerchantAccount[]>([
    {
      id: 'roberto-pos',
      name: 'Don Roberto',
      cashCollected: 150000,
      piggyPayments: 20000,
      quotaUsed: 130000,
      quotaLimit: 200000,
      earnings: 377500,
      address: 'Calle 45 # 7-12',
      lat: 4.6300, 
      lng: -74.0700,
      type: 'SUPERMARKET'
    }
  ]);

  const merchant = merchants[0];

  const [products, setProducts] = useState<Product[]>([
    { id: 'p1', merchantId: 'roberto-pos', merchantName: 'Don Roberto', name: 'Leche Deslactosada 1L', price: 4200, category: 'Alimentos', imageUrl: '🥛' },
  ]);

  const [promotions, setPromotions] = useState<Promotion[]>([
    { 
      id: 'promo-1', 
      merchantId: 'roberto-pos', 
      merchantName: 'Don Roberto', 
      title: 'Pack Parrillero Familiar', 
      description: 'Llévate todo para el asado pagando una parte con tu cerdito.', 
      piggyPrice: 15000, 
      otherPrice: 35000, 
      totalValue: 65000, 
      imageUrl: '🥩', 
      expiryDate: '12h 45m', 
      category: 'Alimentos' 
    }
  ]);

  // Función Central de Transacciones POS
  const handleProcessTransaction = (targetPhone: string, amount: number, type: 'SAVING' | 'PAYMENT') => {
    const numericAmount = Number(amount);

    if (type === 'SAVING') {
      // CARGAR VUELTAS (Depósito)
      setMerchants(prev => prev.map(m => 
        m.id === merchant.id ? { ...m, cashCollected: m.cashCollected + numericAmount } : m
      ));
      if (targetPhone === user.phone || targetPhone === '3001234567') {
        setUser(prev => ({ ...prev, balance: prev.balance + numericAmount, xp: prev.xp + 50 }));
      }
    } else {
      // COBRO CON PIGGY (Pago/Retiro)
      if (targetPhone === user.phone || targetPhone === '3001234567') {
        if (user.balance < numericAmount) return false; // Fail safe
        setUser(prev => ({ ...prev, balance: prev.balance - numericAmount, xp: prev.xp + 20 }));
      }
      setMerchants(prev => prev.map(m => 
        m.id === merchant.id ? { ...m, piggyPayments: m.piggyPayments + numericAmount } : m
      ));
    }
    return true;
  };

  const addProduct = (newProduct: Omit<Product, 'id' | 'merchantId' | 'merchantName'>) => {
    const fullProduct: Product = {
      ...newProduct,
      id: `p${Date.now()}`,
      merchantId: merchant.id,
      merchantName: merchant.name,
    };
    setProducts([fullProduct, ...products]);
  };

  const addPromotion = (newPromo: Omit<Promotion, 'id' | 'merchantId' | 'merchantName'>) => {
    const fullPromo: Promotion = {
      ...newPromo,
      id: `promo-${Date.now()}`,
      merchantId: merchant.id,
      merchantName: merchant.name,
    };
    setPromotions([fullPromo, ...promotions]);
  };

  const handleViewStore = (merchantName: string) => {
    setMarketplaceMerchantFilter(merchantName);
    setActiveTab('MARKETPLACE');
  };

  const merchantProducts = products.filter(p => p.merchantId === merchant.id);
  const merchantPromos = promotions.filter(p => p.merchantId === merchant.id);

  if (!isLogged) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6">
        <div className="w-full max-w-sm space-y-8 text-center">
          <Logo />
          <div className="space-y-2">
            <h1 className="text-2xl font-bold text-slate-900">¡Bienvenido de vuelta!</h1>
            <p className="text-slate-500">Ingresa con tu número de celular para empezar a ahorrar.</p>
          </div>

          <div className="bg-white p-8 rounded-3xl shadow-xl space-y-6">
            <div className="text-left space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase">Número de Celular</label>
              <div className="flex items-center gap-3 p-4 bg-slate-50 rounded-2xl border border-slate-100">
                <span className="text-slate-400 font-bold border-r pr-3">+57</span>
                <input 
                  type="tel" 
                  placeholder="300 000 0000" 
                  className="bg-transparent outline-none w-full font-bold text-slate-800"
                  value={phoneNumber}
                  onChange={(e) => setPhoneNumber(e.target.value)}
                />
              </div>
            </div>

            <button 
              onClick={() => setIsLogged(true)}
              className="w-full py-4 bg-[#FF007F] text-white rounded-2xl font-bold shadow-lg shadow-pink-200 active:scale-95 transition-all"
            >
              INGRESAR
            </button>

            <div className="flex flex-wrap gap-2 justify-center">
              <button onClick={() => {setRole(AppRole.USER); setIsLogged(true); setActiveTab('HOME');}} className="text-[10px] bg-slate-100 px-3 py-1 rounded-full text-slate-500 font-bold"> USUARIO </button>
              <button onClick={() => {setRole(AppRole.MERCHANT); setIsLogged(true); setActiveTab('HOME');}} className="text-[10px] bg-slate-100 px-3 py-1 rounded-full text-slate-500 font-bold"> COMERCIO </button>
              <button onClick={() => {setRole(AppRole.CASHIER); setIsLogged(true); setActiveTab('HOME');}} className="text-[10px] bg-slate-900 px-3 py-1 rounded-full text-[#CCFF00] font-bold"> CAJERO ⚡ </button>
              <button onClick={() => {setRole(AppRole.ADMIN); setIsLogged(true); setActiveTab('HOME');}} className="text-[10px] bg-slate-100 px-3 py-1 rounded-full text-slate-500 font-bold"> ADMIN </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  const renderContent = () => {
    if (role === AppRole.CASHIER) {
      return (
        <CashierView 
          merchantName={merchant.name} 
          onProcessTransaction={handleProcessTransaction}
          mockUserBalance={user.balance}
        />
      );
    }
    if (role === AppRole.USER) {
      switch(activeTab) {
        case 'MARKETPLACE': return <MarketplaceView products={products} userBalance={user.balance} initialMerchant={marketplaceMerchantFilter} />;
        case 'PROMOTIONS': return <PromotionsView promotions={promotions} userBalance={user.balance} />;
        case 'MAP': return <MapView merchants={merchants} userBalance={user.balance} onViewStore={handleViewStore} />;
        default: return <UserView user={user} />;
      }
    }
    if (role === AppRole.MERCHANT) {
      switch(activeTab) {
        case 'MARKETPLACE': return <MerchantInventory products={merchantProducts} onAddProduct={addProduct} />;
        case 'PROMOTIONS': return <MerchantPromotions promotions={merchantPromos} onAddPromotion={addPromotion} />;
        default: return <MerchantView merchant={merchant} />;
      }
    }
    return <AdminView />;
  };

  return (
    <div className="min-h-screen bg-slate-50 pt-8 overflow-x-hidden">
      <div className="max-w-md md:max-w-4xl mx-auto px-4 flex justify-between items-center mb-8">
        <Logo />
        <button onClick={() => setIsLogged(false)} className="w-10 h-10 bg-white rounded-full shadow-sm flex items-center justify-center text-slate-400">
          <i className="fa-solid fa-sign-out"></i>
        </button>
      </div>

      {renderContent()}

      {(role === AppRole.USER || role === AppRole.MERCHANT) && (
        <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-[90%] max-w-sm bg-[#1A1A40] text-white rounded-3xl p-4 flex justify-between items-center shadow-2xl z-50">
          <button onClick={() => {setActiveTab('HOME'); setMarketplaceMerchantFilter('Todos');}} className={`flex flex-col items-center gap-1 transition-all ${activeTab === 'HOME' ? 'text-[#CCFF00]' : 'opacity-50'}`}>
            <i className="fa-solid fa-house"></i>
            <span className="text-[10px]">Inicio</span>
          </button>

          <button onClick={() => {setActiveTab('MARKETPLACE'); setMarketplaceMerchantFilter('Todos');}} className={`flex flex-col items-center gap-1 transition-all ${activeTab === 'MARKETPLACE' ? 'text-[#CCFF00]' : 'opacity-50'}`}>
            <i className={`fa-solid ${role === AppRole.USER ? 'fa-store' : 'fa-boxes-stacked'}`}></i>
            <span className="text-[10px]">{role === AppRole.USER ? 'Tienda' : 'Inventario'}</span>
          </button>

          <div className="relative -top-10">
            <button className="w-14 h-14 bg-[#FF007F] rounded-full flex items-center justify-center text-white shadow-lg border-4 border-slate-50 active:scale-90 transition-transform">
              <i className="fa-solid fa-qrcode text-xl"></i>
            </button>
          </div>

          <button onClick={() => setActiveTab('PROMOTIONS')} className={`flex flex-col items-center gap-1 transition-all ${activeTab === 'PROMOTIONS' ? 'text-[#CCFF00]' : 'opacity-50'}`}>
            <i className={`fa-solid ${role === AppRole.USER ? 'fa-tags' : 'fa-bullhorn'}`}></i>
            <span className="text-[10px]">{role === AppRole.USER ? 'Promos' : 'Campañas'}</span>
          </button>

          <button onClick={() => role === AppRole.USER ? setActiveTab('MAP') : setActiveTab('HOME')} className={`flex flex-col items-center gap-1 transition-all ${activeTab === 'MAP' ? 'text-[#CCFF00]' : 'opacity-50'}`}>
            <i className={`fa-solid ${role === AppRole.USER ? 'fa-map-location-dot' : 'fa-chart-line'}`}></i>
            <span className="text-[10px]">{role === AppRole.USER ? 'Mapa' : 'Métricas'}</span>
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';

interface CashierViewProps {
  merchantName: string;
  onProcessTransaction: (phone: string, amount: number, type: 'SAVING' | 'PAYMENT') => boolean;
  mockUserBalance: number;
}

type Step = 'TYPE' | 'PHONE' | 'OTP' | 'AMOUNT' | 'SUCCESS';

const CashierView: React.FC<CashierViewProps> = ({ merchantName, onProcessTransaction, mockUserBalance }) => {
  const [step, setStep] = useState<Step>('TYPE');
  const [txType, setTxType] = useState<'SAVING' | 'PAYMENT'>('SAVING');
  const [phone, setPhone] = useState('');
  const [otp, setOtp] = useState('');
  const [amount, setAmount] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isExistingUser, setIsExistingUser] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Simulación de búsqueda de usuario
  useEffect(() => {
    if (phone === '3001234567') {
      setIsExistingUser(true);
    } else {
      setIsExistingUser(false);
    }
  }, [phone]);

  const handleKeypad = (val: string) => {
    setError(null);
    if (step === 'PHONE' && phone.length < 10) setPhone(prev => prev + val);
    if (step === 'OTP' && otp.length < 4) setOtp(prev => prev + val);
    if (step === 'AMOUNT') {
      if (amount === '0') setAmount(val);
      else setAmount(prev => prev + val);
    }
  };

  const handleBackspace = () => {
    if (step === 'PHONE') setPhone(prev => prev.slice(0, -1));
    if (step === 'OTP') setOtp(prev => prev.slice(0, -1));
    if (step === 'AMOUNT') setAmount(prev => prev.slice(0, -1));
  };

  const nextStep = () => {
    setIsLoading(true);
    setTimeout(() => {
      setIsLoading(false);

      if (step === 'PHONE') {
        setStep('OTP');
      } else if (step === 'OTP') {
        setStep('AMOUNT');
      } else if (step === 'AMOUNT') {
        const numericAmount = parseInt(amount);

        // Validación de saldo para pagos
        if (txType === 'PAYMENT' && isExistingUser && mockUserBalance < numericAmount) {
          setError(`Saldo insuficiente. El cliente solo tiene $${mockUserBalance.toLocaleString()}`);
          return;
        }

        const success = onProcessTransaction(phone, numericAmount, txType);
        if (success) {
          setStep('SUCCESS');
        } else {
          setError('Error procesando la transacción.');
        }
      }
    }, 1000);
  };

  const reset = () => {
    setStep('TYPE');
    setPhone('');
    setOtp('');
    setAmount('');
    setIsExistingUser(false);
    setError(null);
  };

  const themeColor = txType === 'SAVING' ? '#CCFF00' : '#FF007F';
  const themeText = txType === 'SAVING' ? '#1A1A40' : '#FFFFFF';

  return (
    <div className="max-w-md mx-auto min-h-[85vh] bg-[#f8fafc] flex flex-col animate-fadeIn border-x border-slate-200 shadow-2xl relative overflow-hidden">
      {/* Header POS */}
      <div className="p-6 bg-[#1A1A40] text-white flex justify-between items-center rounded-b-[2.5rem] shadow-2xl border-b-4 border-[#000]">
        <div className="space-y-1">
          <div className="flex items-center gap-2">
            <span className="w-2 h-2 bg-emerald-400 rounded-full animate-pulse"></span>
            <p className="text-[10px] font-black uppercase tracking-widest text-emerald-400">Terminal POS v2.5</p>
          </div>
          <h2 className="text-xl font-black italic uppercase tracking-tighter">{merchantName}</h2>
        </div>
        <div className="w-12 h-12 rounded-2xl flex items-center justify-center shadow-lg transform rotate-3 transition-colors duration-500" style={{ backgroundColor: themeColor }}>
          <i className={`fa-solid ${txType === 'SAVING' ? 'fa-cash-register' : 'fa-hand-holding-dollar'} text-[#1A1A40] text-xl`}></i>
        </div>
      </div>

      <div className="flex-1 p-6 flex flex-col">
        {step === 'TYPE' && (
          <div className="flex-1 flex flex-col justify-center space-y-6 animate-fadeIn">
            <div className="text-center space-y-2 mb-4">
              <h3 className="text-3xl font-black text-[#1A1A40] italic uppercase tracking-tighter">¿Qué operación haremos?</h3>
              <p className="text-xs text-slate-400 font-bold uppercase">Selecciona el tipo de transacción</p>
            </div>

            <button 
              onClick={() => { setTxType('SAVING'); setStep('PHONE'); }}
              className="group p-8 bg-white border-4 border-slate-100 rounded-[3rem] hover:border-[#CCFF00] transition-all flex items-center gap-6 active:scale-95 shadow-sm"
            >
              <div className="w-20 h-20 bg-[#CCFF00] rounded-[2rem] flex items-center justify-center text-3xl text-[#1A1A40] shadow-lg group-hover:rotate-12 transition-transform">
                <i className="fa-solid fa-piggy-bank"></i>
              </div>
              <div className="text-left">
                <h4 className="text-xl font-black text-[#1A1A40] uppercase italic">Cargar Vueltas</h4>
                <p className="text-xs text-slate-400 font-bold">Abono al cerdito del cliente</p>
              </div>
            </button>

            <button 
              onClick={() => { setTxType('PAYMENT'); setStep('PHONE'); }}
              className="group p-8 bg-white border-4 border-slate-100 rounded-[3rem] hover:border-[#FF007F] transition-all flex items-center gap-6 active:scale-95 shadow-sm"
            >
              <div className="w-20 h-20 bg-[#FF007F] rounded-[2rem] flex items-center justify-center text-3xl text-white shadow-lg group-hover:-rotate-12 transition-transform">
                <i className="fa-solid fa-cart-shopping"></i>
              </div>
              <div className="text-left">
                <h4 className="text-xl font-black text-[#1A1A40] uppercase italic">Cobro con Piggy</h4>
                <p className="text-xs text-slate-400 font-bold">Pago de producto con ahorros</p>
              </div>
            </button>
          </div>
        )}

        {step !== 'TYPE' && step !== 'SUCCESS' && (
          <div className="flex justify-between mb-10 px-4">
            {['PHONE', 'OTP', 'AMOUNT'].map((s, idx) => (
              <div key={s} className="flex flex-col items-center gap-2 relative">
                <div className={`w-10 h-10 rounded-2xl flex items-center justify-center text-sm font-black border-2 transition-all duration-500 shadow-sm ${
                  step === s ? 'text-white scale-110 rotate-3' : 'bg-white border-slate-100 text-slate-200'
                }`} style={{ backgroundColor: step === s ? themeColor : '', borderColor: step === s ? themeColor : '' }}>
                  {idx + 1}
                </div>
                <span className={`text-[8px] font-black uppercase tracking-widest ${step === s ? 'text-[#1A1A40]' : 'text-slate-300'}`}>
                  {s === 'PHONE' ? 'Cliente' : s === 'OTP' ? 'Seguridad' : txType === 'SAVING' ? 'Recibir' : 'Cobrar'}
                </span>
              </div>
            ))}
          </div>
        )}

        {step === 'PHONE' && (
          <div className="space-y-6 animate-fadeIn flex-1 flex flex-col justify-center">
            <div className="text-center space-y-2">
              <h3 className="text-2xl font-black text-[#1A1A40] italic uppercase tracking-tighter">Identificar Cliente</h3>
              <p className="text-xs text-slate-400 font-medium">Ingresa el celular del ahorrador.</p>
            </div>

            <div className="bg-white p-8 rounded-[2.5rem] border-2 border-slate-100 shadow-sm transition-all focus-within:border-[#1A1A40]">
              <div className="flex items-center gap-4 text-4xl font-black text-[#1A1A40]">
                <span className="text-slate-200">+57</span>
                <div className="flex-1 h-12 flex items-center tracking-[0.1em]">
                  {phone || <span className="text-slate-100">3XX...</span>}
                </div>
              </div>
            </div>

            {phone.length === 10 && (
              <div className={`p-4 rounded-2xl flex items-center gap-3 animate-slideUp border-2 ${isExistingUser ? 'bg-emerald-50 border-emerald-100 text-emerald-700' : 'bg-blue-50 border-blue-100 text-blue-700'}`}>
                <i className={`fa-solid ${isExistingUser ? 'fa-user-check' : 'fa-user-plus'}`}></i>
                <div className="flex-1">
                  <p className="text-[10px] font-black uppercase">{isExistingUser ? 'Usuario Registrado' : 'Usuario Nuevo'}</p>
                  <p className="text-xs font-bold text-slate-600">{isExistingUser ? 'Valentina Sanchez' : 'Se creará cuenta al finalizar'}</p>
                </div>
                {isExistingUser && txType === 'PAYMENT' && (
                  <div className="text-right">
                    <p className="text-[8px] font-black uppercase opacity-60">Saldo</p>
                    <p className="text-xs font-black">${mockUserBalance.toLocaleString()}</p>
                  </div>
                )}
              </div>
            )}
          </div>
        )}

        {step === 'OTP' && (
          <div className="space-y-8 animate-fadeIn text-center flex-1 flex flex-col justify-center">
            <div className="space-y-2">
              <h3 className="text-2xl font-black text-[#1A1A40] italic uppercase tracking-tighter">Seguridad Biométrica/SMS</h3>
              <p className="text-xs text-slate-400 font-medium px-12">Pide al cliente el código de validación de su App.</p>
            </div>

            <div className="flex justify-center gap-4">
              {[0, 1, 2, 3].map(i => (
                <div key={i} className={`w-14 h-18 bg-white rounded-2xl border-2 flex items-center justify-center text-3xl font-black transition-all ${
                  otp[i] ? 'text-white shadow-xl scale-110' : 'border-slate-100 text-slate-200'
                }`} style={{ backgroundColor: otp[i] ? themeColor : '', borderColor: otp[i] ? themeColor : '' }}>
                  {otp[i] || '•'}
                </div>
              ))}
            </div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest cursor-pointer hover:text-[#1A1A40]">Reenviar Código</p>
          </div>
        )}

        {step === 'AMOUNT' && (
          <div className="space-y-8 animate-fadeIn flex-1 flex flex-col justify-center">
            <div className="text-center space-y-2">
              <h3 className="text-2xl font-black text-[#1A1A40] italic uppercase tracking-tighter">
                {txType === 'SAVING' ? 'Cargar Vueltas' : 'Cobro de Producto'}
              </h3>
              <p className="text-xs text-slate-400 font-bold">Ingresa el valor de la transacción</p>
            </div>

            <div className="p-10 rounded-[3rem] border-b-[12px] border-[#1A1A40] shadow-2xl text-center relative overflow-hidden transition-colors duration-500" style={{ backgroundColor: themeColor }}>
              <p className="text-[10px] font-black uppercase tracking-[0.3em] mb-4 opacity-40" style={{ color: themeText }}>Monto Final</p>
              <div className="flex items-center justify-center gap-2">
                <span className="text-3xl font-black opacity-30" style={{ color: themeText }}>$</span>
                <div className="text-6xl font-black tracking-tighter italic" style={{ color: themeText }}>
                  {amount ? parseInt(amount).toLocaleString() : '0'}
                </div>
              </div>
            </div>

            {error && (
              <div className="bg-rose-50 border-2 border-rose-100 p-4 rounded-2xl flex items-center gap-3 text-rose-600 animate-shake">
                <i className="fa-solid fa-circle-exclamation text-xl"></i>
                <p className="text-xs font-black uppercase leading-tight">{error}</p>
              </div>
            )}
          </div>
        )}

        {step === 'SUCCESS' && (
          <div className="text-center space-y-8 animate-fadeIn p-4 flex-1 flex flex-col justify-center">
            <div className="relative inline-block mx-auto">
              <div className="w-32 h-32 rounded-[2.5rem] flex items-center justify-center shadow-2xl border-4 border-white rotate-6 transition-colors duration-500" style={{ backgroundColor: themeColor }}>
                <i className={`fa-solid ${txType === 'SAVING' ? 'fa-piggy-bank' : 'fa-check-double'} text-5xl text-[#1A1A40]`}></i>
              </div>
            </div>

            <div className="space-y-3">
              <h3 className="text-3xl font-black text-[#1A1A40] italic uppercase tracking-tighter leading-none">
                {txType === 'SAVING' ? '¡Ahorro Exitoso!' : '¡Cobro Completado!'}
              </h3>
              <p className="text-sm text-slate-500 font-bold px-4">
                Se han procesado <span className="text-[#FF007F] font-black">${parseInt(amount).toLocaleString()}</span> para el cliente <span className="text-[#1A1A40] font-black">{phone}</span>.
              </p>
              <div className="bg-emerald-50 py-3 px-6 rounded-2xl inline-block border border-emerald-100">
                <p className="text-[9px] font-black text-emerald-600 uppercase tracking-widest">+ XP ASIGNADOS AL CLIENTE</p>
              </div>
            </div>

            <button 
              onClick={reset}
              className="w-full py-6 bg-[#1A1A40] text-white rounded-[2rem] font-black shadow-2xl active:scale-95 transition-all text-xs tracking-[0.2em] border-b-8 border-black flex items-center justify-center gap-3"
            >
              NUEVA OPERACIÓN
            </button>
          </div>
        )}

        {/* Teclado POS Universal */}
        {step !== 'SUCCESS' && step !== 'TYPE' && (
          <div className="mt-8 grid grid-cols-3 gap-3">
            {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(n => (
              <button 
                key={n} 
                onClick={() => handleKeypad(n.toString())}
                className="h-16 bg-white rounded-2xl font-black text-2xl text-[#1A1A40] shadow-sm active:bg-slate-100 active:scale-90 transition-all border border-slate-100 border-b-4 border-slate-200"
              >
                {n}
              </button>
            ))}
            <button onClick={handleBackspace} className="h-16 bg-white rounded-2xl font-black text-[#FF007F] shadow-sm active:scale-90 transition-all border border-slate-100 border-b-4 border-slate-200">
              <i className="fa-solid fa-backspace"></i>
            </button>
            <button onClick={() => handleKeypad('0')} className="h-16 bg-white rounded-2xl font-black text-2xl text-[#1A1A40] shadow-sm active:scale-90 transition-all border border-slate-100 border-b-4 border-slate-200">0</button>
            <button 
              onClick={nextStep}
              disabled={isLoading || (step === 'PHONE' && phone.length < 10) || (step === 'OTP' && otp.length < 4) || (step === 'AMOUNT' && !amount)}
              className={`h-16 rounded-2xl font-black text-white shadow-2xl transition-all flex items-center justify-center text-xl ${
                isLoading ? 'bg-slate-300' : 'active:scale-95 border-b-8 shadow-pink-200'
              }`}
              style={{ backgroundColor: isLoading ? '' : themeColor, borderBottomColor: isLoading ? '' : '#000' }}
            >
              {isLoading ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-chevron-right"></i>}
            </button>
          </div>
        )}
      </div>

      <div className="p-4 bg-slate-100 text-center flex justify-between items-center px-8">
        <button onClick={reset} className="text-[9px] font-black text-slate-400 uppercase tracking-widest hover:text-rose-500">
          <i className="fa-solid fa-circle-left mr-1"></i> Cancelar
        </button>
        <p className="text-[8px] font-bold text-slate-300 uppercase tracking-widest">
          Transacción Segura Piggybanko POS
        </p>
      </div>
    </div>
  );
};

export default CashierView;

import React, { useState } from 'react';
import { AppRole, UserAccount, MerchantAccount, Product, Promotion, Transaction } from './types';
import { Logo, COLORS } from './constants';
import UserView from './components/UserView';
import MerchantView from './components/MerchantView';
import AdminView from './components/AdminView';
import MarketplaceView from './components/MarketplaceView';
import MerchantInventory from './components/MerchantInventory';
import MerchantPromotions from './components/MerchantPromotions';
import PromotionsView from './components/PromotionsView';
import MapView from './components/MapView';
import CashierView from './components/CashierView';

type SubView = 'HOME' | 'MARKETPLACE' | 'PROMOTIONS' | 'MAP';

const App: React.FC = () => {
  const [role, setRole] = useState<AppRole>(AppRole.USER);
  const [isLogged, setIsLogged] = useState(false);
  const [phoneNumber, setPhoneNumber] = useState('');
  const [activeTab, setActiveTab] = useState<SubView>('HOME');
  const [marketplaceMerchantFilter, setMarketplaceMerchantFilter] = useState('Todos');

  // Mock Data con State para permitir actualizaciones
  const [user, setUser] = useState<UserAccount>({
    id: 'valen-001',
    phone: '3001234567',
    balance: 45350,
    xp: 650,
    level: 2,
    goalName: 'Tenis Nike Air',
    goalTarget: 70000,
    lastYield: 5
  });

  const [merchants, setMerchants] = useState<MerchantAccount[]>([
    {
      id: 'roberto-pos',
      name: 'Don Roberto',
      cashCollected: 150000,
      piggyPayments: 20000,
      quotaUsed: 130000,
      quotaLimit: 200000,
      earnings: 377500,
      address: 'Calle 45 # 7-12',
      lat: 4.6300, 
      lng: -74.0700,
      type: 'SUPERMARKET'
    }
  ]);

  const merchant = merchants[0];

  const [products, setProducts] = useState<Product[]>([
    { id: 'p1', merchantId: 'roberto-pos', merchantName: 'Don Roberto', name: 'Leche Deslactosada 1L', price: 4200, category: 'Alimentos', imageUrl: '🥛' },
  ]);

  const [promotions, setPromotions] = useState<Promotion[]>([
    { 
      id: 'promo-1', 
      merchantId: 'roberto-pos', 
      merchantName: 'Don Roberto', 
      title: 'Pack Parrillero Familiar', 
      description: 'Llévate todo para el asado pagando una parte con tu cerdito.', 
      piggyPrice: 15000, 
      otherPrice: 35000, 
      totalValue: 65000, 
      imageUrl: '🥩', 
      expiryDate: '12h 45m', 
      category: 'Alimentos' 
    }
  ]);

  // Función Central de Transacciones POS
  const handleProcessTransaction = (targetPhone: string, amount: number, type: 'SAVING' | 'PAYMENT') => {
    const numericAmount = Number(amount);

    if (type === 'SAVING') {
      // CARGAR VUELTAS (Depósito)
      setMerchants(prev => prev.map(m => 
        m.id === merchant.id ? { ...m, cashCollected: m.cashCollected + numericAmount } : m
      ));
      if (targetPhone === user.phone || targetPhone === '3001234567') {
        setUser(prev => ({ ...prev, balance: prev.balance + numericAmount, xp: prev.xp + 50 }));
      }
    } else {
      // COBRO CON PIGGY (Pago/Retiro)
      if (targetPhone === user.phone || targetPhone === '3001234567') {
        if (user.balance < numericAmount) return false; // Fail safe
        setUser(prev => ({ ...prev, balance: prev.balance - numericAmount, xp: prev.xp + 20 }));
      }
      setMerchants(prev => prev.map(m => 
        m.id === merchant.id ? { ...m, piggyPayments: m.piggyPayments + numericAmount } : m
      ));
    }
    return true;
  };

  const addProduct = (newProduct: Omit<Product, 'id' | 'merchantId' | 'merchantName'>) => {
    const fullProduct: Product = {
      ...newProduct,
      id: `p${Date.now()}`,
      merchantId: merchant.id,
      merchantName: merchant.name,
    };
    setProducts([fullProduct, ...products]);
  };

  const addPromotion = (newPromo: Omit<Promotion, 'id' | 'merchantId' | 'merchantName'>) => {
    const fullPromo: Promotion = {
      ...newPromo,
      id: `promo-${Date.now()}`,
      merchantId: merchant.id,
      merchantName: merchant.name,
    };
    setPromotions([fullPromo, ...promotions]);
  };

  const handleViewStore = (merchantName: string) => {
    setMarketplaceMerchantFilter(merchantName);
    setActiveTab('MARKETPLACE');
  };

  const goHome = () => {
    setActiveTab('HOME');
    setMarketplaceMerchantFilter('Todos');
  };

  const merchantProducts = products.filter(p => p.merchantId === merchant.id);
  const merchantPromos = promotions.filter(p => p.merchantId === merchant.id);

  if (!isLogged) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6">
        <div className="w-full max-w-sm space-y-8 text-center">
          <Logo />
          <div className="space-y-2">
            <h1 className="text-2xl font-bold text-slate-900">¡Bienvenido de vuelta!</h1>
            <p className="text-slate-500">Ingresa con tu número de celular para empezar a ahorrar.</p>
          </div>

          <div className="bg-white p-8 rounded-3xl shadow-xl space-y-6">
            <div className="text-left space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase">Número de Celular</label>
              <div className="flex items-center gap-3 p-4 bg-slate-50 rounded-2xl border border-slate-100">
                <span className="text-slate-400 font-bold border-r pr-3">+57</span>
                <input 
                  type="tel" 
                  placeholder="300 000 0000" 
                  className="bg-transparent outline-none w-full font-bold text-slate-800"
                  value={phoneNumber}
                  onChange={(e) => setPhoneNumber(e.target.value)}
                />
              </div>
            </div>

            <button 
              onClick={() => setIsLogged(true)}
              className="w-full py-4 bg-[#FF007F] text-white rounded-2xl font-bold shadow-lg shadow-pink-200 active:scale-95 transition-all"
            >
              INGRESAR
            </button>

            <div className="flex flex-wrap gap-2 justify-center">
              <button onClick={() => {setRole(AppRole.USER); setIsLogged(true); setActiveTab('HOME');}} className="text-[10px] bg-slate-100 px-3 py-1 rounded-full text-slate-500 font-bold"> USUARIO </button>
              <button onClick={() => {setRole(AppRole.MERCHANT); setIsLogged(true); setActiveTab('HOME');}} className="text-[10px] bg-slate-100 px-3 py-1 rounded-full text-slate-500 font-bold"> COMERCIO </button>
              <button onClick={() => {setRole(AppRole.CASHIER); setIsLogged(true); setActiveTab('HOME');}} className="text-[10px] bg-slate-900 px-3 py-1 rounded-full text-[#CCFF00] font-bold"> CAJERO ⚡ </button>
              <button onClick={() => {setRole(AppRole.ADMIN); setIsLogged(true); setActiveTab('HOME');}} className="text-[10px] bg-slate-100 px-3 py-1 rounded-full text-slate-500 font-bold"> ADMIN </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  const renderContent = () => {
    if (role === AppRole.CASHIER) {
      return (
        <CashierView 
          merchantName={merchant.name} 
          onProcessTransaction={handleProcessTransaction}
          mockUserBalance={user.balance}
          onGoHome={goHome}
        />
      );
    }
    if (role === AppRole.USER) {
      switch(activeTab) {
        case 'MARKETPLACE': return <MarketplaceView products={products} userBalance={user.balance} initialMerchant={marketplaceMerchantFilter} />;
        case 'PROMOTIONS': return <PromotionsView promotions={promotions} userBalance={user.balance} />;
        case 'MAP': return <MapView merchants={merchants} userBalance={user.balance} onViewStore={handleViewStore} />;
        default: return <UserView user={user} onGoHome={goHome} />;
      }
    }
    if (role === AppRole.MERCHANT) {
      switch(activeTab) {
        case 'MARKETPLACE': return <MerchantInventory products={merchantProducts} onAddProduct={addProduct} />;
        case 'PROMOTIONS': return <MerchantPromotions promotions={merchantPromos} onAddPromotion={addPromotion} />;
        default: return <MerchantView merchant={merchant} onGoHome={goHome} />;
      }
    }
    return <AdminView />;
  };

  return (
    <div className="min-h-screen bg-slate-50 pt-8 overflow-x-hidden">
      <div className="max-w-md md:max-w-4xl mx-auto px-4 flex justify-between items-center mb-8">
        <button onClick={goHome} className="hover:scale-105 active:scale-95 transition-transform">
          <Logo />
        </button>
        <button onClick={() => setIsLogged(false)} className="w-10 h-10 bg-white rounded-full shadow-sm flex items-center justify-center text-slate-400 border border-slate-100 active:bg-rose-50 hover:text-rose-500 transition-all">
          <i className="fa-solid fa-sign-out"></i>
        </button>
      </div>

      {renderContent()}

      {(role === AppRole.USER || role === AppRole.MERCHANT) && (
        <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-[90%] max-w-sm bg-[#1A1A40] text-white rounded-3xl p-4 flex justify-between items-center shadow-2xl z-50">
          <button onClick={goHome} className={`flex flex-col items-center gap-1 transition-all ${activeTab === 'HOME' ? 'text-[#CCFF00]' : 'opacity-50'}`}>
            <i className="fa-solid fa-house"></i>
            <span className="text-[10px]">Inicio</span>
          </button>

          <button onClick={() => {setActiveTab('MARKETPLACE'); setMarketplaceMerchantFilter('Todos');}} className={`flex flex-col items-center gap-1 transition-all ${activeTab === 'MARKETPLACE' ? 'text-[#CCFF00]' : 'opacity-50'}`}>
            <i className={`fa-solid ${role === AppRole.USER ? 'fa-store' : 'fa-boxes-stacked'}`}></i>
            <span className="text-[10px]">{role === AppRole.USER ? 'Tienda' : 'Inventario'}</span>
          </button>

          <div className="relative -top-10">
            <button className="w-14 h-14 bg-[#FF007F] rounded-full flex items-center justify-center text-white shadow-lg border-4 border-slate-50 active:scale-90 transition-transform">
              <i className="fa-solid fa-qrcode text-xl"></i>
            </button>
          </div>

          <button onClick={() => setActiveTab('PROMOTIONS')} className={`flex flex-col items-center gap-1 transition-all ${activeTab === 'PROMOTIONS' ? 'text-[#CCFF00]' : 'opacity-50'}`}>
            <i className={`fa-solid ${role === AppRole.USER ? 'fa-tags' : 'fa-bullhorn'}`}></i>
            <span className="text-[10px]">{role === AppRole.USER ? 'Promos' : 'Campañas'}</span>
          </button>

          <button onClick={() => role === AppRole.USER ? setActiveTab('MAP') : setActiveTab('HOME')} className={`flex flex-col items-center gap-1 transition-all ${activeTab === 'MAP' ? 'text-[#CCFF00]' : 'opacity-50'}`}>
            <i className={`fa-solid ${role === AppRole.USER ? 'fa-map-location-dot' : 'fa-chart-line'}`}></i>
            <span className="text-[10px]">{role === AppRole.USER ? 'Mapa' : 'Métricas'}</span>
          </button>
        </div>
      )}
    </div>
  );
};

