        <div className="space-y-1">
          <div className="flex items-center gap-2">
            <span className="w-2 h-2 bg-emerald-400 rounded-full animate-pulse"></span>
            <p className="text-[10px] font-black uppercase tracking-widest text-emerald-400">Terminal POS v2.5</p>
          </div>
          <h2 className="text-xl font-black italic uppercase tracking-tighter">{merchantName}</h2>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={onGoHome}
            className="w-10 h-10 bg-white/10 hover:bg-[#CCFF00] hover:text-[#1A1A40] rounded-xl flex items-center justify-center transition-all border border-white/20 shadow-lg"
          >
            <i className="fa-solid fa-house text-sm"></i>
          </button>
          <div className="w-12 h-12 rounded-2xl flex items-center justify-center shadow-lg transform rotate-3 transition-colors duration-500" style={{ backgroundColor: themeColor }}>
            <i className={`fa-solid ${txType === 'SAVING' ? 'fa-cash-register' : 'fa-hand-holding-dollar'} text-[#1A1A40] text-xl`}></i>
          </div>
        </div>
      </div>

      <div className="flex-1 p-6 flex flex-col">
        {step === 'TYPE' && (
