              </div>
            </button>

            <button 
              onClick={() => { setTxType('PAYMENT'); setStep('PHONE'); }}
              className="group p-8 bg-white border-4 border-slate-100 rounded-[3rem] hover:border-[#FF007F] transition-all flex items-center gap-6 active:scale-95 shadow-sm"
            >
              <div className="w-20 h-20 bg-[#FF007F] rounded-[2rem] flex items-center justify-center text-3xl text-white shadow-lg group-hover:-rotate-12 transition-transform">
                <i className="fa-solid fa-cart-shopping"></i>
              </div>
              <div className="text-left">
                <h4 className="text-xl font-black text-[#1A1A40] uppercase italic">Cobro con Piggy</h4>
                <p className="text-xs text-slate-400 font-bold">Pago de producto con ahorros</p>
              </div>
            </button>
          </div>
        )}

        {step !== 'TYPE' && step !== 'SUCCESS' && (
          <div className="flex justify-between mb-10 px-4">
            {['PHONE', 'OTP', 'AMOUNT'].map((s, idx) => (
