        )}

        {step === 'PHONE' && (
          <div className="space-y-6 animate-fadeIn flex-1 flex flex-col justify-center">
            <div className="text-center space-y-2">
              <h3 className="text-2xl font-black text-[#1A1A40] italic uppercase tracking-tighter">Identificar Cliente</h3>
