import React, { useState, useMemo } from 'react';
import { Product } from '../types';

interface MerchantInventoryProps {
  products: Product[];
  onAddProduct: (product: Omit<Product, 'id' | 'merchantId' | 'merchantName'>) => void;
  onRemoveProduct: (id: string) => void;
}

const MerchantInventory: React.FC<MerchantInventoryProps> = ({ products, onAddProduct, onRemoveProduct }) => {
  const [showForm, setShowForm] = useState(false);
  const [name, setName] = useState('');
  const [price, setPrice] = useState('');
  const [category, setCategory] = useState('Alimentos');
  const [emoji, setEmoji] = useState('📦');

  // Sorting state
  const [sortBy, setSortBy] = useState<'default' | 'nameAsc' | 'priceAsc' | 'priceDesc'>('default');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !price) return;

    onAddProduct({
      name,
      price: parseFloat(price),
      category,
      imageUrl: emoji,
    });

    // Reset form
    setName('');
    setPrice('');
    setCategory('Alimentos');
    setEmoji('📦');
    setShowForm(false);
  };

  const handleDelete = (id: string) => {
    if (window.confirm('¿Deseas eliminar este producto del marketplace?')) {
      onRemoveProduct(id);
    }
  };

  const sortedProducts = useMemo(() => {
    const list = [...products];
    if (sortBy === 'nameAsc') {
      return list.sort((a, b) => a.name.localeCompare(b.name));
    } else if (sortBy === 'priceAsc') {
      return list.sort((a, b) => a.price - b.price);
    } else if (sortBy === 'priceDesc') {
      return list.sort((a, b) => b.price - a.price);
    }
    return list;
  }, [products, sortBy]);

  return (
    <div className="max-w-md mx-auto space-y-6 pb-24 px-4">
      <div className="flex justify-between items-center">
        <h2 className="text-xl font-bold text-slate-800 tracking-tight">Mis Productos</h2>
        <button 
          onClick={() => setShowForm(!showForm)}
          className="bg-[#FF007F] text-white px-4 py-2 rounded-xl text-xs font-bold shadow-md flex items-center gap-2 transition-all active:scale-95"
        >
          <i className={`fa-solid ${showForm ? 'fa-times' : 'fa-plus'}`}></i>
          {showForm ? 'Cerrar' : 'Publicar Nuevo'}
        </button>
      </div>

      {showForm && (
        <form onSubmit={handleSubmit} className="bg-white p-6 rounded-3xl shadow-xl border border-pink-100 space-y-4 animate-fadeIn">
          <h3 className="font-bold text-slate-800">Detalles del Producto</h3>
          <div className="space-y-3">
            <div>
              <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Nombre</label>
              <input 
                type="text" 
                placeholder="Ej. Pan Tajado" 
                value={name}
                onChange={(e) => setName(e.target.value)}
                className="w-full p-3 bg-slate-50 rounded-xl text-sm border-none focus:ring-2 focus:ring-pink-400 transition-all outline-none" 
                required
              />
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Precio ($)</label>
                <input 
                  type="number" 
                  placeholder="0.00" 
                  value={price}
                  onChange={(e) => setPrice(e.target.value)}
                  className="w-full p-3 bg-slate-50 rounded-xl text-sm border-none focus:ring-2 focus:ring-pink-400 transition-all outline-none" 
                  required
                />
              </div>
              <div>
                <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Categoría</label>
                <select 
                  value={category}
                  onChange={(e) => setCategory(e.target.value)}
                  className="w-full p-3 bg-slate-50 rounded-xl text-sm border-none focus:ring-2 focus:ring-pink-400 transition-all outline-none"
                >
                  <option>Alimentos</option>
                  <option>Aseo</option>
                  <option>Snacks</option>
                  <option>Tecno</option>
                </select>
              </div>
            </div>

            <div>
              <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Icono/Emoji representativo</label>
              <input 
                type="text" 
                placeholder="Ej. 🍞" 
                value={emoji}
                onChange={(e) => setEmoji(e.target.value)}
                className="w-full p-3 bg-slate-50 rounded-xl text-sm border-none focus:ring-2 focus:ring-pink-400 transition-all outline-none" 
                maxLength={2}
              />
            </div>

            <button type="submit" className="w-full py-3 bg-[#1A1A40] text-white rounded-xl font-bold shadow-lg shadow-blue-900/20 active:scale-95 transition-all">
              PUBLICAR EN MARKETPLACE
            </button>
          </div>
        </form>
      )}

      {/* Sorting Tools */}
      {products.length > 0 && (
        <div className="flex items-center justify-between px-1">
          <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Ordenar listado</span>
          <div className="flex gap-2">
            <button 
              onClick={() => setSortBy(sortBy === 'nameAsc' ? 'default' : 'nameAsc')}
              className={`text-[10px] font-bold px-3 py-1.5 rounded-full transition-all border ${sortBy === 'nameAsc' ? 'bg-[#1A1A40] text-white border-[#1A1A40]' : 'bg-white text-slate-500 border-slate-200'}`}
            >
              <i className="fa-solid fa-arrow-down-a-z mr-1"></i> A-Z
            </button>
            <button 
              onClick={() => setSortBy(sortBy === 'priceAsc' ? 'priceDesc' : sortBy === 'priceDesc' ? 'default' : 'priceAsc')}
              className={`text-[10px] font-bold px-3 py-1.5 rounded-full transition-all border ${sortBy.startsWith('price') ? 'bg-[#1A1A40] text-white border-[#1A1A40]' : 'bg-white text-slate-500 border-slate-200'}`}
            >
              <i className={`fa-solid ${sortBy === 'priceDesc' ? 'fa-arrow-down-wide-short' : 'fa-arrow-up-wide-short'} mr-1`}></i> Precio
            </button>
          </div>
        </div>
      )}

      <div className="space-y-3">
        {sortedProducts.length === 0 ? (
          <div className="text-center py-10 text-slate-400 italic text-sm">
            No has publicado productos todavía.
          </div>
        ) : (
          sortedProducts.map(p => (
            <div key={p.id} className="bg-white p-4 rounded-3xl shadow-sm border border-slate-100 flex items-center justify-between transition-all hover:shadow-md">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-slate-50 rounded-2xl flex items-center justify-center text-2xl group-hover:scale-110 transition-transform">
                  {p.imageUrl}
                </div>
                <div>
                  <h4 className="font-bold text-slate-800 text-sm leading-tight">{p.name}</h4>
                  <div className="flex items-center gap-2 mt-1">
                    <p className="text-xs text-[#FF007F] font-black">${p.price.toLocaleString()}</p>
                    <span className="text-[8px] bg-slate-100 text-slate-500 px-2 py-0.5 rounded-full font-bold uppercase tracking-tighter">{p.category}</span>
                  </div>
                </div>
              </div>
              <div className="flex gap-1.5">
                <button className="w-8 h-8 rounded-xl bg-slate-50 text-slate-400 flex items-center justify-center hover:bg-slate-100 transition-colors">
                  <i className="fa-solid fa-pen text-[10px]"></i>
                </button>
                <button 
                  onClick={() => handleDelete(p.id)}
                  className="w-8 h-8 rounded-xl bg-rose-50 text-rose-500 flex items-center justify-center hover:bg-rose-100 transition-colors"
                >
                  <i className="fa-solid fa-trash text-[10px]"></i>
                </button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

