import CashierView from './CashierView';

interface MerchantViewProps {
  merchant: MerchantAccount;
  products?: Product[];
  onGoHome: () => void;
  onMerchantPayUser: (phone: string, amount: number) => boolean;
}

const MerchantView: React.FC<MerchantViewProps> = ({ merchant, products = [], onGoHome, onMerchantPayUser }) => {
  const [insight, setInsight] = useState("Analizando tu crecimiento...");
  const [isConciliating, setIsConciliating] = useState(false);
  const [isCashierMode, setIsCashierMode] = useState(false);

  // States for Paying User Flow
  const [isPayingUser, setIsPayingUser] = useState(false);
  const [payStep, setPayStep] = useState<'ID' | 'AMOUNT' | 'CONFIRM' | 'SUCCESS'>('ID');
  const [targetPhone, setTargetPhone] = useState('');
  const [payAmount, setPayAmount] = useState('');
  const [payError, setPayError] = useState<string | null>(null);

  // Constants for math (simulated)
  const COMMISSION_RATE = 0.035; // 3.5% fee for digital sales
  const COLLECTION_INCENTIVE = 0.01; // 1% merchant earns for collecting cash

  useEffect(() => {
    async function fetchInsight() {
      const msg = await getMerchantInsight(merchant.earnings, merchant.cashCollected);
      setInsight(msg);
    }
    fetchInsight();
  }, [merchant.earnings, merchant.cashCollected]);

  if (isCashierMode) {
    return (
      <div className="animate-fadeIn">
        <button 
          onClick={() => setIsCashierMode(false)}
          className="absolute top-8 right-8 z-[110] bg-white w-10 h-10 rounded-full shadow-lg flex items-center justify-center text-[#1A1A40]"
        >
          <i className="fa-solid fa-xmark"></i>
        </button>
        <CashierView 
          merchantName={merchant.name} 
          onProcessTransaction={() => true} 
          mockUserBalance={0} 
          onGoHome={() => setIsCashierMode(false)}
        />
      </div>
    );
  }

  // Payment to User Flow Handlers
  const handleNextPayStep = () => {
    if (payStep === 'ID') {
      if (targetPhone.length < 10) return setPayError('Celular inválido');
      setPayError(null);
      setPayStep('AMOUNT');
    } else if (payStep === 'AMOUNT') {
      const amt = parseFloat(payAmount);
      if (isNaN(amt) || amt <= 0) return setPayError('Monto inválido');
      if (amt > merchant.earnings) return setPayError('Saldo insuficiente en tus ganancias');
      setPayError(null);
      setPayStep('CONFIRM');
    }
  };

  const handleConfirmPay = () => {
    const success = onMerchantPayUser(targetPhone, parseFloat(payAmount));
    if (success) {
      setPayStep('SUCCESS');
    } else {
      setPayError('Error al procesar el pago');
    }
  };

  const closePayFlow = () => {
    setIsPayingUser(false);
    setPayStep('ID');
    setTargetPhone('');
    setPayAmount('');
    setPayError(null);
  };

  // Calculations for "Cruce de Cuentas"
  const grossDigitalSales = merchant.piggyPayments;
  const systemCommission = grossDigitalSales * COMMISSION_RATE;
  const netDigitalSales = grossDigitalSales - systemCommission;

  const grossCashCollected = merchant.cashCollected;
  const collectionIncentiveAmount = grossCashCollected * COLLECTION_INCENTIVE;
  const netCashToPiggy = grossCashCollected - collectionIncentiveAmount;

