          </div>
        </div>
      </div>

      <div className="flex-1 p-6 flex flex-col">
        {step === 'TYPE' && (
          <div className="flex-1 flex flex-col justify-center space-y-6">
            <div className="text-center space-y-2 mb-4">
              <h3 className="text-3xl font-black text-[#1A1A40] italic uppercase">¿Qué haremos hoy?</h3>
              <p className="text-xs text-slate-400 font-bold uppercase">Operación de Caja</p>
            </div>
            <button onClick={() => { setTxType('SAVING'); setStep('PHONE'); }} className="group p-8 bg-white border-4 border-slate-100 rounded-[3rem] hover:border-[#CCFF00] transition-all flex items-center gap-6 active:scale-95 shadow-sm">
              <div className="w-20 h-20 bg-[#CCFF00] rounded-[2rem] flex items-center justify-center text-3xl text-[#1A1A40]">
                <i className="fa-solid fa-piggy-bank"></i>
              </div>
              <div className="text-left">
                <h4 className="text-xl font-black text-[#1A1A40] uppercase italic">Cargar Vueltas</h4>
                <p className="text-xs text-slate-400 font-bold">Abono al cerdito</p>
              </div>
            </button>
            <button onClick={() => { setTxType('PAYMENT'); setStep('PHONE'); }} className="group p-8 bg-white border-4 border-slate-100 rounded-[3rem] hover:border-[#FF007F] transition-all flex items-center gap-6 active:scale-95 shadow-sm">
              <div className="w-20 h-20 bg-[#FF007F] rounded-[2rem] flex items-center justify-center text-3xl text-white">
                <i className="fa-solid fa-cart-shopping"></i>
              </div>
              <div className="text-left">
                <h4 className="text-xl font-black text-[#1A1A40] uppercase italic">Cobro Digital</h4>
                <p className="text-xs text-slate-400 font-bold">Pago con ahorros</p>
              </div>
            </button>
          </div>
        )}

        {/* Dynamic Steps rendering logic remains exactly as before */}
        {step !== 'TYPE' && step !== 'SUCCESS' && (
          <div className="flex justify-between mb-10 px-4">
            {['PHONE', 'OTP', 'AMOUNT'].map((s, idx) => (
              <div key={s} className="flex flex-col items-center gap-2">
                <div className={`w-10 h-10 rounded-2xl flex items-center justify-center text-sm font-black border-2 transition-all ${step === s ? 'text-white scale-110 rotate-3' : 'bg-white border-slate-100 text-slate-200'}`} style={{ backgroundColor: step === s ? themeColor : '', borderColor: step === s ? themeColor : '' }}>
                  {idx + 1}
                </div>
              </div>
            ))}
          </div>
        )}

        {/* ... Logic for steps PHONE, OTP, AMOUNT, SUCCESS same as before ... */}
        {step === 'PHONE' && (
          <div className="space-y-6 animate-fadeIn flex-1 flex flex-col justify-center">
             <h3 className="text-2xl font-black text-[#1A1A40] text-center uppercase">Celular Cliente</h3>
             <div className="bg-white p-8 rounded-[2.5rem] border-2 border-slate-100 text-center text-4xl font-black text-[#1A1A40]">
                <span className="opacity-20 mr-2">+57</span>
                {phone || '3XX...'}
             </div>
          </div>
        )}

        {step === 'OTP' && (
          <div className="space-y-8 animate-fadeIn text-center flex-1 flex flex-col justify-center">
            <h3 className="text-2xl font-black text-[#1A1A40] uppercase">Código de Seguridad</h3>
            <div className="flex justify-center gap-4">
              {[0, 1, 2, 3].map(i => (
                <div key={i} className={`w-14 h-18 bg-white rounded-2xl border-2 flex items-center justify-center text-3xl font-black ${otp[i] ? 'text-white' : 'text-slate-100'}`} style={{ backgroundColor: otp[i] ? themeColor : '' }}>
                  {otp[i] || '•'}
                </div>
              ))}
            </div>
          </div>
        )}

        {step === 'AMOUNT' && (
          <div className="space-y-8 animate-fadeIn flex-1 flex flex-col justify-center">
            <h3 className="text-2xl font-black text-[#1A1A40] text-center uppercase">Monto Final</h3>
            <div className="p-10 rounded-[3rem] text-center" style={{ backgroundColor: themeColor }}>
              <div className="text-6xl font-black tracking-tighter italic" style={{ color: themeText }}>
                ${amount ? parseInt(amount).toLocaleString() : '0'}
              </div>
            </div>
            {error && <p className="text-rose-500 text-center font-black uppercase text-xs">{error}</p>}
          </div>
        )}

        {step === 'SUCCESS' && (
           <div className="text-center space-y-8 animate-fadeIn flex-1 flex flex-col justify-center">
              <div className="w-32 h-32 bg-[#CCFF00] rounded-[2.5rem] flex items-center justify-center mx-auto text-5xl">✅</div>
              <h3 className="text-3xl font-black text-[#1A1A40] uppercase">¡OPERACIÓN EXITOSA!</h3>
              <button onClick={reset} className="w-full py-5 bg-[#1A1A40] text-white rounded-2xl font-black">NUEVA TRANSACCIÓN</button>
           </div>
        )}

        {step !== 'SUCCESS' && step !== 'TYPE' && (
          <div className="mt-8 grid grid-cols-3 gap-3">
            {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(n => (
              <button key={n} onClick={() => handleKeypad(n.toString())} className="h-16 bg-white rounded-2xl font-black text-2xl border-b-4 border-slate-200">{n}</button>
            ))}
            <button onClick={handleBackspace} className="h-16 bg-white rounded-2xl font-black text-rose-500 border-b-4 border-slate-200">DEL</button>
            <button onClick={() => handleKeypad('0')} className="h-16 bg-white rounded-2xl font-black text-2xl border-b-4 border-slate-200">0</button>
            <button onClick={nextStep} className="h-16 bg-[#1A1A40] text-white rounded-2xl font-black" style={{ backgroundColor: themeColor, color: themeText }}>OK</button>
          </div>
        )}
      </div>
    </div>
  );
};

