           <div className="flex items-center gap-2 bg-[#FF007F]/5 text-[#FF007F] px-4 py-1.5 rounded-full text-[10px] font-black italic">
             <i className="fa-solid fa-chart-line"></i> +14%
           </div>
        </div>
        <div className="grid grid-cols-2 gap-6">
