import React, { useState, useEffect } from 'react';

interface CashierViewProps {
  merchantName: string;
  onProcessTransaction: (phone: string, amount: number, type: 'SAVING' | 'PAYMENT') => boolean;
  mockUserBalance: number;
  onGoHome: () => void;
}

type Step = 'TYPE' | 'PHONE' | 'OTP' | 'AMOUNT' | 'SUCCESS';

const CashierView: React.FC<CashierViewProps> = ({ merchantName, onProcessTransaction, mockUserBalance, onGoHome }) => {
  const [step, setStep] = useState<Step>('TYPE');
  const [txType, setTxType] = useState<'SAVING' | 'PAYMENT'>('SAVING');
  const [phone, setPhone] = useState('');
  const [otp, setOtp] = useState('');
  const [amount, setAmount] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isExistingUser, setIsExistingUser] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Onboarding States
  const [showOnboarding, setShowOnboarding] = useState(true);
  const [onboardingStep, setOnboardingStep] = useState(0);

  const onboardingData = [
    {
      title: "Terminal Operativa",
      desc: "Bienvenido a tu estación de trabajo. Aquí facilitarás el ahorro de cientos de clientes.",
      icon: "⚡",
      color: "#CCFF00"
    },
    {
      title: "Cargar Vueltas",
      desc: "Cuando un cliente paga en efectivo, ofrécele redondear sus vueltas directamente a su Piggy digital.",
      icon: "🐷",
      color: "#FF007F"
    },
    {
      title: "Cobro Digital",
      desc: "También puedes procesar pagos usando el saldo que los clientes ya tienen ahorrado en su cuenta.",
      icon: "💳",
      color: "#1A1A40"
    }
  ];

  useEffect(() => {
    if (phone === '3001234567') {
      setIsExistingUser(true);
    } else {
      setIsExistingUser(false);
    }
  }, [phone]);

  const handleKeypad = (val: string) => {
    setError(null);
    if (step === 'PHONE' && phone.length < 10) setPhone(prev => prev + val);
    if (step === 'OTP' && otp.length < 4) setOtp(prev => prev + val);
    if (step === 'AMOUNT') {
      if (amount === '0') setAmount(val);
      else setAmount(prev => prev + val);
    }
  };

  const handleBackspace = () => {
    if (step === 'PHONE') setPhone(prev => prev.slice(0, -1));
    if (step === 'OTP') setOtp(prev => prev.slice(0, -1));
    if (step === 'AMOUNT') setAmount(prev => prev.slice(0, -1));
  };

  const nextStep = () => {
    setIsLoading(true);
    setTimeout(() => {
      setIsLoading(false);
      if (step === 'PHONE') { setStep('OTP'); } 
      else if (step === 'OTP') { setStep('AMOUNT'); } 
      else if (step === 'AMOUNT') {
        const numericAmount = parseInt(amount);
        if (txType === 'PAYMENT' && isExistingUser && mockUserBalance < numericAmount) {
          setError(`Saldo insuficiente. El cliente solo tiene $${mockUserBalance.toLocaleString()}`);
          return;
        }
        const success = onProcessTransaction(phone, numericAmount, txType);
        if (success) { setStep('SUCCESS'); } 
        else { setError('Error procesando la transacción.'); }
      }
    }, 1000);
  };

  const reset = () => {
    setStep('TYPE'); setPhone(''); setOtp(''); setAmount(''); setIsExistingUser(false); setError(null);
  };

  const themeColor = txType === 'SAVING' ? '#CCFF00' : '#FF007F';
  const themeText = txType === 'SAVING' ? '#1A1A40' : '#FFFFFF';

  if (showOnboarding) {
    return (
      <div className="fixed inset-0 bg-white z-[100] flex flex-col items-center justify-center p-8 animate-fadeIn">
        <div className="w-full max-w-sm space-y-12 text-center">
          <div className="text-9xl mb-4 animate-pulse drop-shadow-2xl">{onboardingData[onboardingStep].icon}</div>
          <div className="space-y-4">
            <h2 className="text-4xl font-black text-[#1A1A40] italic uppercase tracking-tighter leading-tight">
              {onboardingData[onboardingStep].title}
            </h2>
            <p className="text-slate-400 font-black uppercase text-[10px] tracking-[0.4em]">OPERADOR POS</p>
            <p className="text-slate-500 font-medium leading-relaxed px-4">
              {onboardingData[onboardingStep].desc}
            </p>
          </div>

          <div className="flex justify-center gap-2">
            {onboardingData.map((_, i) => (
              <div key={i} className={`h-2 rounded-full transition-all duration-300 ${onboardingStep === i ? 'w-12 bg-[#FF007F] shadow-[0_0_15px_rgba(255,0,127,0.3)]' : 'w-2 bg-slate-100'}`}></div>
            ))}
          </div>

          <button 
            onClick={() => onboardingStep < 2 ? setOnboardingStep(onboardingStep + 1) : setShowOnboarding(false)}
            className="w-full py-6 bg-[#1A1A40] text-white rounded-[2.5rem] font-black shadow-2xl active:scale-95 transition-all border-b-8 border-black uppercase tracking-[0.2em] text-xs"
          >
            {onboardingStep === 2 ? 'INICIAR TERMINAL' : 'CONTINUAR'}
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-md mx-auto min-h-[85vh] bg-white flex flex-col animate-fadeIn border border-slate-100 rounded-[3rem] shadow-2xl relative overflow-hidden mb-12">
      <div className="p-8 bg-[#1A1A40] text-white flex justify-between items-center rounded-b-[4rem] shadow-2xl">
        <div className="space-y-1">
          <div className="flex items-center gap-2">
            <span className="w-2 h-2 bg-emerald-400 rounded-full animate-pulse"></span>
            <p className="text-[10px] font-black uppercase tracking-widest text-emerald-400">Terminal Activa</p>
          </div>
          <h2 className="text-xl font-black italic uppercase tracking-tighter">{merchantName}</h2>
        </div>
        <div className="flex gap-3">
          <button onClick={onGoHome} className="w-12 h-12 bg-white/10 hover:bg-[#CCFF00] hover:text-[#1A1A40] rounded-2xl flex items-center justify-center transition-all border border-white/10 shadow-inner">
            <i className="fa-solid fa-house text-sm"></i>
          </button>
          <div className="w-12 h-12 rounded-2xl flex items-center justify-center shadow-lg animate-bounce" style={{ backgroundColor: themeColor }}>
            <i className={`fa-solid ${txType === 'SAVING' ? 'fa-cash-register' : 'fa-hand-holding-dollar'} text-[#1A1A40] text-lg`}></i>
          </div>
        </div>
      </div>

      <div className="flex-1 p-8 flex flex-col">
        {step === 'TYPE' && (
          <div className="flex-1 flex flex-col justify-center space-y-8">
            <div className="text-center space-y-3 mb-4">
              <h3 className="text-3xl font-black text-[#1A1A40] italic uppercase tracking-tighter leading-tight">Operación POS</h3>
              <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Selecciona el tipo de proceso</p>
            </div>
            <button onClick={() => { setTxType('SAVING'); setStep('PHONE'); }} className="group p-8 bg-slate-50 border border-slate-100 rounded-[3.5rem] hover:bg-white hover:border-[#CCFF00] hover:shadow-2xl transition-all flex items-center gap-6 active:scale-95">
              <div className="w-20 h-20 bg-[#CCFF00] rounded-[2rem] flex items-center justify-center text-3xl text-[#1A1A40] shadow-lg border-b-4 border-lime-600">
                <i className="fa-solid fa-piggy-bank"></i>
              </div>
              <div className="text-left">
                <h4 className="text-xl font-black text-[#1A1A40] uppercase italic">Abonar Vueltas</h4>
                <p className="text-xs text-slate-400 font-bold uppercase tracking-tighter">Cargar ahorro</p>
              </div>
            </button>
            <button onClick={() => { setTxType('PAYMENT'); setStep('PHONE'); }} className="group p-8 bg-slate-50 border border-slate-100 rounded-[3.5rem] hover:bg-white hover:border-[#FF007F] hover:shadow-2xl transition-all flex items-center gap-6 active:scale-95">
              <div className="w-20 h-20 bg-[#FF007F] rounded-[2rem] flex items-center justify-center text-3xl text-white shadow-lg border-b-4 border-pink-900">
                <i className="fa-solid fa-cart-shopping"></i>
              </div>
              <div className="text-left">
                <h4 className="text-xl font-black text-[#1A1A40] uppercase italic">Cobro Digital</h4>
                <p className="text-xs text-slate-400 font-bold uppercase tracking-tighter">Gasto de ahorro</p>
              </div>
            </button>
          </div>
        )}

        {/* Dynamic Keypad logic (PHONE, OTP, AMOUNT) */}
        {step !== 'TYPE' && step !== 'SUCCESS' && (
           <div className="flex-1 flex flex-col">
              <div className="flex justify-between items-center mb-10 px-4">
                {['PHONE', 'OTP', 'AMOUNT'].map((s, idx) => (
                  <div key={s} className="flex flex-col items-center gap-2">
                    <div className={`w-12 h-12 rounded-[1.2rem] flex items-center justify-center text-sm font-black border-2 transition-all duration-500 ${step === s ? 'text-white scale-125 rotate-6 shadow-xl' : 'bg-white border-slate-100 text-slate-200'}`} style={{ backgroundColor: step === s ? themeColor : '', borderColor: step === s ? themeColor : '' }}>
                      {idx + 1}
                    </div>
                  </div>
                ))}
              </div>

              {step === 'PHONE' && (
                <div className="space-y-6 animate-fadeIn flex-1 flex flex-col justify-center">
                   <h3 className="text-2xl font-black text-[#1A1A40] text-center uppercase italic tracking-tighter">Identificar Cliente</h3>
                   <div className="bg-slate-50 p-10 rounded-[3rem] border border-slate-100 text-center text-4xl font-black text-[#1A1A40] shadow-inner">
                      <span className="opacity-20 mr-2">+57</span>
                      {phone || '...'}
                   </div>
                </div>
              )}

              {step === 'OTP' && (
                <div className="space-y-8 animate-fadeIn text-center flex-1 flex flex-col justify-center">
                  <h3 className="text-2xl font-black text-[#1A1A40] uppercase italic tracking-tighter">Verificación</h3>
                  <div className="flex justify-center gap-4">
                    {[0, 1, 2, 3].map(i => (
                      <div key={i} className={`w-16 h-20 bg-slate-50 rounded-3xl border-2 flex items-center justify-center text-4xl font-black transition-all ${otp[i] ? 'text-white border-transparent' : 'text-slate-200 border-slate-100'}`} style={{ backgroundColor: otp[i] ? themeColor : '' }}>
                        {otp[i] || '•'}
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {step === 'AMOUNT' && (
                <div className="space-y-8 animate-fadeIn flex-1 flex flex-col justify-center">
                  <h3 className="text-2xl font-black text-[#1A1A40] text-center uppercase italic tracking-tighter">Monto Final</h3>
                  <div className="p-12 rounded-[4rem] text-center shadow-2xl" style={{ backgroundColor: themeColor }}>
                    <div className="text-6xl font-black tracking-tighter italic" style={{ color: themeText }}>
                      ${amount ? parseInt(amount).toLocaleString() : '0'}
                    </div>
                  </div>
                  {error && (
                    <div className="bg-rose-50 p-4 rounded-2xl border border-rose-100 animate-shake">
                       <p className="text-rose-500 text-center font-black uppercase text-[10px] tracking-widest">{error}</p>
                    </div>
                  )}
                </div>
              )}

              <div className="mt-8 grid grid-cols-3 gap-4">
                {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(n => (
                  <button 
                    key={n} 
                    onClick={() => handleKeypad(n.toString())} 
                    className="h-20 bg-slate-50 text-[#1A1A40] rounded-3xl font-black text-2xl border border-slate-100 shadow-sm hover:bg-white hover:shadow-md transition-all active:scale-95"
                  >
                    {n}
                  </button>
                ))}
                <button 
                  onClick={handleBackspace} 
                  className="h-20 bg-rose-50 rounded-3xl font-black text-rose-500 border border-rose-100 shadow-sm active:scale-95 transition-all"
                >
                  <i className="fa-solid fa-delete-left text-2xl"></i>
                </button>
                <button 
                  onClick={() => handleKeypad('0')} 
                  className="h-20 bg-slate-50 text-[#1A1A40] rounded-3xl font-black text-2xl border border-slate-100 shadow-sm hover:bg-white hover:shadow-md transition-all active:scale-95"
                >
                  0
                </button>
                <button 
                  onClick={nextStep} 
                  className="h-20 rounded-3xl font-black shadow-xl active:scale-95 transition-all" 
                  style={{ backgroundColor: themeColor, color: themeText }}
                >
                  <i className="fa-solid fa-check text-2xl"></i>
                </button>
              </div>
           </div>
        )}

        {step === 'SUCCESS' && (
           <div className="text-center space-y-12 animate-fadeIn flex-1 flex flex-col justify-center">
              <div className="w-48 h-48 bg-[#CCFF00] rounded-[4rem] flex items-center justify-center mx-auto text-7xl shadow-2xl rotate-6">🎉</div>
              <div className="space-y-4">
                <h3 className="text-4xl font-black text-[#1A1A40] italic uppercase tracking-tighter">¡Listo!</h3>
                <p className="text-slate-400 font-bold uppercase text-xs tracking-widest">Transacción exitosa</p>
              </div>
              <button onClick={reset} className="w-full py-6 bg-[#1A1A40] text-white rounded-[2rem] font-black uppercase tracking-widest border-b-8 border-black shadow-2xl">OPERAR DE NUEVO</button>
           </div>
        )}
      </div>
    </div>
  );
};

