const MarketplaceView: React.FC<MarketplaceViewProps> = ({ products, userBalance, initialMerchant = 'Todos' }) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('Todas');
  const [selectedMerchant, setSelectedMerchant] = useState(initialMerchant);
  const [sortBy, setSortBy] = useState<'none' | 'priceAsc' | 'priceDesc'>('none');
  const [showFilters, setShowFilters] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [isSearchingAI, setIsSearchingAI] = useState(false);

  // Cart State
  const [cart, setCart] = useState<CartItem[]>([]);
  const [showCart, setShowCart] = useState(false);

  // Sync with initialMerchant from props
  useEffect(() => {
    if (initialMerchant) {
      setSelectedMerchant(initialMerchant);
      if (initialMerchant !== 'Todos') {
        setShowFilters(false);
      }
    }
  }, [initialMerchant]);

  const categories = useMemo(() => ['Todas', ...Array.from(new Set(products.map(p => p.category)))], [products]);
  const merchants = useMemo(() => ['Todos', ...Array.from(new Set(products.map(p => p.merchantName)))], [products]);

  const categoryCounts = useMemo(() => {
    const counts: Record<string, number> = {};
    products.forEach(p => {
      counts[p.category] = (counts[p.category] || 0) + 1;
    });
    return counts;
  }, [products]);

  const getCategoryIcon = (category: string) => {
    switch (category) {
      case 'Todas': return 'fa-border-all';
      case 'Alimentos': return 'fa-apple-whole';
      case 'Snacks': return 'fa-cookie-bite';
      case 'Aseo': return 'fa-soap';
      case 'Tecno': return 'fa-microchip';
      default: return 'fa-tag';
    }
  };

  const filteredAndSortedProducts = useMemo(() => {
    let result = products.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = selectedCategory === 'Todas' || p.category === selectedCategory;
      const matchesMerchant = selectedMerchant === 'Todos' || p.merchantName === selectedMerchant;
      return matchesSearch && matchesCategory && matchesMerchant;
    });

    if (sortBy === 'priceAsc') {
      result.sort((a, b) => a.price - b.price);
    } else if (sortBy === 'priceDesc') {
      result.sort((a, b) => b.price - a.price);
    }

    return result;
  }, [products, searchQuery, selectedCategory, selectedMerchant, sortBy]);

  useEffect(() => {
    let timeoutId: number;
    if (searchQuery.length > 2 && filteredAndSortedProducts.length === 0) {
      setIsSearchingAI(true);
      timeoutId = window.setTimeout(async () => {
        const aiSuggestions = await getSearchSuggestions(searchQuery, categories.filter(c => c !== 'Todas'));
        setSuggestions(aiSuggestions);
        setIsSearchingAI(false);
      }, 800);
    } else {
      setSuggestions([]);
      setIsSearchingAI(false);
    }
    return () => clearTimeout(timeoutId);
  }, [searchQuery, filteredAndSortedProducts.length, categories]);

  const addToCart = (product: Product) => {
    setCart(prevCart => {
      const existingItem = prevCart.find(item => item.id === product.id);
      if (existingItem) {
        return prevCart.map(item => 
          item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
        );
      }
      return [...prevCart, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (productId: string) => {
    setCart(prevCart => prevCart.filter(item => item.id !== productId));
  };

  const updateQuantity = (productId: string, delta: number) => {
    setCart(prevCart => prevCart.map(item => {
      if (item.id === productId) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const cartTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const cartItemCount = cart.reduce((sum, item) => sum + item.quantity, 0);
  const canAffordCart = userBalance >= cartTotal;

  const hasActiveFilters = selectedCategory !== 'Todas' || selectedMerchant !== 'Todos' || sortBy !== 'none' || searchQuery !== '';

  return (
    <div className="max-w-md mx-auto space-y-4 pb-24 px-4 relative">
      <div className="flex justify-between items-center mb-2">
        <h2 className="text-2xl font-black text-[#1A1A40] tracking-tight italic">MARKETPLACE</h2>
        <div className="flex gap-2">
          <button 
            onClick={() => setShowFilters(!showFilters)}
            className={`px-4 py-1.5 rounded-full shadow-sm border transition-all flex items-center gap-2 ${
              showFilters || hasActiveFilters
              ? 'bg-[#FF007F] border-[#FF007F] text-white' 
              : 'bg-white border-slate-100 text-slate-600'
            }`}
          >
            <i className="fa-solid fa-sliders text-xs"></i>
            <span className="text-xs font-bold">Filtros</span>
          </button>
        </div>
      </div>

      {/* Search Bar */}
      <div className="relative group">
        <i className="fa-solid fa-magnifying-glass absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 text-sm group-focus-within:text-[#FF007F] transition-colors"></i>
        <input 
          type="text" 
          placeholder="¿Qué quieres comprar con tu ahorro?" 
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
          className="w-full pl-11 pr-4 py-3.5 bg-white rounded-2xl shadow-sm border border-slate-100 text-sm focus:ring-2 focus:ring-pink-400 outline-none transition-all placeholder:text-slate-300 font-medium"
        />
      </div>

      {/* Active Filters Pills */}
      {hasActiveFilters && (
        <div className="flex gap-2 overflow-x-auto no-scrollbar py-1">
          {selectedMerchant !== 'Todos' && (
            <button 
              onClick={() => setSelectedMerchant('Todos')}
              className="flex items-center gap-2 px-3 py-1 bg-indigo-50 text-indigo-600 rounded-full text-[10px] font-black border border-indigo-100 shrink-0"
            >
              <span>TIENDA: {selectedMerchant}</span>
              <i className="fa-solid fa-xmark"></i>
            </button>
          )}
          {selectedCategory !== 'Todas' && (
            <button 
              onClick={() => setSelectedCategory('Todas')}
              className="flex items-center gap-2 px-3 py-1 bg-pink-50 text-[#FF007F] rounded-full text-[10px] font-black border border-pink-100 shrink-0"
            >
              <span>CAT: {selectedCategory}</span>
              <i className="fa-solid fa-xmark"></i>
            </button>
          )}
          {sortBy !== 'none' && (
            <button 
              onClick={() => setSortBy('none')}
              className="flex items-center gap-2 px-3 py-1 bg-slate-50 text-slate-500 rounded-full text-[10px] font-black border border-slate-100 shrink-0"
            >
              <span>ORDEN: {sortBy === 'priceAsc' ? '$$+' : '$$$'}</span>
              <i className="fa-solid fa-xmark"></i>
            </button>
          )}
          {searchQuery !== '' && (
            <button 
              onClick={() => setSearchQuery('')}
              className="flex items-center gap-2 px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full text-[10px] font-black border border-emerald-100 shrink-0"
            >
              <span>BUSCA: {searchQuery}</span>
              <i className="fa-solid fa-xmark"></i>
            </button>
          )}
        </div>
      )}

      {/* Merchants Explorer Section */}
      <div className="space-y-3">
        <div className="flex justify-between items-center px-1">
          <label className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em]">Tiendas Aliadas</label>
          <button 
            onClick={() => setSelectedMerchant('Todos')}
            className="text-[9px] font-black text-[#FF007F] uppercase tracking-tighter"
          >
            Ver todas
          </button>
        </div>
        <div className="flex gap-3 overflow-x-auto pb-2 no-scrollbar">
          {merchants.map(m => {
            const isActive = selectedMerchant === m;
            return (
              <button
                key={m}
                onClick={() => setSelectedMerchant(m)}
                className={`flex items-center gap-2 px-4 py-2.5 rounded-2xl border-2 transition-all shrink-0 ${
                  isActive 
                  ? 'bg-[#1A1A40] border-[#CCFF00] text-white shadow-lg scale-105' 
                  : 'bg-white border-slate-100 text-slate-600'
                }`}
              >
                <div className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-black ${isActive ? 'bg-[#CCFF00] text-[#1A1A40]' : 'bg-slate-100 text-slate-400'}`}>
                  {m === 'Todos' ? <i className="fa-solid fa-globe"></i> : m.charAt(0).toUpperCase()}
                </div>
                <span className="text-[11px] font-black whitespace-nowrap">{m}</span>
              </button>
            );
          })}
        </div>
      </div>

      {/* Expandable Filter Section */}
      {showFilters && (
        <div className="bg-white p-5 rounded-3xl shadow-xl border border-slate-100 space-y-4 animate-fadeIn">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Ordenar por precio</label>
            <div className="flex gap-2">
              <button 
                onClick={() => setSortBy(sortBy === 'priceAsc' ? 'none' : 'priceAsc')}
                className={`flex-1 py-2.5 rounded-xl text-[10px] font-black border transition-all ${sortBy === 'priceAsc' ? 'bg-[#1A1A40] text-white border-[#1A1A40]' : 'bg-slate-50 text-slate-500 border-slate-100'}`}
              >
                MENOR A MAYOR
              </button>
              <button 
                onClick={() => setSortBy(sortBy === 'priceDesc' ? 'none' : 'priceDesc')}
                className={`flex-1 py-2.5 rounded-xl text-[10px] font-black border transition-all ${sortBy === 'priceDesc' ? 'bg-[#1A1A40] text-white border-[#1A1A40]' : 'bg-slate-50 text-slate-500 border-slate-100'}`}
              >
                MAYOR A MENOR
              </button>
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Categoría</label>
            <select 
              value={selectedCategory}
              onChange={(e) => setSelectedCategory(e.target.value)}
              className="w-full p-3 bg-slate-50 rounded-xl text-xs border border-slate-100 focus:ring-2 focus:ring-pink-400 outline-none appearance-none font-bold"
            >
              {categories.map(cat => (
                <option key={cat} value={cat}>
                  {cat} {cat !== 'Todas' ? `(${categoryCounts[cat] || 0})` : `(${products.length})`}
                </option>
              ))}
            </select>
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Filtrar por Comercio</label>
            <select 
              value={selectedMerchant}
              onChange={(e) => setSelectedMerchant(e.target.value)}
              className="w-full p-3 bg-slate-50 rounded-xl text-xs border border-slate-100 focus:ring-2 focus:ring-pink-400 outline-none appearance-none font-bold"
            >
              {merchants.map(m => <option key={m} value={m}>{m}</option>)}
            </select>
          </div>

          <button 
            onClick={() => {
              setSelectedCategory('Todas');
              setSelectedMerchant('Todos');
              setSortBy('none');
              setSearchQuery('');
            }}
            className="w-full text-[10px] font-black text-[#FF007F] py-2 hover:underline uppercase tracking-widest"
          >
            Limpiar todos los filtros
          </button>
        </div>
      )}

      {/* Category Selection Pills */}
      <div className="space-y-2">
        <label className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Explorar Categorías</label>
        <div className="flex gap-3 overflow-x-auto pb-4 no-scrollbar">
          {categories.map(cat => {
            const isActive = selectedCategory === cat;
            return (
              <button
                key={cat}
                onClick={() => setSelectedCategory(cat)}
                className={`flex flex-col items-center gap-2 shrink-0 transition-all duration-300 group`}
              >
                <div className={`w-16 h-16 rounded-[1.8rem] flex flex-col items-center justify-center border-2 transition-all ${
                  isActive 
                  ? 'bg-[#1A1A40] border-[#1A1A40] text-[#CCFF00] shadow-xl scale-110 -translate-y-1' 
                  : 'bg-white border-slate-100 text-slate-400 group-hover:border-slate-300'
                }`}>
                  <i className={`fa-solid ${getCategoryIcon(cat)} text-xl`}></i>
                  <span className="text-[8px] font-black mt-1 opacity-60">
                    {cat === 'Todas' ? products.length : categoryCounts[cat] || 0}
                  </span>
                </div>
                <span className={`text-[10px] font-black uppercase tracking-tighter ${isActive ? 'text-[#1A1A40]' : 'text-slate-400'}`}>
                  {cat}
                </span>
              </button>
            );
          })}
        </div>
      </div>

      {/* Product Grid */}
      <div className="grid grid-cols-2 gap-4">
        {filteredAndSortedProducts.length > 0 ? (
          filteredAndSortedProducts.map((product) => {
            const canAfford = userBalance >= product.price;
            const inCart = cart.find(item => item.id === product.id);
            return (
              <div 
                key={product.id} 
                className="bg-white rounded-[2.5rem] p-4 shadow-sm border border-slate-100 flex flex-col h-full relative overflow-hidden transition-all hover:shadow-lg active:scale-[0.98] group"
              >
                {canAfford ? (
                  <div className="absolute top-3 left-3 bg-[#CCFF00] text-[#1A1A40] text-[9px] font-black px-2.5 py-1 rounded-full shadow-sm z-10 animate-pulse border border-[#1A1A40]/10">
                    ALCANZA 🐷
                  </div>
                ) : (
                  <div className="absolute top-3 left-3 bg-slate-100 text-slate-400 text-[8px] font-bold px-2 py-0.5 rounded-full z-10 border border-slate-200">
                    FALTA POCO
                  </div>
                )}

                <div className="aspect-square bg-slate-50 rounded-[1.8rem] mb-4 flex items-center justify-center text-5xl group-hover:scale-110 transition-transform duration-300 grayscale-[0.1]">
                  {product.imageUrl}
                </div>

                <div className="flex-1 space-y-1">
                  <div className="flex items-center gap-1.5">
                    <span className="text-[8px] font-black text-[#FF007F] bg-pink-50 px-2 py-0.5 rounded-full uppercase tracking-widest italic">
                      {product.category}
                    </span>
                  </div>
                  <h3 className="text-sm font-bold text-slate-800 leading-tight line-clamp-2 min-h-[2.5rem]">
                    {product.name}
                  </h3>
                  <button 
                    onClick={(e) => { e.stopPropagation(); setSelectedMerchant(product.merchantName); }}
                    className="flex items-center gap-1.5 opacity-60 hover:opacity-100 transition-opacity"
                  >
                     <i className="fa-solid fa-shop text-[8px]"></i>
                     <p className="text-[9px] font-bold text-slate-500 truncate underline decoration-dotted">
                       {product.merchantName}
                     </p>
                  </button>
                </div>

                <div className="mt-4 pt-3 border-t border-slate-50 flex flex-col gap-3">
                  <div className="flex items-baseline justify-between">
                     <span className="text-[9px] text-slate-400 font-bold uppercase">Precio</span>
                     <span className="text-lg font-black text-[#1A1A40]">
                       ${product.price.toLocaleString()}
                     </span>
                  </div>

                  <button 
                    onClick={() => addToCart(product)}
                    className={`w-full py-3 rounded-2xl text-[10px] font-black transition-all flex items-center justify-center gap-2 ${
                      inCart 
                      ? 'bg-emerald-500 text-white shadow-lg' 
                      : 'bg-[#1A1A40] text-white shadow-xl shadow-blue-900/20 active:scale-95'
                    }`}
                  >
                    {inCart ? (
                      <>
                        <i className="fa-solid fa-check"></i>
                        AGREGADO ({inCart.quantity})
                      </>
                    ) : (
                      <>
                        <i className="fa-solid fa-cart-plus"></i>
                        AGREGAR
                      </>
                    )}
                  </button>
                </div>
              </div>
            );
          })
        ) : (
          <div className="col-span-2 py-12 text-center space-y-6">
             <div className="w-24 h-24 bg-slate-100 rounded-full flex items-center justify-center mx-auto text-5xl animate-bounce">
               🐷
             </div>
             <div className="px-6 space-y-4">
               <div className="space-y-1">
                 <p className="text-sm text-slate-800 font-black italic">"¡Oink! No encontré nada para '{searchQuery}'"</p>
                 <p className="text-xs text-slate-400 font-bold uppercase tracking-tight">Pero tengo algunas ideas para ti:</p>
               </div>

               {isSearchingAI ? (
                 <div className="flex flex-col items-center gap-2">
                   <div className="flex gap-1">
                     <div className="w-1.5 h-1.5 bg-[#FF007F] rounded-full animate-bounce delay-75"></div>
                     <div className="w-1.5 h-1.5 bg-[#FF007F] rounded-full animate-bounce delay-150"></div>
                     <div className="w-1.5 h-1.5 bg-[#FF007F] rounded-full animate-bounce delay-300"></div>
                   </div>
                   <p className="text-[9px] font-black text-slate-300 uppercase italic">Piggy AI está pensando...</p>
                 </div>
               ) : (
                 <div className="flex flex-wrap justify-center gap-2 animate-fadeIn">
                   {suggestions.length > 0 ? (
                     suggestions.map((suggestion, i) => (
                       <button 
                         key={i}
                         onClick={() => setSearchQuery(suggestion)}
                         className="px-4 py-2 bg-pink-50 text-[#FF007F] rounded-full text-[10px] font-black border border-pink-100 shadow-sm hover:bg-[#FF007F] hover:text-white transition-all"
                       >
                         {suggestion}
                       </button>
                     ))
                   ) : (
                     categories.filter(c => c !== 'Todas').map((cat, i) => (
                        <button 
                          key={i}
                          onClick={() => {setSelectedCategory(cat); setSearchQuery('');}}
                          className="px-4 py-2 bg-slate-50 text-[#1A1A40] rounded-full text-[10px] font-black border border-slate-100 shadow-sm hover:bg-[#1A1A40] hover:text-white transition-all"
                        >
                          {cat}
                        </button>
                     ))
                   )}
                 </div>
               )}

               <button 
                onClick={() => {setSelectedCategory('Todas'); setSelectedMerchant('Todos'); setSearchQuery('');}}
                className="text-[10px] font-black text-[#FF007F] mt-6 uppercase underline tracking-[0.2em]"
               >
                 Explorar todo el Marketplace
               </button>
             </div>
          </div>
        )}
      </div>

      {/* Floating Cart Button */}
      {cart.length > 0 && (
        <button 
          onClick={() => setShowCart(true)}
          className="fixed bottom-24 right-6 w-16 h-16 bg-[#FF007F] text-white rounded-full shadow-2xl flex items-center justify-center z-[60] animate-bounce active:scale-90 transition-transform"
        >
          <div className="relative">
            <i className="fa-solid fa-shopping-basket text-2xl"></i>
            <span className="absolute -top-3 -right-3 bg-[#CCFF00] text-[#1A1A40] text-[10px] font-black w-6 h-6 rounded-full flex items-center justify-center border-2 border-[#FF007F]">
              {cartItemCount}
            </span>
          </div>
        </button>
      )}

      {/* Cart Drawer Overlay */}
      {showCart && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-end justify-center animate-fadeIn" onClick={() => setShowCart(false)}>
          <div className="w-full max-w-md bg-white rounded-t-[3rem] p-8 max-h-[80vh] overflow-y-auto shadow-2xl animate-slideUp" onClick={e => e.stopPropagation()}>
            <div className="w-12 h-1.5 bg-slate-200 rounded-full mx-auto mb-6"></div>

            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-black text-[#1A1A40]">Tu Canasta Piggy</h3>
              <button onClick={() => setShowCart(false)} className="w-10 h-10 bg-slate-100 rounded-full flex items-center justify-center text-slate-400">
                <i className="fa-solid fa-times"></i>
              </button>
            </div>

            <div className="space-y-4 mb-8">
              {cart.map(item => (
                <div key={item.id} className="flex items-center gap-4 bg-slate-50 p-4 rounded-[2rem] border border-slate-100">
                  <div className="w-16 h-16 bg-white rounded-2xl flex items-center justify-center text-3xl shadow-sm">
                    {item.imageUrl}
                  </div>
                  <div className="flex-1">
                    <h4 className="text-sm font-bold text-slate-800 line-clamp-1">{item.name}</h4>
                    <p className="text-xs text-slate-400 mb-2">por {item.merchantName}</p>
                    <div className="flex items-center justify-between">
                      <div className="flex items-center gap-3 bg-white px-3 py-1.5 rounded-full border border-slate-100">
                        <button onClick={() => updateQuantity(item.id, -1)} className="text-[#FF007F]"><i className="fa-solid fa-minus"></i></button>
                        <span className="text-sm font-black w-4 text-center">{item.quantity}</span>
                        <button onClick={() => updateQuantity(item.id, 1)} className="text-[#FF007F]"><i className="fa-solid fa-plus"></i></button>
                      </div>
                      <p className="text-sm font-black text-[#1A1A40]">${(item.price * item.quantity).toLocaleString()}</p>
                    </div>
                  </div>
                  <button onClick={() => removeFromCart(item.id)} className="text-rose-500 p-2"><i className="fa-solid fa-trash-can"></i></button>
                </div>
              ))}
            </div>

            <div className="bg-[#1A1A40] text-white p-6 rounded-[2.5rem] space-y-4 shadow-xl">
              <div className="flex justify-between items-center opacity-70 text-sm">
                <span>Saldo en Piggybanko</span>
                <span>${userBalance.toLocaleString()}</span>
              </div>
              <div className="flex justify-between items-end border-t border-white/10 pt-4">
                <span className="text-lg font-bold">Total a pagar</span>
                <span className="text-2xl font-black text-[#CCFF00]">${cartTotal.toLocaleString()}</span>
              </div>

              {!canAffordCart && (
                <div className="bg-rose-500/20 text-rose-200 p-3 rounded-2xl text-[10px] font-bold text-center border border-rose-500/30">
                  ⚠️ Te faltan ${(cartTotal - userBalance).toLocaleString()} para esta compra.
                </div>
              )}

              <button 
                disabled={!canAffordCart || cart.length === 0}
                className={`w-full py-4 rounded-2xl font-black flex items-center justify-center gap-3 transition-all ${
                  canAffordCart && cart.length > 0 
                  ? 'bg-[#FF007F] text-white shadow-lg active:scale-95' 
                  : 'bg-white/10 text-white/30 cursor-not-allowed'
                }`}
              >
                <i className="fa-solid fa-check-double"></i>
                COMPRAR CON MI AHORRO
              </button>
            </div>

            <p className="text-center text-[10px] text-slate-400 mt-6 font-bold uppercase tracking-widest">
              El ahorro de hoy es el capricho de mañana.
            </p>
          </div>
        </div>
      )}

      <div className="text-center pb-8">
        <p className="text-[9px] text-slate-400 font-medium font-bold uppercase tracking-widest">
          Tus ahorros en Piggybanko valen más en comercios aliados.
        </p>
      </div>
    </div>
  );
};

export default MarketplaceView;

import React, { useState } from 'react';
import { AppRole, UserAccount, MerchantAccount, Product, Promotion, Transaction } from './types';
import { Logo, COLORS } from './constants';
import UserView from './components/UserView';
import MerchantView from './components/MerchantView';
import AdminView from './components/AdminView';
import MarketplaceView from './components/MarketplaceView';
import MerchantInventory from './components/MerchantInventory';
import MerchantPromotions from './components/MerchantPromotions';
import PromotionsView from './components/PromotionsView';
import MapView from './components/MapView';
import CashierView from './components/CashierView';
import LoginView from './components/LoginView';

type SubView = 'HOME' | 'MARKETPLACE' | 'PROMOTIONS' | 'MAP';

const App: React.FC = () => {
  const [role, setRole] = useState<AppRole>(AppRole.USER);
  const [isLogged, setIsLogged] = useState(false);
  const [phoneNumber, setPhoneNumber] = useState('');
  const [activeTab, setActiveTab] = useState<SubView>('HOME');
  const [marketplaceMerchantFilter, setMarketplaceMerchantFilter] = useState('Todos');

  // Cashier Auth States
  const [cashierPin, setCashierPin] = useState('');
  const [storeCode, setStoreCode] = useState('');
  const [loginError, setLoginError] = useState(false);

  // Mock Data
  const [user, setUser] = useState<UserAccount>({
    id: 'valen-001',
    phone: '3001234567',
    balance: 45350,
    xp: 650,
    level: 2,
    goalName: 'Tenis Nike Air',
    goalTarget: 70000,
    lastYield: 5
  });

  const [merchants, setMerchants] = useState<MerchantAccount[]>([
    {
      id: 'roberto-pos',
      name: 'Don Roberto',
      cashCollected: 150000,
      piggyPayments: 20000,
      quotaUsed: 130000,
      quotaLimit: 200000,
      earnings: 377500,
      address: 'Calle 45 # 7-12',
      lat: 4.6300, 
      lng: -74.0700,
      type: 'SUPERMARKET'
    }
  ]);

  const merchant = merchants[0];

  const [products, setProducts] = useState<Product[]>([
    { id: 'p1', merchantId: 'roberto-pos', merchantName: 'Don Roberto', name: 'Leche Deslactosada 1L', price: 4200, category: 'Alimentos', imageUrl: '🥛' },
    { id: 'p2', merchantId: 'roberto-pos', merchantName: 'Don Roberto', name: 'Pan Tajado Familiar', price: 5500, category: 'Alimentos', imageUrl: '🍞' },
    { id: 'p3', merchantId: 'roberto-pos', merchantName: 'Don Roberto', name: 'Huevos AA x30', price: 16000, category: 'Alimentos', imageUrl: '🥚' },
  ]);

  const [promotions, setPromotions] = useState<Promotion[]>([
    { 
      id: 'promo-1', 
      merchantId: 'roberto-pos', 
      merchantName: 'Don Roberto', 
      title: 'Pack Parrillero Familiar', 
      description: 'Llévate todo para el asado pagando una parte con tu cerdito.', 
      piggyPrice: 15000, 
      otherPrice: 35000, 
      totalValue: 65000, 
      imageUrl: '🥩', 
      expiryDate: '12h 45m', 
      category: 'Alimentos' 
    }
  ]);

  const handleLoginAction = (selectedRole: AppRole, phone: string, pin?: string, code?: string, name?: string) => {
    setLoginError(false);
    setRole(selectedRole);
    setPhoneNumber(phone);

    // Si hay un nombre, simulamos registro actualizando el usuario mock
    if (name) {
      setUser(prev => ({ ...prev, phone, id: `user-${Date.now()}` }));
    }

    if (selectedRole === AppRole.CASHIER) {
      if (pin === '1234' && code?.toUpperCase() === 'PIGGY-001' && phone.length >= 10) {
        setIsLogged(true);
      } else {
        setLoginError(true);
      }
    } else {
      if (phone.length >= 10) {
        setIsLogged(true);
      } else {
        setLoginError(true);
      }
    }
  };

  const handleLogout = () => {
    setIsLogged(false);
    setActiveTab('HOME');
    setLoginError(false);
  };

  // Acciones de Gestión
  const addProduct = (newProduct: Omit<Product, 'id' | 'merchantId' | 'merchantName'>) => {
    const product: Product = {
      ...newProduct,
      id: `p-${Date.now()}`,
      merchantId: merchant.id,
      merchantName: merchant.name
    };
    setProducts([product, ...products]);
  };

  const removeProduct = (id: string) => {
    setProducts(products.filter(p => p.id !== id));
  };

  const addPromotion = (newPromo: Omit<Promotion, 'id' | 'merchantId' | 'merchantName'>) => {
    const promo: Promotion = {
      ...newPromo,
      id: `promo-${Date.now()}`,
      merchantId: merchant.id,
      merchantName: merchant.name
    };
    setPromotions([promo, ...promotions]);
  };

  const removePromotion = (id: string) => {
    setPromotions(promotions.filter(p => p.id !== id));
  };

  const handleProcessTransaction = (targetPhone: string, amount: number, type: 'SAVING' | 'PAYMENT') => {
    const numericAmount = Number(amount);
    if (type === 'SAVING') {
      setMerchants(prev => prev.map(m => m.id === merchant.id ? { ...m, cashCollected: m.cashCollected + numericAmount } : m));
      if (targetPhone === user.phone || targetPhone === '3001234567') {
        setUser(prev => ({ ...prev, balance: prev.balance + numericAmount, xp: prev.xp + 50 }));
      }
    } else {
      if (targetPhone === user.phone || targetPhone === '3001234567') {
        if (user.balance < numericAmount) return false;
        setUser(prev => ({ ...prev, balance: prev.balance - numericAmount, xp: prev.xp + 20 }));
      }
      setMerchants(prev => prev.map(m => m.id === merchant.id ? { ...m, piggyPayments: m.piggyPayments + numericAmount } : m));
    }
    return true;
  };

  const handleMerchantPayUser = (targetPhone: string, amount: number) => {
    if (merchant.earnings < amount) return false;
    setMerchants(prev => prev.map(m => m.id === merchant.id ? { ...m, earnings: m.earnings - amount } : m));
    if (targetPhone === user.phone || targetPhone === '3001234567') {
      setUser(prev => ({ ...prev, balance: prev.balance + amount }));
    }
    return true;
  };

  const goHome = () => {
    setActiveTab('HOME');
    setMarketplaceMerchantFilter('Todos');
  };

  const handleViewStore = (merchantName: string) => {
    setMarketplaceMerchantFilter(merchantName);
    setActiveTab('MARKETPLACE');
  };

  const merchantProducts = products.filter(p => p.merchantId === merchant.id);

  const renderContent = () => {
    if (role === AppRole.CASHIER) {
      return (
        <CashierView 
          merchantName={merchant.name} 
          onProcessTransaction={handleProcessTransaction}
          mockUserBalance={user.balance}
          onGoHome={goHome}
        />
      );
    }
    if (role === AppRole.USER) {
      switch(activeTab) {
        case 'MARKETPLACE': return <MarketplaceView products={products} userBalance={user.balance} initialMerchant={marketplaceMerchantFilter} />;
        case 'PROMOTIONS': return <PromotionsView promotions={promotions} userBalance={user.balance} />;
        case 'MAP': return <MapView merchants={merchants} userBalance={user.balance} onViewStore={handleViewStore} />;
        default: return <UserView user={user} onGoHome={goHome} />;
      }
    }
    if (role === AppRole.MERCHANT) {
      switch(activeTab) {
        case 'MARKETPLACE': return <MerchantInventory products={merchantProducts} onAddProduct={addProduct} onRemoveProduct={removeProduct} />;
        case 'PROMOTIONS': return <MerchantPromotions promotions={promotions.filter(p => p.merchantId === merchant.id)} onAddPromotion={addPromotion} onRemovePromotion={removePromotion} />;
        default: return <MerchantView merchant={merchant} products={merchantProducts} onGoHome={goHome} onMerchantPayUser={handleMerchantPayUser} />;
      }
    }
    return <AdminView />;
  };

  if (!isLogged) {
    return <LoginView onLogin={handleLoginAction} loginError={loginError} />;
  }

  return (
    <div className="min-h-screen bg-white pt-8 overflow-x-hidden">
      <div className="max-w-md md:max-w-4xl mx-auto px-4 flex justify-between items-center mb-8">
        <button onClick={goHome} className="hover:scale-105 active:scale-95 transition-transform">
          <Logo />
        </button>
        <div className="flex items-center gap-3">
          {role === AppRole.CASHIER && (
            <div className="hidden md:flex flex-col items-end">
              <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Cajero Activo</span>
              <span className="text-[10px] font-bold text-[#1A1A40]">ID: {phoneNumber.slice(-4)}</span>
            </div>
          )}
          <button 
            onClick={handleLogout} 
            className="w-10 h-10 bg-white rounded-full shadow-md flex items-center justify-center text-slate-400 border border-slate-100 active:bg-rose-50 hover:text-rose-500 transition-all group"
            title="Cerrar Sesión"
          >
            <i className="fa-solid fa-sign-out group-hover:translate-x-0.5 transition-transform"></i>
          </button>
        </div>
      </div>

      <div className="animate-fadeIn">
        {renderContent()}
      </div>

      {(role === AppRole.USER || role === AppRole.MERCHANT) && (
        <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-[90%] max-w-sm bg-[#1A1A40] text-white rounded-3xl p-4 flex justify-between items-center shadow-2xl z-50">
          <button onClick={goHome} className={`flex flex-col items-center gap-1 transition-all ${activeTab === 'HOME' ? 'text-[#FF007F]' : 'opacity-50'}`}>
            <i className="fa-solid fa-house"></i>
            <span className="text-[10px]">Inicio</span>
          </button>
          <button onClick={() => setActiveTab('MARKETPLACE')} className={`flex flex-col items-center gap-1 transition-all ${activeTab === 'MARKETPLACE' ? 'text-[#FF007F]' : 'opacity-50'}`}>
            <i className={`fa-solid ${role === AppRole.USER ? 'fa-store' : 'fa-boxes-stacked'}`}></i>
            <span className="text-[10px]">{role === AppRole.USER ? 'Tienda' : 'Inventario'}</span>
          </button>
          <div className="relative -top-10">
            <button className="w-14 h-14 bg-[#FF007F] rounded-full flex items-center justify-center text-white shadow-lg border-4 border-white active:scale-90 transition-transform">
              <i className="fa-solid fa-qrcode text-xl"></i>
            </button>
          </div>
          <button onClick={() => setActiveTab('PROMOTIONS')} className={`flex flex-col items-center gap-1 transition-all ${activeTab === 'PROMOTIONS' ? 'text-[#FF007F]' : 'opacity-50'}`}>
            <i className={`fa-solid ${role === AppRole.USER ? 'fa-tags' : 'fa-bullhorn'}`}></i>
            <span className="text-[10px]">{role === AppRole.USER ? 'Promos' : 'Campañas'}</span>
          </button>
          <button onClick={() => role === AppRole.USER ? setActiveTab('MAP') : setActiveTab('HOME')} className={`flex flex-col items-center gap-1 transition-all ${activeTab === 'MAP' ? 'text-[#FF007F]' : 'opacity-50'}`}>
            <i className={`fa-solid ${role === AppRole.USER ? 'fa-map-location-dot' : 'fa-chart-line'}`}></i>
            <span className="text-[10px]">{role === AppRole.USER ? 'Mapa' : 'Métricas'}</span>
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { MerchantAccount, Product } from '../types';
import { getMerchantInsight } from '../services/geminiService';
import { COLORS } from '../constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import CashierView from './CashierView';

interface MerchantViewProps {
  merchant: MerchantAccount;
  products?: Product[];
  onGoHome: () => void;
  onMerchantPayUser: (phone: string, amount: number) => boolean;
}

const MerchantView: React.FC<MerchantViewProps> = ({ merchant, products = [], onGoHome, onMerchantPayUser }) => {
  const [insight, setInsight] = useState("Analizando tu crecimiento...");
  const [isConciliating, setIsConciliating] = useState(false);
  const [isCashierMode, setIsCashierMode] = useState(false);

  // Onboarding States
  const [showOnboarding, setShowOnboarding] = useState(true);
  const [step, setStep] = useState(0);

  // States for Paying User Flow
  const [isPayingUser, setIsPayingUser] = useState(false);
  const [payStep, setPayStep] = useState<'ID' | 'AMOUNT' | 'CONFIRM' | 'SUCCESS'>('ID');
  const [targetPhone, setTargetPhone] = useState('');
  const [payAmount, setPayAmount] = useState('');
  const [payError, setPayError] = useState<string | null>(null);

  useEffect(() => {
    async function fetchInsight() {
      const msg = await getMerchantInsight(merchant.earnings, merchant.cashCollected);
      setInsight(msg);
    }
    fetchInsight();
  }, [merchant.earnings, merchant.cashCollected]);

  const onboardingSteps = [
    {
      title: "Bienvenido, Socio",
      desc: "Piggybanko convierte tu negocio en un punto de ahorro digital. Aquí verás cómo crece tu rentabilidad.",
      icon: "🏪",
      color: "#1A1A40"
    },
    {
      title: "Gana por Recaudar",
      desc: "Por cada peso que recibas de un usuario para su ahorro, tú ganas el 1% de comisión inmediata.",
      icon: "💰",
      color: "#FF007F"
    },
    {
      title: "Vende en el Marketplace",
      desc: "Tus productos están visibles para miles de ahorradores que quieren gastar su 'cerdito' en tu tienda.",
      icon: "🚀",
      color: "#FF007F"
    }
  ];

  if (showOnboarding) {
    return (
      <div className="fixed inset-0 bg-white z-[100] flex flex-col items-center justify-center p-8 animate-fadeIn">
        <div className="w-full max-w-sm space-y-12 text-center">
          <div className="text-9xl mb-4 animate-bounce drop-shadow-2xl">{onboardingSteps[step].icon}</div>
          <div className="space-y-4">
            <h2 className="text-4xl font-black text-[#1A1A40] italic uppercase tracking-tighter leading-tight">
              {onboardingSteps[step].title}
            </h2>
            <p className="text-slate-500 font-medium leading-relaxed px-4">
              {onboardingSteps[step].desc}
            </p>
          </div>

          <div className="flex justify-center gap-2">
            {onboardingSteps.map((_, i) => (
              <div key={i} className={`h-2 rounded-full transition-all duration-300 ${step === i ? 'w-12 bg-[#FF007F] shadow-[0_0_15px_#FF007F]' : 'w-2 bg-slate-100'}`}></div>
            ))}
          </div>

          <button 
            onClick={() => step < 2 ? setStep(step + 1) : setShowOnboarding(false)}
            className="w-full py-6 bg-[#1A1A40] text-white rounded-[2.5rem] font-black shadow-2xl active:scale-95 transition-all border-b-8 border-black uppercase tracking-[0.2em] text-xs"
          >
            {step === 2 ? '¡ACTIVAR MI NEGOCIO!' : 'ENTIENDO, SIGUIENTE'}
          </button>
        </div>
      </div>
    );
  }

  const handleExecutePayment = () => {
    setPayError(null);
    const amount = parseFloat(payAmount);
    if (isNaN(amount) || amount <= 0) {
      setPayError("Monto inválido");
      return;
    }
    if (amount > merchant.earnings) {
      setPayError("Saldo insuficiente en ganancias");
      return;
    }
    if (targetPhone.length < 10) {
      setPayError("Número de celular incompleto");
      return;
    }

    const success = onMerchantPayUser(targetPhone, amount);
    if (success) {
      setPayStep('SUCCESS');
    } else {
      setPayError("Error procesando el pago");
    }
  };

  const renderPayUserFlow = () => {
    return (
      <div className="fixed inset-0 bg-white z-[100] flex flex-col p-6 animate-fadeIn">
        <div className="max-w-md mx-auto w-full flex flex-col h-full">
          <div className="flex items-center justify-between mb-8">
            <button 
              onClick={() => { setIsPayingUser(false); setPayStep('ID'); setPayAmount(''); setTargetPhone(''); }}
              className="w-10 h-10 bg-slate-50 rounded-full flex items-center justify-center text-slate-400"
            >
              <i className="fa-solid fa-arrow-left"></i>
            </button>
            <h3 className="font-black text-[#1A1A40] uppercase tracking-widest text-xs">Pago a Usuario</h3>
            <div className="w-10"></div>
          </div>

          <div className="flex-1 space-y-8 flex flex-col justify-center">
            {payStep === 'ID' && (
              <div className="space-y-6 animate-slideLeft">
                <div className="text-center space-y-2">
                  <div className="w-20 h-20 bg-indigo-50 text-indigo-600 rounded-[2rem] flex items-center justify-center text-3xl mx-auto shadow-inner">
                    <i className="fa-solid fa-user-tag"></i>
                  </div>
                  <h4 className="text-2xl font-black text-[#1A1A40] italic uppercase tracking-tighter">¿A quién pagamos?</h4>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Ingresa el celular del cliente</p>
                </div>
                <div className="bg-slate-50 border border-slate-100 p-6 rounded-[2.5rem] flex items-center gap-4 focus-within:ring-4 focus-within:ring-indigo-50 transition-all">
                  <span className="text-slate-300 font-black text-xl">+57</span>
                  <input 
                    type="tel"
                    value={targetPhone}
                    onChange={(e) => setTargetPhone(e.target.value.replace(/\D/g, '').slice(0, 10))}
                    className="bg-transparent outline-none text-[#1A1A40] font-black text-2xl w-full"
                    placeholder="300 000 0000"
                  />
                </div>
                <button 
                  onClick={() => targetPhone.length === 10 && setPayStep('AMOUNT')}
                  disabled={targetPhone.length < 10}
                  className={`w-full py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest transition-all ${targetPhone.length === 10 ? 'bg-[#1A1A40] text-white shadow-xl' : 'bg-slate-100 text-slate-300'}`}
                >
                  SIGUIENTE
                </button>
              </div>
            )}

            {payStep === 'AMOUNT' && (
              <div className="space-y-6 animate-slideLeft">
                <div className="text-center space-y-2">
                  <h4 className="text-2xl font-black text-[#1A1A40] italic uppercase tracking-tighter">¿Cuánto enviamos?</h4>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Saldo disponible: ${merchant.earnings.toLocaleString()}</p>
                </div>
                <div className="bg-slate-50 border border-slate-100 p-8 rounded-[3rem] text-center shadow-inner">
                  <div className="flex items-center justify-center gap-2">
                    <span className="text-3xl font-black text-slate-300">$</span>
                    <input 
                      type="number"
                      value={payAmount}
                      onChange={(e) => setPayAmount(e.target.value)}
                      className="bg-transparent outline-none text-[#1A1A40] font-black text-5xl w-full text-center"
                      placeholder="0"
                    />
                  </div>
                </div>
                {payError && <p className="text-rose-500 text-[10px] font-black text-center uppercase tracking-tight">{payError}</p>}
                <button 
                  onClick={() => parseFloat(payAmount) > 0 && setPayStep('CONFIRM')}
                  className="w-full py-5 bg-[#1A1A40] text-white rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-xl"
                >
                  REVISAR PAGO
                </button>
              </div>
            )}

            {payStep === 'CONFIRM' && (
              <div className="space-y-8 animate-slideUp">
                <div className="bg-slate-900 text-white p-8 rounded-[3.5rem] shadow-2xl space-y-6 relative overflow-hidden">
                  <div className="absolute -top-10 -right-10 w-32 h-32 bg-indigo-500 rounded-full blur-[80px] opacity-20"></div>
                  <div className="space-y-1 relative z-10">
                    <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Confirmar Transacción</p>
                    <h4 className="text-3xl font-black italic tracking-tighter uppercase">RESUMEN</h4>
                  </div>
                  <div className="space-y-4 relative z-10">
                    <div className="flex justify-between items-center border-b border-white/10 pb-4">
                      <span className="text-white/40 text-[10px] font-bold uppercase">Destinatario</span>
                      <span className="font-black text-indigo-300">+57 {targetPhone}</span>
                    </div>
                    <div className="flex justify-between items-center">
                      <span className="text-white/40 text-[10px] font-bold uppercase">Monto Total</span>
                      <span className="text-2xl font-black text-[#FF007F]">${parseFloat(payAmount).toLocaleString()}</span>
                    </div>
                  </div>
                </div>
                <button 
                  onClick={handleExecutePayment}
                  className="w-full py-6 bg-[#FF007F] text-white rounded-[2.5rem] font-black text-xs uppercase tracking-widest shadow-2xl active:scale-95 border-b-8 border-pink-900"
                >
                  CONFIRMAR Y PAGAR AHORA 💸
                </button>
              </div>
            )}

            {payStep === 'SUCCESS' && (
              <div className="text-center space-y-10 animate-fadeIn">
                <div className="w-48 h-48 bg-[#FF007F] rounded-[4rem] flex items-center justify-center mx-auto text-7xl shadow-2xl rotate-6 animate-bounce">
                  ✨
                </div>
                <div className="space-y-3">
                  <h4 className="text-4xl font-black text-[#1A1A40] italic uppercase tracking-tighter">¡Pago Enviado!</h4>
                  <p className="text-slate-400 font-bold uppercase text-[10px] tracking-widest">El cliente ya tiene su saldo disponible.</p>
                </div>
                <button 
                  onClick={() => { setIsPayingUser(false); setPayStep('ID'); setPayAmount(''); setTargetPhone(''); }}
                  className="w-full py-6 bg-[#1A1A40] text-white rounded-[2rem] font-black uppercase tracking-widest border-b-8 border-black shadow-2xl"
                >
                  VOLVER AL PANEL
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  };

  if (isPayingUser) {
    return renderPayUserFlow();
  }

  if (isCashierMode) {
    return (
      <div className="animate-fadeIn">
        <button 
          onClick={() => setIsCashierMode(false)}
          className="absolute top-8 right-8 z-[110] bg-white w-12 h-12 rounded-full shadow-2xl flex items-center justify-center text-[#1A1A40] border border-slate-100 hover:text-rose-500 transition-all"
        >
          <i className="fa-solid fa-xmark text-lg"></i>
        </button>
        <CashierView 
          merchantName={merchant.name} 
          onProcessTransaction={() => true} 
          mockUserBalance={0} 
          onGoHome={() => setIsCashierMode(false)}
        />
      </div>
    );
  }

  // Calculations for charts and data
  const grossDigitalSales = merchant.piggyPayments;
  const netDigitalSales = grossDigitalSales * 0.965;
  const netCashToPiggy = merchant.cashCollected * 0.99;
  const finalBalance = netCashToPiggy - netDigitalSales;
  const merchantOwesPiggy = finalBalance > 0;

  const topProductsData = products.map((p, idx) => ({
    name: p.name,
    sales: [45, 32, 28, 15, 10][idx] || 5,
    revenue: ([45, 32, 28, 15, 10][idx] || 5) * p.price,
    emoji: p.imageUrl
  })).sort((a, b) => b.revenue - a.revenue).slice(0, 5);

  const handleConciliate = () => {
    setIsConciliating(true);
    setTimeout(() => {
      setIsConciliating(false);
      alert("Cierre de caja enviado. Esperando validación del sistema.");
    }, 2000);
  };

  return (
    <div className="max-w-md mx-auto space-y-6 pb-32 px-4 animate-fadeIn relative">
      <div className="grid grid-cols-2 gap-4">
        <button 
          onClick={() => setIsCashierMode(true)}
          className="p-6 bg-[#FF007F] text-white rounded-[3rem] font-black shadow-xl flex flex-col gap-4 border-b-8 border-pink-900 active:scale-95 transition-all"
        >
          <div className="w-14 h-14 bg-[#1A1A40] rounded-[1.5rem] flex items-center justify-center text-white text-xl">
            <i className="fa-solid fa-cash-register"></i>
          </div>
          <div className="text-left">
            <span className="text-xs uppercase tracking-tight block">Terminal TPV</span>
            <span className="text-[10px] opacity-60">Cobros físicos</span>
          </div>
        </button>

        <button 
          onClick={() => setIsPayingUser(true)}
          className="p-6 bg-white text-[#1A1A40] rounded-[3rem] font-black shadow-xl flex flex-col gap-4 border border-slate-100 border-b-8 active:scale-95 transition-all"
        >
          <div className="w-14 h-14 bg-indigo-50 rounded-[1.5rem] flex items-center justify-center text-indigo-600 text-xl">
