                </div>
                <button 
                  onClick={() => { setIsPayingUser(false); setPayStep('ID'); setPayAmount(''); setTargetPhone(''); setUserFound(null); }}
                  className="w-full py-6 bg-[#1A1A40] text-white rounded-[2rem] font-black uppercase tracking-widest border-b-8 border-black shadow-2xl"
                >
                  VOLVER AL PANEL
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  };

  if (isPayingUser) {
    return renderPayUserFlow();
  }

  if (isCashierMode) {
    return (
