             <span className="text-[10px] bg-[#1A1A40] text-[#FF007F] px-3 py-1 rounded-full font-black uppercase tracking-widest">ACTIVO</span>
             <span className="text-[10px] text-slate-400 font-bold uppercase">{merchant.name}</span>
