        <div className="bg-slate-50 px-6 py-3 rounded-[1.8rem] border border-slate-100 text-right">
           <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Saldo Retirable</p>
           <h3 className="text-lg font-black text-indigo-600">${merchant.earnings.toLocaleString()}</h3>
