/**
 * Piggybanko Wompi Integration Service
 * Maneja la comunicación con el widget de pagos de Wompi.
 */

declare var WidgetCheckout: any;

export interface WompiConfig {
  amount: number;
  email: string;
  reference: string;
  onSuccess: (transaction: any) => void;
  onClose?: () => void;
}

export const openWompiCheckout = (config: WompiConfig) => {
  // En un entorno real usaríamos la llave pública de Wompi
  // pub_test_Q5yDA9xoKdePzhS8qn9G9S1YREi98A2
  const checkout = new WidgetCheckout({
    currency: 'COP',
    amountInCents: config.amount * 100,
    reference: config.reference,
    publicKey: 'pub_test_Q5yDA9xoKdePzhS8qn9G9S1YREi98A2', // Key de prueba
    customerData: {
      email: config.email,
    }
  });

  checkout.open((result: any) => {
    const transaction = result.transaction;
    if (transaction.status === 'APPROVED') {
      config.onSuccess(transaction);
    } else {
      console.warn("Transacción no aprobada:", transaction.status);
    }
  });
};

export const generateReference = (prefix: string = 'PB') => {
  return `${prefix}-${Date.now()}-${Math.floor(Math.random() * 1000)}`;
};

