/**
 * Piggybanko Wompi Integration Service
 */

declare var WidgetCheckout: any;
declare var confetti: any;

// En producción estas llaves vendrían de variables de entorno seguras
const WOMPI_PUBLIC_KEY = 'pub_test_Q5yDA9xoKdePzhS8qn9G9S1YREi98A2'; 

export interface WompiConfig {
  amount: number;
  email: string;
  reference: string;
  onSuccess: (transaction: any) => void;
  onClose?: () => void;
}

export const openWompiCheckout = (config: WompiConfig) => {
  if (typeof WidgetCheckout === 'undefined') {
    console.error("Wompi Widget no cargado");
    return;
  }

  const checkout = new WidgetCheckout({
    currency: 'COP',
    amountInCents: Math.round(config.amount * 100),
    reference: config.reference,
    publicKey: WOMPI_PUBLIC_KEY,
    customerData: {
      email: config.email,
    }
  });

  checkout.open((result: any) => {
    const transaction = result.transaction;
    if (transaction.status === 'APPROVED') {
      // Lanzar confeti al éxito
      confetti({
        particleCount: 150,
        spread: 70,
        origin: { y: 0.6 },
        colors: ['#FF007F', '#1A1A40', '#CCFF00']
      });
      config.onSuccess(transaction);
    } else {
      console.warn("Wompi Status:", transaction.status);
    }
    if (config.onClose) config.onClose();
  });
};

export const generateReference = (prefix: string = 'PB') => {
  return `${prefix}-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
};

import React, { useState, useEffect } from 'react';
import { MerchantAccount, Product } from '../types';
import { getMerchantInsight } from '../services/geminiService';
import { openWompiCheckout, generateReference } from '../services/wompiService';
import CashierView from './CashierView';

interface MerchantViewProps {
  merchant: MerchantAccount;
  allMerchants?: MerchantAccount[];
  products?: Product[];
  onGoHome: () => void;
  onMerchantPayUser: (phone: string, amount: number) => boolean;
  onSettlement: (amount: number) => void;
  onB2BTransfer?: (targetId: string, amount: number) => void;
}

const MerchantView: React.FC<MerchantViewProps> = ({ 
  merchant, 
  allMerchants = [], 
  onGoHome, 
  onSettlement,
  onB2BTransfer 
}) => {
  const [insight, setInsight] = useState("Analizando tu crecimiento...");
  const [isCashierMode, setIsCashierMode] = useState(false);
  const [showOnboarding, setShowOnboarding] = useState(false);

  // B2B States
  const [isB2BModalOpen, setIsB2BModalOpen] = useState(false);
  const [selectedTarget, setSelectedTarget] = useState<string>('');
  const [b2bAmount, setB2BAmount] = useState<number>(0);
  const [isProcessing, setIsProcessing] = useState(false);

  useEffect(() => {
    async function fetchInsight() {
      const msg = await getMerchantInsight(merchant.earnings, merchant.cashCollected);
      setInsight(msg);
    }
    fetchInsight();
  }, [merchant.earnings, merchant.cashCollected]);

  const grossDigitalSales = merchant.piggyPayments;
  const netDigitalSales = grossDigitalSales * 0.965;
  const netCashToPiggy = merchant.cashCollected * 0.99;
  const finalBalance = netCashToPiggy - netDigitalSales;
  const merchantOwesPiggy = finalBalance > 0;

  const handleSettlement = () => {
    if (!merchantOwesPiggy) return;
    setIsProcessing(true);
    openWompiCheckout({
      amount: Math.round(finalBalance),
      email: `${merchant.id}@negocio.com`,
      reference: generateReference('STL'),
      onSuccess: () => onSettlement(Math.round(finalBalance)),
      onClose: () => setIsProcessing(false)
    });
  };

  const handleB2BPayment = () => {
    if (!selectedTarget || b2bAmount <= 0) return;
    setIsProcessing(true);
    openWompiCheckout({
      amount: b2bAmount,
      email: `${merchant.id}@provider.com`,
      reference: generateReference('B2B'),
      onSuccess: () => {
        if (onB2BTransfer) onB2BTransfer(selectedTarget, b2bAmount);
        setIsB2BModalOpen(false);
        setB2BAmount(0);
        setSelectedTarget('');
      },
      onClose: () => setIsProcessing(false)
    });
  };

  if (isCashierMode) {
    return (
      <div className="animate-fadeIn">
        <button onClick={() => setIsCashierMode(false)} className="absolute top-8 right-8 z-[110] bg-white w-12 h-12 rounded-full shadow-2xl flex items-center justify-center border border-slate-100 hover:text-rose-500"><i className="fa-solid fa-xmark"></i></button>
        <CashierView merchantName={merchant.name} onProcessTransaction={() => true} mockUserBalance={0} onGoHome={() => setIsCashierMode(false)} />
      </div>
    );
  }

  return (
    <div className="max-w-md mx-auto space-y-6 pb-32 px-4 animate-fadeIn relative">
      {/* B2B Transfer Modal */}
      {isB2BModalOpen && (
        <div className="fixed inset-0 bg-[#1A1A40]/90 backdrop-blur-lg z-[200] flex items-end sm:items-center justify-center p-4">
          <div className="bg-white w-full max-w-sm rounded-[3rem] p-8 space-y-8 animate-slideUp shadow-2xl relative overflow-hidden border border-white/20">
            <div className="flex justify-between items-center">
              <h3 className="text-2xl font-black text-[#1A1A40] italic uppercase tracking-tighter">Pago B2B</h3>
              <button onClick={() => setIsB2BModalOpen(false)} className="w-10 h-10 bg-slate-100 rounded-full text-slate-400">
                <i className="fa-solid fa-xmark"></i>
              </button>
            </div>

            <div className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Comercio / Proveedor Destino</label>
                <select 
                  value={selectedTarget}
                  onChange={(e) => setSelectedTarget(e.target.value)}
                  className="w-full p-4 bg-slate-50 rounded-2xl border-2 border-slate-100 text-sm font-black text-[#1A1A40] outline-none appearance-none"
                >
                  <option value="">Selecciona un aliado</option>
                  {allMerchants.filter(m => m.id !== merchant.id).map(m => (
                    <option key={m.id} value={m.id}>{m.name}</option>
                  ))}
                </select>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Monto a Transferir</label>
                <div className="bg-slate-50 p-6 rounded-[2.5rem] border-2 border-slate-100 flex items-center gap-4">
                  <span className="text-3xl font-black text-[#FF007F]">$</span>
                  <input 
                    type="number" 
                    value={b2bAmount || ''}
                    onChange={(e) => setB2BAmount(parseInt(e.target.value) || 0)}
                    className="bg-transparent w-full text-4xl font-black text-[#1A1A40] outline-none"
                    placeholder="0"
                  />
                </div>
              </div>
            </div>

            <button 
              onClick={handleB2BPayment}
              disabled={!selectedTarget || b2bAmount <= 0 || isProcessing}
              className={`w-full py-6 rounded-[2.5rem] font-black text-xs uppercase tracking-widest transition-all border-b-8 ${selectedTarget && b2bAmount > 0 && !isProcessing ? 'bg-[#1A1A40] text-white border-black shadow-xl active:scale-95' : 'bg-slate-100 text-slate-300 border-slate-200 cursor-not-allowed'}`}
            >
              {isProcessing ? <i className="fa-solid fa-spinner fa-spin mr-2"></i> : null}
              {isProcessing ? 'PROCESANDO...' : 'PAGAR CON WOMPI 🏦'}
            </button>
          </div>
        </div>
      )}

      {/* Action Hub */}
      <div className="grid grid-cols-2 gap-4">
        <button onClick={() => setIsCashierMode(true)} className="p-6 bg-[#FF007F] text-white rounded-[3rem] font-black shadow-xl flex flex-col gap-4 border-b-8 border-pink-900 active:scale-95 transition-all">
