import React, { useState } from 'react';
import { AppRole, UserAccount, MerchantAccount, Product, Promotion } from './types';
import { Logo } from './constants';
import UserView from './components/UserView';
import MerchantView from './components/MerchantView';
import AdminView from './components/AdminView';
import MarketplaceView from './components/MarketplaceView';
import MerchantInventory from './components/MerchantInventory';
import MerchantPromotions from './components/MerchantPromotions';
import PromotionsView from './components/PromotionsView';
import MapView from './components/MapView';
import CashierView from './components/CashierView';
import LoginView from './components/LoginView';

type SubView = 'HOME' | 'MARKETPLACE' | 'PROMOTIONS' | 'MAP';

const App: React.FC = () => {
  const [role, setRole] = useState<AppRole>(AppRole.USER);
  const [isLogged, setIsLogged] = useState(false);
  const [phoneNumber, setPhoneNumber] = useState('');
  const [activeTab, setActiveTab] = useState<SubView>('HOME');
  const [marketplaceMerchantFilter, setMarketplaceMerchantFilter] = useState('Todos');

  const [loginError, setLoginError] = useState(false);

  const [user, setUser] = useState<UserAccount>({
    id: 'valen-001', phone: '3001234567', balance: 45350, xp: 650, level: 2, goalName: 'Tenis Nike Air', goalTarget: 70000, lastYield: 5
  });

  const [merchants, setMerchants] = useState<MerchantAccount[]>([
    {
      id: 'roberto-pos', name: 'Don Roberto', cashCollected: 150000, piggyPayments: 20000, quotaUsed: 130000, quotaLimit: 200000, earnings: 377500, address: 'Calle 45 # 7-12', lat: 4.6300, lng: -74.0700, type: 'SUPERMARKET'
    },
    {
      id: 'pan-del-valle', name: 'Pan del Valle', cashCollected: 45000, piggyPayments: 5000, quotaUsed: 40000, quotaLimit: 100000, earnings: 120000, address: 'Av Siempre Viva 123', lat: 4.6350, lng: -74.0750, type: 'BAKERY'
    }
  ]);

  const currentMerchantId = 'roberto-pos'; // Simulado
  const merchant = merchants.find(m => m.id === currentMerchantId) || merchants[0];

  const [products, setProducts] = useState<Product[]>([
    { id: 'p1', merchantId: 'roberto-pos', merchantName: 'Don Roberto', name: 'Leche Deslactosada 1L', price: 4200, category: 'Alimentos', imageUrl: '🥛' },
    { id: 'p2', merchantId: 'roberto-pos', merchantName: 'Don Roberto', name: 'Pan Tajado Familiar', price: 5500, category: 'Alimentos', imageUrl: '🍞' },
    { id: 'p3', merchantId: 'roberto-pos', merchantName: 'Don Roberto', name: 'Huevos AA x30', price: 16000, category: 'Alimentos', imageUrl: '🥚' },
  ]);

  const [promotions, setPromotions] = useState<Promotion[]>([
    { id: 'promo-1', merchantId: 'roberto-pos', merchantName: 'Don Roberto', title: 'Pack Parrillero Familiar', description: 'Llévate todo para el asado.', piggyPrice: 15000, otherPrice: 35000, totalValue: 65000, imageUrl: '🥩', expiryDate: '12h 45m', category: 'Alimentos' }
  ]);

  const handleLoginAction = (selectedRole: AppRole, phone: string, pin?: string, code?: string, name?: string) => {
    setLoginError(false);
    setRole(selectedRole);
    setPhoneNumber(phone);
    if (name) setUser(prev => ({ ...prev, phone, id: `user-${Date.now()}` }));
    if (phone.length >= 10) setIsLogged(true);
    else setLoginError(true);
  };

  const handleTopUp = (amount: number) => {
    setUser(prev => ({ ...prev, balance: prev.balance + amount, xp: prev.xp + 100 }));
  };

  const handleSettlement = (amount: number) => {
    setMerchants(prev => prev.map(m => m.id === merchant.id ? { ...m, cashCollected: 0, piggyPayments: 0 } : m));
  };

  const handleB2BTransfer = (targetId: string, amount: number) => {
    setMerchants(prev => prev.map(m => {
      if (m.id === merchant.id) return { ...m, earnings: m.earnings - amount };
      if (m.id === targetId) return { ...m, earnings: m.earnings + amount };
      return m;
    }));
  };

  const handleProcessTransaction = (targetPhone: string, amount: number, type: 'SAVING' | 'PAYMENT') => {
    const numericAmount = Number(amount);
    if (type === 'SAVING') {
      setMerchants(prev => prev.map(m => m.id === merchant.id ? { ...m, cashCollected: m.cashCollected + numericAmount } : m));
      if (targetPhone === user.phone) setUser(prev => ({ ...prev, balance: prev.balance + numericAmount, xp: prev.xp + 50 }));
    } else {
      if (targetPhone === user.phone) {
        if (user.balance < numericAmount) return false;
        setUser(prev => ({ ...prev, balance: prev.balance - numericAmount, xp: prev.xp + 20 }));
      }
      setMerchants(prev => prev.map(m => m.id === merchant.id ? { ...m, piggyPayments: m.piggyPayments + numericAmount } : m));
    }
    return true;
  };

  const renderContent = () => {
    if (role === AppRole.CASHIER) return <CashierView merchantName={merchant.name} onProcessTransaction={handleProcessTransaction} mockUserBalance={user.balance} onGoHome={() => setActiveTab('HOME')} />;
    if (role === AppRole.USER) {
      switch(activeTab) {
        case 'MARKETPLACE': return <MarketplaceView products={products} userBalance={user.balance} initialMerchant={marketplaceMerchantFilter} />;
        case 'PROMOTIONS': return <PromotionsView promotions={promotions} userBalance={user.balance} />;
        case 'MAP': return <MapView merchants={merchants} userBalance={user.balance} onViewStore={(m) => {setMarketplaceMerchantFilter(m); setActiveTab('MARKETPLACE');}} />;
        default: return <UserView user={user} onGoHome={() => setActiveTab('HOME')} onTopUp={handleTopUp} />;
      }
    }
    if (role === AppRole.MERCHANT) {
        switch(activeTab) {
          case 'MARKETPLACE': return <MerchantInventory products={products.filter(p => p.merchantId === merchant.id)} onAddProduct={() => {}} onRemoveProduct={() => {}} />;
          case 'PROMOTIONS': return <MerchantPromotions promotions={promotions} onAddPromotion={() => {}} onRemovePromotion={() => {}} />;
          default: return <MerchantView merchant={merchant} allMerchants={merchants} onGoHome={() => setActiveTab('HOME')} onMerchantPayUser={() => true} onSettlement={handleSettlement} onB2BTransfer={handleB2BTransfer} />;
        }
    }
    return <AdminView />;
  };

  if (!isLogged) return <LoginView onLogin={handleLoginAction} loginError={loginError} />;

  return (
    <div className="min-h-screen bg-white pt-8 overflow-x-hidden">
      <div className="max-w-md md:max-w-4xl mx-auto px-4 flex justify-between items-center mb-8">
        <button onClick={() => setActiveTab('HOME')} className="hover:scale-105 active:scale-95 transition-transform"><Logo /></button>
        <button onClick={() => setIsLogged(false)} className="w-10 h-10 bg-white rounded-full shadow-md flex items-center justify-center text-slate-400 border border-slate-100"><i className="fa-solid fa-sign-out"></i></button>
      </div>
      <div className="animate-fadeIn">{renderContent()}</div>
      {(role === AppRole.USER || role === AppRole.MERCHANT) && (
        <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-[90%] max-w-sm bg-[#1A1A40] text-white rounded-3xl p-4 flex justify-between items-center shadow-2xl z-50">
          <button onClick={() => setActiveTab('HOME')} className={`flex flex-col items-center gap-1 ${activeTab === 'HOME' ? 'text-[#FF007F]' : 'opacity-50'}`}><i className="fa-solid fa-house"></i><span className="text-[10px]">Inicio</span></button>
          <button onClick={() => setActiveTab('MARKETPLACE')} className={`flex flex-col items-center gap-1 ${activeTab === 'MARKETPLACE' ? 'text-[#FF007F]' : 'opacity-50'}`}><i className="fa-solid fa-store"></i><span className="text-[10px]">Tienda</span></button>
          <div className="relative -top-10"><button className="w-14 h-14 bg-[#FF007F] rounded-full flex items-center justify-center text-white border-4 border-white shadow-xl shadow-pink-500/20 active:scale-90 transition-all"><i className="fa-solid fa-qrcode text-xl"></i></button></div>
          <button onClick={() => setActiveTab('PROMOTIONS')} className={`flex flex-col items-center gap-1 ${activeTab === 'PROMOTIONS' ? 'text-[#FF007F]' : 'opacity-50'}`}><i className="fa-solid fa-tags"></i><span className="text-[10px]">Promos</span></button>
          <button onClick={() => setActiveTab('MAP')} className={`flex flex-col items-center gap-1 ${activeTab === 'MAP' ? 'text-[#FF007F]' : 'opacity-50'}`}><i className="fa-solid fa-map-location-dot"></i><span className="text-[10px]">Mapa</span></button>
        </div>
      )}
    </div>
  );
};

export default App;

/**
 * Piggybanko Wompi Integration Service
 * Configuración oficial para ambiente de pruebas y producción.
 */

declare var WidgetCheckout: any;
declare var confetti: any;

// Llaves de Wompi (Pruebas por defecto, cambiar a Producción cuando sea necesario)
export const WOMPI_CONFIG = {
  publicKey: 'pub_test_Q5yDA9xoKdePzhS8qn9G9S1YREi98A2', // Llave pública de prueba
  currency: 'COP',
  integrityKey: '', // Opcional: para mayor seguridad en firmas (backend)
};

export interface WompiTransactionResult {
  id: string;
  status: 'APPROVED' | 'DECLINED' | 'ERROR' | 'VOIDED';
  amountInCents: number;
  reference: string;
  paymentMethodType: string;
  paymentMethod: any;
  redirectUrl?: string;
}

export interface WompiConfig {
  amount: number;
  email: string;
  reference: string;
  onSuccess: (result: WompiTransactionResult) => void;
  onError?: (error: any) => void;
  onClose?: () => void;
}

export const openWompiCheckout = (config: WompiConfig) => {
  if (typeof WidgetCheckout === 'undefined') {
    console.error("Wompi Widget no cargado. Revisa la conexión a internet.");
    if (config.onError) config.onError("Wompi Widget not loaded");
    return;
  }

  const checkout = new WidgetCheckout({
    currency: WOMPI_CONFIG.currency,
    amountInCents: Math.round(config.amount * 100),
    reference: config.reference,
    publicKey: WOMPI_CONFIG.publicKey,
    customerData: {
      email: config.email,
    }
  });

  checkout.open((result: any) => {
    const transaction = result.transaction;

    if (transaction.status === 'APPROVED') {
      // Celebración visual
      confetti({
        particleCount: 200,
        spread: 90,
        origin: { y: 0.7 },
        colors: ['#FF007F', '#1A1A40', '#CCFF00', '#FFFFFF']
      });
      config.onSuccess(transaction);
    } else {
      console.warn("Wompi Transaction Status:", transaction.status);
      if (config.onError) config.onError(transaction);
    }

    if (config.onClose) config.onClose();
  });
};

export const generateReference = (prefix: string = 'PB') => {
  const date = new Date().toISOString().split('T')[0].replace(/-/g, '');
  const random = Math.floor(Math.random() * 10000).toString().padStart(4, '0');
  return `${prefix}-${date}-${random}`;
};

