import React, { useState, useEffect } from 'react';
import { MerchantAccount, Product } from '../types';
import { getMerchantInsight } from '../services/geminiService';
import { openWompiCheckout, generateReference } from '../services/wompiService';
import CashierView from './CashierView';

interface MerchantViewProps {
  merchant: MerchantAccount;
  allMerchants?: MerchantAccount[];
  products?: Product[];
  onGoHome: () => void;
  onMerchantPayUser: (phone: string, amount: number) => boolean;
  onSettlement: (amount: number, txResult: any) => void;
  onB2BTransfer?: (targetId: string, amount: number, txResult: any) => void;
}

const MerchantView: React.FC<MerchantViewProps> = ({ 
  merchant, 
  allMerchants = [], 
  onGoHome, 
  onSettlement,
  onB2BTransfer 
}) => {
  const [insight, setInsight] = useState("Analizando tu crecimiento...");
  const [isCashierMode, setIsCashierMode] = useState(false);
  const [isB2BModalOpen, setIsB2BModalOpen] = useState(false);
  const [selectedTarget, setSelectedTarget] = useState<string>('');
  const [b2bAmount, setB2BAmount] = useState<number>(0);
  const [isProcessing, setIsProcessing] = useState(false);

  useEffect(() => {
    async function fetchInsight() {
      const msg = await getMerchantInsight(merchant.earnings, merchant.cashCollected);
      setInsight(msg);
    }
    fetchInsight();
  }, [merchant.earnings, merchant.cashCollected]);

  const grossDigitalSales = merchant.piggyPayments;
  const netDigitalSales = grossDigitalSales * 0.965;
  const netCashToPiggy = merchant.cashCollected * 0.99;
  const finalBalance = netCashToPiggy - netDigitalSales;
  const merchantOwesPiggy = finalBalance > 0;

  const handleSettlement = () => {
    if (!merchantOwesPiggy) return;
    setIsProcessing(true);
    openWompiCheckout({
      amount: Math.round(finalBalance),
      email: `${merchant.id}@negocio.com`,
      reference: generateReference('STL'),
      onSuccess: (tx) => onSettlement(Math.round(finalBalance), tx),
      onClose: () => setIsProcessing(false)
    });
  };

  const handleB2BPayment = () => {
    if (!selectedTarget || b2bAmount <= 0) return;
    setIsProcessing(true);
    openWompiCheckout({
      amount: b2bAmount,
      email: `${merchant.id}@provider.com`,
      reference: generateReference('B2B'),
      onSuccess: (tx) => {
        if (onB2BTransfer) onB2BTransfer(selectedTarget, b2bAmount, tx);
        setIsB2BModalOpen(false);
        setB2BAmount(0);
        setSelectedTarget('');
      },
      onClose: () => setIsProcessing(false)
    });
  };

  if (isCashierMode) {
    return (
      <div className="animate-fadeIn">
        <button onClick={() => setIsCashierMode(false)} className="absolute top-8 right-8 z-[110] bg-white w-12 h-12 rounded-full shadow-2xl flex items-center justify-center border border-slate-100 hover:text-rose-500"><i className="fa-solid fa-xmark"></i></button>
        <CashierView merchantName={merchant.name} onProcessTransaction={() => true} mockUserBalance={0} onGoHome={() => setIsCashierMode(false)} />
      </div>
    );
  }

  return (
    <div className="max-w-md mx-auto space-y-6 pb-32 px-4 animate-fadeIn relative">
      {/* B2B Modal */}
      {isB2BModalOpen && (
        <div className="fixed inset-0 bg-[#1A1A40]/90 backdrop-blur-lg z-[200] flex items-end sm:items-center justify-center p-4">
          <div className="bg-white w-full max-w-sm rounded-[3rem] p-8 space-y-8 animate-slideUp shadow-2xl border border-white/20">
            <h3 className="text-2xl font-black text-[#1A1A40] italic uppercase tracking-tighter">Pago B2B</h3>
            <select value={selectedTarget} onChange={(e) => setSelectedTarget(e.target.value)} className="w-full p-4 bg-slate-50 rounded-2xl border-2 border-slate-100 text-sm font-black outline-none">
              <option value="">Selecciona un aliado</option>
              {allMerchants.filter(m => m.id !== merchant.id).map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
            </select>
            <div className="bg-slate-50 p-6 rounded-[2.5rem] border-2 border-slate-100 flex items-center gap-4">
              <span className="text-3xl font-black text-[#FF007F]">$</span>
              <input type="number" value={b2bAmount || ''} onChange={(e) => setB2BAmount(parseInt(e.target.value) || 0)} className="bg-transparent w-full text-4xl font-black text-[#1A1A40] outline-none" placeholder="0" />
            </div>
            <button onClick={handleB2BPayment} disabled={!selectedTarget || b2bAmount <= 0 || isProcessing} className={`w-full py-6 rounded-[2.5rem] font-black text-xs uppercase transition-all border-b-8 ${selectedTarget && b2bAmount > 0 && !isProcessing ? 'bg-[#1A1A40] text-white border-black shadow-xl' : 'bg-slate-100 text-slate-300 border-slate-200'}`}>
              {isProcessing ? 'PROCESANDO...' : 'PAGAR CON WOMPI 🏦'}
            </button>
            <button onClick={() => setIsB2BModalOpen(false)} className="w-full text-[10px] font-black text-slate-400 uppercase tracking-widest">Cerrar</button>
          </div>
        </div>
      )}

      {/* Action Hub */}
      <div className="grid grid-cols-2 gap-4">
        <button onClick={() => setIsCashierMode(true)} className="p-6 bg-[#FF007F] text-white rounded-[3rem] font-black shadow-xl flex flex-col gap-4 border-b-8 border-pink-900 active:scale-95 transition-all">
          <div className="w-14 h-14 bg-[#1A1A40] rounded-[1.5rem] flex items-center justify-center text-xl shadow-lg"><i className="fa-solid fa-cash-register"></i></div>
          <span className="text-xs uppercase block tracking-widest">TPV Terminal</span>
        </button>
        <button onClick={() => setIsB2BModalOpen(true)} className="p-6 bg-white text-[#1A1A40] rounded-[3rem] font-black shadow-xl flex flex-col gap-4 border border-slate-100 border-b-8 active:scale-95 transition-all">
          <div className="w-14 h-14 bg-[#CCFF00] rounded-[1.5rem] flex items-center justify-center text-xl shadow-lg border-2 border-[#1A1A40]"><i className="fa-solid fa-building-columns"></i></div>
          <span className="text-xs uppercase block tracking-widest">Pago B2B</span>
        </button>
      </div>

      {/* Settlement Card */}
      <div className="bg-[#1A1A40] rounded-[3.5rem] p-8 shadow-2xl relative overflow-hidden border border-white/5">
        <div className="relative z-10 space-y-8">
          <div className="space-y-1">
            <p className="text-[10px] font-black text-white/40 uppercase tracking-[0.3em]">Balance de Recaudo</p>
            <h4 className={`text-4xl font-black italic ${merchantOwesPiggy ? 'text-[#FF007F]' : 'text-[#CCFF00]'}`}>${Math.abs(finalBalance).toLocaleString()}</h4>
            <p className="text-[9px] font-bold text-white/20 uppercase tracking-tighter">{merchantOwesPiggy ? 'Debes transferir a Piggybanko' : 'Saldo a tu favor'}</p>
          </div>
          <button onClick={handleSettlement} disabled={!merchantOwesPiggy || isProcessing} className={`w-full py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-xl active:scale-95 transition-all border-b-8 ${merchantOwesPiggy && !isProcessing ? 'bg-[#FF007F] text-white border-pink-900' : 'bg-white/10 text-white/20 cursor-not-allowed'}`}>
            {isProcessing ? 'PROCESANDO...' : 'LIQUIDAR CAJA AHORA 💸'}
          </button>
        </div>
      </div>

      <div className="glass p-6 rounded-[2.5rem] flex items-center gap-5 shadow-sm">
        <div className="w-14 h-14 rounded-2xl bg-[#1A1A40] flex items-center justify-center text-white shrink-0 shadow-xl border-2 border-[#FF007F]"><i className="fa-solid fa-wand-magic-sparkles text-xl text-[#FF007F]"></i></div>
        <p className="text-[11px] text-[#1A1A40] leading-relaxed font-bold italic line-clamp-2">"AI: {insight}"</p>
      </div>
    </div>
  );
};

export default MerchantView;

/**
 * Piggybanko Wompi Integration Service
