/**
 * Generic Storage Service for Piggybanko
 * Abstrae el acceso a la persistencia para permitir cambios futuros a IndexedDB o API REST.
 */
export class StorageService {
  static save(key: string, data: any): void {
    try {
      const serializedData = JSON.stringify(data);
      localStorage.setItem(`piggy_${key}`, serializedData);
    } catch (error) {
      console.error(`Error saving to storage [${key}]:`, error);
    }
  }

  static get<T>(key: string): T | null {
    try {
      const data = localStorage.getItem(`piggy_${key}`);
      return data ? JSON.parse(data) : null;
    } catch (error) {
      console.error(`Error reading from storage [${key}]:`, error);
      return null;
    }
  }

  static remove(key: string): void {
    localStorage.removeItem(`piggy_${key}`);
  }

  static clear(): void {
    const keys = Object.keys(localStorage);
    keys.forEach(key => {
      if (key.startsWith('piggy_')) localStorage.removeItem(key);
    });
  }
}

import { UserAccount, MerchantAccount, Transaction, Product, Promotion } from '../types';
import { StorageService } from '../services/storageService';

/**
 * PiggyRepository: El corazón de datos de Piggybanko.
 * Gestiona la persistencia y las reglas de negocio transaccionales.
 */
export class PiggyRepository {
  private static KEYS = {
    USER: 'current_user',
    MERCHANTS: 'merchants',
    TRANSACTIONS: 'transactions',
    PRODUCTS: 'products',
    PROMOTIONS: 'promotions'
  };

  // --- USER METHODS ---
  static getUser(): UserAccount {
    const defaultUser: UserAccount = {
      id: 'valen-001', 
      phone: '3001234567', 
      balance: 45350, 
      xp: 650, 
      level: 2, 
      goalName: 'Tenis Nike Air', 
      goalTarget: 70000, 
      lastYield: 5
    };
    return StorageService.get<UserAccount>(this.KEYS.USER) || defaultUser;
  }

  static updateUser(user: UserAccount): void {
    StorageService.save(this.KEYS.USER, user);
  }

  // --- MERCHANT METHODS ---
  static getMerchants(): MerchantAccount[] {
    const defaultMerchants: MerchantAccount[] = [
      {
        id: 'roberto-pos', name: 'Don Roberto', cashCollected: 150000, piggyPayments: 20000, 
        quotaUsed: 130000, quotaLimit: 200000, earnings: 377500, address: 'Calle 45 # 7-12', 
        lat: 4.6300, lng: -74.0700, type: 'SUPERMARKET'
      },
      {
        id: 'pan-del-valle', name: 'Pan del Valle', cashCollected: 45000, piggyPayments: 5000, 
        quotaUsed: 40000, quotaLimit: 100000, earnings: 120000, address: 'Av Siempre Viva 123', 
        lat: 4.6350, lng: -74.0750, type: 'BAKERY'
      }
    ];
    return StorageService.get<MerchantAccount[]>(this.KEYS.MERCHANTS) || defaultMerchants;
  }

  static updateMerchant(merchant: MerchantAccount): void {
    const merchants = this.getMerchants();
    const index = merchants.findIndex(m => m.id === merchant.id);
    if (index !== -1) {
      merchants[index] = merchant;
      StorageService.save(this.KEYS.MERCHANTS, merchants);
    }
  }

  // --- TRANSACTIONAL LOGIC ---
  static processTopUp(amount: number, txId: string, reference: string): void {
    const user = this.getUser();
    user.balance += amount;
    user.xp += 100;
    this.updateUser(user);

    this.addTransaction({
      id: txId,
      type: 'YIELD', // Usamos YIELD o SAVING para incrementos
      amount: amount,
      description: 'Recarga Wompi',
      timestamp: new Date().toISOString(),
      status: 'COMPLETADA',
      paymentMethod: 'Wompi Pay'
    });
  }

  static processB2B(fromId: string, toId: string, amount: number, txId: string): void {
    const merchants = this.getMerchants();
    const fromMerchant = merchants.find(m => m.id === fromId);
    const toMerchant = merchants.find(m => m.id === toId);

    if (fromMerchant && toMerchant) {
      fromMerchant.earnings -= amount;
      toMerchant.earnings += amount;
      this.updateMerchant(fromMerchant);
      this.updateMerchant(toMerchant);

      this.addTransaction({
        id: txId,
        type: 'PAYMENT',
        amount: -amount,
        description: `Transferencia B2B a ${toMerchant.name}`,
        timestamp: new Date().toISOString(),
        status: 'COMPLETADA'
      });
    }
  }

  static addTransaction(tx: Transaction): void {
    const transactions = StorageService.get<Transaction[]>(this.KEYS.TRANSACTIONS) || [];
    transactions.unshift(tx); // Nueva transacción al inicio
    StorageService.save(this.KEYS.TRANSACTIONS, transactions.slice(0, 50)); // Guardar últimas 50
  }

  static getTransactions(): Transaction[] {
    return StorageService.get<Transaction[]>(this.KEYS.TRANSACTIONS) || [];
  }
}

import React, { useState, useEffect } from 'react';
import { AppRole, UserAccount, MerchantAccount, Product, Promotion, Transaction } from './types';
import { Logo } from './constants';
import UserView from './components/UserView';
import MerchantView from './components/MerchantView';
import AdminView from './components/AdminView';
import MarketplaceView from './components/MarketplaceView';
import MerchantInventory from './components/MerchantInventory';
import MerchantPromotions from './components/MerchantPromotions';
import PromotionsView from './components/PromotionsView';
import MapView from './components/MapView';
import CashierView from './components/CashierView';
import LoginView from './components/LoginView';
import WompiReceipt from './components/WompiReceipt';
import { PiggyRepository } from './repositories/piggyRepository';

type SubView = 'HOME' | 'MARKETPLACE' | 'PROMOTIONS' | 'MAP';

interface ReceiptState {
  transactionId: string;
  amount: number;
  reference: string;
  date: string;
  type: string;
}

const App: React.FC = () => {
  const [role, setRole] = useState<AppRole>(AppRole.USER);
  const [isLogged, setIsLogged] = useState(false);
  const [activeTab, setActiveTab] = useState<SubView>('HOME');
  const [marketplaceMerchantFilter, setMarketplaceMerchantFilter] = useState('Todos');
  const [receipt, setReceipt] = useState<ReceiptState | null>(null);

  // States synchronized with Repository
  const [user, setUser] = useState<UserAccount>(PiggyRepository.getUser());
  const [merchants, setMerchants] = useState<MerchantAccount[]>(PiggyRepository.getMerchants());
  const [transactions, setTransactions] = useState<Transaction[]>(PiggyRepository.getTransactions());

  const currentMerchantId = 'roberto-pos';
  const merchant = merchants.find(m => m.id === currentMerchantId) || merchants[0];

  // Refresh local state whenever we update repository (simple sync)
  const syncState = () => {
    setUser(PiggyRepository.getUser());
    setMerchants(PiggyRepository.getMerchants());
    setTransactions(PiggyRepository.getTransactions());
  };

  const products: Product[] = [
    { id: 'p1', merchantId: 'roberto-pos', merchantName: 'Don Roberto', name: 'Leche Deslactosada 1L', price: 4200, category: 'Alimentos', imageUrl: '🥛' },
    { id: 'p2', merchantId: 'roberto-pos', merchantName: 'Don Roberto', name: 'Pan Tajado Familiar', price: 5500, category: 'Alimentos', imageUrl: '🍞' },
    { id: 'p3', merchantId: 'roberto-pos', merchantName: 'Don Roberto', name: 'Huevos AA x30', price: 16000, category: 'Alimentos', imageUrl: '🥚' },
  ];

  const promotions: Promotion[] = [
    { id: 'promo-1', merchantId: 'roberto-pos', merchantName: 'Don Roberto', title: 'Pack Parrillero Familiar', description: 'Llévate todo para el asado.', piggyPrice: 15000, otherPrice: 35000, totalValue: 65000, imageUrl: '🥩', expiryDate: '12h 45m', category: 'Alimentos' }
  ];

  const handleTopUp = (amount: number, txResult: any) => {
    PiggyRepository.processTopUp(amount, txResult.id, txResult.reference);
    syncState();
    setReceipt({
      transactionId: txResult.id,
      amount,
      reference: txResult.reference,
      date: new Date().toLocaleString(),
      type: 'RECARGA WALLET'
    });
  };

  const handleSettlement = (amount: number, txResult: any) => {
    const updatedMerchant = { ...merchant, cashCollected: 0, piggyPayments: 0 };
    PiggyRepository.updateMerchant(updatedMerchant);
    PiggyRepository.addTransaction({
      id: txResult.id,
      type: 'PAYMENT',
      amount: -amount,
      description: 'Liquidación de Caja Piggybanko',
      timestamp: new Date().toISOString(),
      status: 'COMPLETADA'
    });
    syncState();
    setReceipt({
      transactionId: txResult.id,
      amount,
      reference: txResult.reference,
      date: new Date().toLocaleString(),
      type: 'LIQUIDACIÓN CAJA'
    });
  };

  const handleB2BTransfer = (targetId: string, amount: number, txResult: any) => {
    PiggyRepository.processB2B(merchant.id, targetId, amount, txResult.id);
    syncState();
    setReceipt({
      transactionId: txResult.id,
      amount,
      reference: txResult.reference,
      date: new Date().toLocaleString(),
      type: `PAGO B2B: ${merchants.find(m => m.id === targetId)?.name}`
    });
  };

  const renderContent = () => {
    if (role === AppRole.CASHIER) return <CashierView merchantName={merchant.name} onProcessTransaction={() => true} mockUserBalance={user.balance} onGoHome={() => setActiveTab('HOME')} />;
    if (role === AppRole.USER) {
      switch(activeTab) {
        case 'MARKETPLACE': return <MarketplaceView products={products} userBalance={user.balance} initialMerchant={marketplaceMerchantFilter} />;
        case 'PROMOTIONS': return <PromotionsView promotions={promotions} userBalance={user.balance} />;
        case 'MAP': return <MapView merchants={merchants} userBalance={user.balance} onViewStore={(m) => {setMarketplaceMerchantFilter(m); setActiveTab('MARKETPLACE');}} />;
        default: return <UserView user={user} onGoHome={() => setActiveTab('HOME')} onTopUp={(amt, tx) => handleTopUp(amt, tx)} />;
      }
    }
    if (role === AppRole.MERCHANT) {
        switch(activeTab) {
          case 'MARKETPLACE': return <MerchantInventory products={products.filter(p => p.merchantId === merchant.id)} onAddProduct={() => {}} onRemoveProduct={() => {}} />;
          case 'PROMOTIONS': return <MerchantPromotions promotions={promotions} onAddPromotion={() => {}} onRemovePromotion={() => {}} />;
          default: return <MerchantView merchant={merchant} allMerchants={merchants} onGoHome={() => setActiveTab('HOME')} onMerchantPayUser={() => true} onSettlement={(amt, tx) => handleSettlement(amt, tx)} onB2BTransfer={(target, amt, tx) => handleB2BTransfer(target, amt, tx)} />;
        }
    }
    return <AdminView />;
  };

  if (!isLogged) return <LoginView onLogin={(r) => {setRole(r); setIsLogged(true);}} loginError={false} />;

  return (
    <div className="min-h-screen bg-white pt-8 overflow-x-hidden">
      {receipt && (
        <WompiReceipt 
          {...receipt} 
          onClose={() => setReceipt(null)} 
        />
      )}

      <div className="max-w-md md:max-w-4xl mx-auto px-4 flex justify-between items-center mb-8">
        <button onClick={() => setActiveTab('HOME')} className="hover:scale-105 active:scale-95 transition-transform"><Logo /></button>
        <button onClick={() => setIsLogged(false)} className="w-10 h-10 bg-white rounded-full shadow-md flex items-center justify-center text-slate-400 border border-slate-100"><i className="fa-solid fa-sign-out"></i></button>
      </div>

      <div className="animate-fadeIn">{renderContent()}</div>

      {(role === AppRole.USER || role === AppRole.MERCHANT) && (
        <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-[90%] max-w-sm bg-[#1A1A40] text-white rounded-3xl p-4 flex justify-between items-center shadow-2xl z-50">
          <button onClick={() => setActiveTab('HOME')} className={`flex flex-col items-center gap-1 ${activeTab === 'HOME' ? 'text-[#FF007F]' : 'opacity-50'}`}><i className="fa-solid fa-house"></i><span className="text-[10px]">Inicio</span></button>
          <button onClick={() => setActiveTab('MARKETPLACE')} className={`flex flex-col items-center gap-1 ${activeTab === 'MARKETPLACE' ? 'text-[#FF007F]' : 'opacity-50'}`}><i className="fa-solid fa-store"></i><span className="text-[10px]">Tienda</span></button>
          <div className="relative -top-10"><button className="w-14 h-14 bg-[#FF007F] rounded-full flex items-center justify-center text-white border-4 border-white shadow-xl shadow-pink-500/20 active:scale-90 transition-all"><i className="fa-solid fa-qrcode text-xl"></i></button></div>
          <button onClick={() => setActiveTab('PROMOTIONS')} className={`flex flex-col items-center gap-1 ${activeTab === 'PROMOTIONS' ? 'text-[#FF007F]' : 'opacity-50'}`}><i className="fa-solid fa-tags"></i><span className="text-[10px]">Promos</span></button>
          <button onClick={() => setActiveTab('MAP')} className={`flex flex-col items-center gap-1 ${activeTab === 'MAP' ? 'text-[#FF007F]' : 'opacity-50'}`}><i className="fa-solid fa-map-location-dot"></i><span className="text-[10px]">Mapa</span></button>
        </div>
      )}
    </div>
  );
};

export default App;

