import { initializeApp } from 'firebase/app';
import { getFirestore } from 'firebase/firestore';

/**
 * Piggybanko Cloud Configuration
 * Reemplazar con las credenciales del proyecto real en producción.
 */
const firebaseConfig = {
  apiKey: "AIzaSyAs-FakeKey-Piggybanko",
  authDomain: "piggybanko-fintech.firebaseapp.com",
  projectId: "piggybanko-fintech",
  storageBucket: "piggybanko-fintech.appspot.com",
  messagingSenderId: "123456789",
  appId: "1:123456789:web:abcdef"
};

const app = initializeApp(firebaseConfig);
export const db = getFirestore(app);

import { 
  collection, 
  doc, 
  getDoc, 
  getDocs, 
  setDoc, 
  updateDoc, 
  query, 
  orderBy, 
  limit, 
  addDoc,
  Timestamp,
  arrayUnion
} from 'firebase/firestore';
import { db } from '../services/firebaseService';
import { UserAccount, MerchantAccount, Transaction } from '../types';

/**
 * PiggyRepository: Cloud Edition
 * Ahora utiliza Firestore como backend en tiempo real.
 */
export class PiggyRepository {
  private static COLLECTIONS = {
    USERS: 'users',
    MERCHANTS: 'merchants',
    TRANSACTIONS: 'transactions'
  };

  // --- USER METHODS ---
  static async getUser(userId: string = 'valen-001'): Promise<UserAccount> {
    const userRef = doc(db, this.COLLECTIONS.USERS, userId);
    const userSnap = await getDoc(userRef);

    if (userSnap.exists()) {
      return userSnap.data() as UserAccount;
    } else {
      // Default initial user in cloud
      const defaultUser: UserAccount = {
        id: userId, phone: '3001234567', balance: 45350, xp: 650, level: 2, 
        goalName: 'Tenis Nike Air', goalTarget: 70000, lastYield: 5
      };
      await setDoc(userRef, defaultUser);
      return defaultUser;
    }
  }

  static async updateUser(user: UserAccount): Promise<void> {
    const userRef = doc(db, this.COLLECTIONS.USERS, user.id);
    await setDoc(userRef, user, { merge: true });
  }

  // --- MERCHANT METHODS ---
  static async getMerchants(): Promise<MerchantAccount[]> {
    const merchantsCol = collection(db, this.COLLECTIONS.MERCHANTS);
    const merchantSnapshot = await getDocs(merchantsCol);

    if (merchantSnapshot.empty) {
      // Seed initial data if empty
      const initial = [
        {
          id: 'roberto-pos', name: 'Don Roberto', cashCollected: 150000, piggyPayments: 20000, 
          quotaUsed: 130000, quotaLimit: 200000, earnings: 377500, address: 'Calle 45 # 7-12', 
          lat: 4.6300, lng: -74.0700, type: 'SUPERMARKET'
        }
      ];
      for (const m of initial) {
        await setDoc(doc(db, this.COLLECTIONS.MERCHANTS, m.id), m);
      }
      return initial as MerchantAccount[];
    }

    return merchantSnapshot.docs.map(doc => doc.data() as MerchantAccount);
  }

  static async updateMerchant(merchant: MerchantAccount): Promise<void> {
    const merchantRef = doc(db, this.COLLECTIONS.MERCHANTS, merchant.id);
    await setDoc(merchantRef, merchant, { merge: true });
  }

  // --- TRANSACTIONAL LOGIC ---
  static async processTopUp(amount: number, txId: string, reference: string, userId: string = 'valen-001'): Promise<void> {
    const user = await this.getUser(userId);
    user.balance += amount;
    user.xp += 100;

    // Cloud Atomic Updates (Batch would be better but keeping it simple)
    await this.updateUser(user);

    await this.addTransaction({
      id: txId,
      type: 'YIELD',
      amount: amount,
      description: 'Recarga Wompi',
      timestamp: new Date().toISOString(),
      status: 'COMPLETADA',
      paymentMethod: 'Wompi Pay'
    });
  }

  static async processB2B(fromId: string, toId: string, amount: number, txId: string): Promise<void> {
    const fromRef = doc(db, this.COLLECTIONS.MERCHANTS, fromId);
    const toRef = doc(db, this.COLLECTIONS.MERCHANTS, toId);

    const fromSnap = await getDoc(fromRef);
    const toSnap = await getDoc(toRef);

    if (fromSnap.exists() && toSnap.exists()) {
      const fromData = fromSnap.data() as MerchantAccount;
      const toData = toSnap.data() as MerchantAccount;

      await updateDoc(fromRef, { earnings: fromData.earnings - amount });
      await updateDoc(toRef, { earnings: toData.earnings + amount });

      await this.addTransaction({
        id: txId,
        type: 'PAYMENT',
        amount: -amount,
        description: `B2B a ${toData.name}`,
        timestamp: new Date().toISOString(),
        status: 'COMPLETADA'
      });
    }
  }

  static async addTransaction(tx: Transaction): Promise<void> {
    const txCol = collection(db, this.COLLECTIONS.TRANSACTIONS);
    await addDoc(txCol, { ...tx, serverTimestamp: Timestamp.now() });
  }

  static async getTransactions(): Promise<Transaction[]> {
    const txCol = collection(db, this.COLLECTIONS.TRANSACTIONS);
    const q = query(txCol, orderBy('timestamp', 'desc'), limit(30));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => doc.data() as Transaction);
  }
}

import React, { useState, useEffect } from 'react';
import { AppRole, UserAccount, MerchantAccount, Product, Promotion, Transaction } from './types';
import { Logo } from './constants';
import UserView from './components/UserView';
import MerchantView from './components/MerchantView';
import AdminView from './components/AdminView';
import MarketplaceView from './components/MarketplaceView';
import MerchantInventory from './components/MerchantInventory';
import MerchantPromotions from './components/MerchantPromotions';
import PromotionsView from './components/PromotionsView';
import MapView from './components/MapView';
import CashierView from './components/CashierView';
import LoginView from './components/LoginView';
import WompiReceipt from './components/WompiReceipt';
import { PiggyRepository } from './repositories/piggyRepository';

type SubView = 'HOME' | 'MARKETPLACE' | 'PROMOTIONS' | 'MAP';

interface ReceiptState {
  transactionId: string;
  amount: number;
  reference: string;
  date: string;
  type: string;
}

const App: React.FC = () => {
  const [role, setRole] = useState<AppRole>(AppRole.USER);
  const [isLogged, setIsLogged] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<SubView>('HOME');
  const [marketplaceMerchantFilter, setMarketplaceMerchantFilter] = useState('Todos');
  const [receipt, setReceipt] = useState<ReceiptState | null>(null);

  // States synchronized with Repository
  const [user, setUser] = useState<UserAccount | null>(null);
  const [merchants, setMerchants] = useState<MerchantAccount[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);

  const currentMerchantId = 'roberto-pos';
  const merchant = merchants.find(m => m.id === currentMerchantId) || merchants[0];

  // Initial Data Load
  useEffect(() => {
    const loadInitialData = async () => {
      setIsLoading(true);
      try {
        const [userData, merchantList, txList] = await Promise.all([
          PiggyRepository.getUser(),
          PiggyRepository.getMerchants(),
          PiggyRepository.getTransactions()
        ]);
        setUser(userData);
        setMerchants(merchantList);
        setTransactions(txList);
      } catch (err) {
        console.error("Error loading cloud data:", err);
      } finally {
        setIsLoading(false);
      }
    };
    loadInitialData();
  }, []);

  const syncState = async () => {
    const [userData, merchantList, txList] = await Promise.all([
      PiggyRepository.getUser(user?.id),
      PiggyRepository.getMerchants(),
      PiggyRepository.getTransactions()
    ]);
    setUser(userData);
    setMerchants(merchantList);
    setTransactions(txList);
  };

  const products: Product[] = [
    { id: 'p1', merchantId: 'roberto-pos', merchantName: 'Don Roberto', name: 'Leche Deslactosada 1L', price: 4200, category: 'Alimentos', imageUrl: '🥛' },
    { id: 'p2', merchantId: 'roberto-pos', merchantName: 'Don Roberto', name: 'Pan Tajado Familiar', price: 5500, category: 'Alimentos', imageUrl: '🍞' },
    { id: 'p3', merchantId: 'roberto-pos', merchantName: 'Don Roberto', name: 'Huevos AA x30', price: 16000, category: 'Alimentos', imageUrl: '🥚' },
  ];

  const promotions: Promotion[] = [
    { id: 'promo-1', merchantId: 'roberto-pos', merchantName: 'Don Roberto', title: 'Pack Parrillero Familiar', description: 'Llévate todo para el asado.', piggyPrice: 15000, otherPrice: 35000, totalValue: 65000, imageUrl: '🥩', expiryDate: '12h 45m', category: 'Alimentos' }
  ];

  const handleTopUp = async (amount: number, txResult: any) => {
    await PiggyRepository.processTopUp(amount, txResult.id, txResult.reference, user?.id);
    await syncState();
    setReceipt({
      transactionId: txResult.id,
      amount,
      reference: txResult.reference,
      date: new Date().toLocaleString(),
      type: 'RECARGA WALLET'
    });
  };

  const handleSettlement = async (amount: number, txResult: any) => {
    const updatedMerchant = { ...merchant, cashCollected: 0, piggyPayments: 0 };
    await PiggyRepository.updateMerchant(updatedMerchant);
    await PiggyRepository.addTransaction({
      id: txResult.id,
      type: 'PAYMENT',
      amount: -amount,
      description: 'Liquidación de Caja Piggybanko',
      timestamp: new Date().toISOString(),
      status: 'COMPLETADA'
    });
    await syncState();
    setReceipt({
      transactionId: txResult.id,
      amount,
      reference: txResult.reference,
      date: new Date().toLocaleString(),
      type: 'LIQUIDACIÓN CAJA'
    });
  };

  const handleB2BTransfer = async (targetId: string, amount: number, txResult: any) => {
    await PiggyRepository.processB2B(merchant.id, targetId, amount, txResult.id);
    await syncState();
    setReceipt({
      transactionId: txResult.id,
      amount,
      reference: txResult.reference,
      date: new Date().toLocaleString(),
      type: `PAGO B2B: ${merchants.find(m => m.id === targetId)?.name}`
    });
  };

  const renderContent = () => {
    if (isLoading) return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] gap-4">
        <div className="loader-dots flex gap-2">
          <div className="w-4 h-4 bg-[#FF007F] rounded-full"></div>
          <div className="w-4 h-4 bg-[#1A1A40] rounded-full"></div>
          <div className="w-4 h-4 bg-[#CCFF00] rounded-full"></div>
        </div>
        <p className="text-[10px] font-black uppercase tracking-widest text-slate-300">Sincronizando con Piggy Cloud...</p>
      </div>
    );

    if (role === AppRole.CASHIER) return <CashierView merchantName={merchant.name} onProcessTransaction={() => true} mockUserBalance={user?.balance || 0} onGoHome={() => setActiveTab('HOME')} />;
    if (role === AppRole.USER && user) {
      switch(activeTab) {
        case 'MARKETPLACE': return <MarketplaceView products={products} userBalance={user.balance} initialMerchant={marketplaceMerchantFilter} />;
        case 'PROMOTIONS': return <PromotionsView promotions={promotions} userBalance={user.balance} />;
        case 'MAP': return <MapView merchants={merchants} userBalance={user.balance} onViewStore={(m) => {setMarketplaceMerchantFilter(m); setActiveTab('MARKETPLACE');}} />;
        default: return <UserView user={user} onGoHome={() => setActiveTab('HOME')} onTopUp={(amt, tx) => handleTopUp(amt, tx)} />;
      }
    }
    if (role === AppRole.MERCHANT) {
        switch(activeTab) {
          case 'MARKETPLACE': return <MerchantInventory products={products.filter(p => p.merchantId === merchant.id)} onAddProduct={() => {}} onRemoveProduct={() => {}} />;
          case 'PROMOTIONS': return <MerchantPromotions promotions={promotions} onAddPromotion={() => {}} onRemovePromotion={() => {}} />;
          default: return <MerchantView merchant={merchant} allMerchants={merchants} onGoHome={() => setActiveTab('HOME')} onMerchantPayUser={() => true} onSettlement={(amt, tx) => handleSettlement(amt, tx)} onB2BTransfer={(target, amt, tx) => handleB2BTransfer(target, amt, tx)} />;
        }
    }
    return <AdminView />;
  };

  if (!isLogged) return <LoginView onLogin={(r) => {setRole(r); setIsLogged(true);}} loginError={false} />;

  return (
    <div className="min-h-screen bg-white pt-8 overflow-x-hidden">
      {receipt && (
        <WompiReceipt 
          {...receipt} 
          onClose={() => setReceipt(null)} 
        />
      )}

      <div className="max-w-md md:max-w-4xl mx-auto px-4 flex justify-between items-center mb-8">
        <button onClick={() => setActiveTab('HOME')} className="hover:scale-105 active:scale-95 transition-transform"><Logo /></button>
        <button onClick={() => setIsLogged(false)} className="w-10 h-10 bg-white rounded-full shadow-md flex items-center justify-center text-slate-400 border border-slate-100"><i className="fa-solid fa-sign-out"></i></button>
      </div>

      <div className="animate-fadeIn">{renderContent()}</div>

      {(role === AppRole.USER || role === AppRole.MERCHANT) && (
        <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-[90%] max-w-sm bg-[#1A1A40] text-white rounded-3xl p-4 flex justify-between items-center shadow-2xl z-50">
          <button onClick={() => setActiveTab('HOME')} className={`flex flex-col items-center gap-1 ${activeTab === 'HOME' ? 'text-[#FF007F]' : 'opacity-50'}`}><i className="fa-solid fa-house"></i><span className="text-[10px]">Inicio</span></button>
          <button onClick={() => setActiveTab('MARKETPLACE')} className={`flex flex-col items-center gap-1 ${activeTab === 'MARKETPLACE' ? 'text-[#FF007F]' : 'opacity-50'}`}><i className="fa-solid fa-store"></i><span className="text-[10px]">Tienda</span></button>
          <div className="relative -top-10"><button className="w-14 h-14 bg-[#FF007F] rounded-full flex items-center justify-center text-white border-4 border-white shadow-xl shadow-pink-500/20 active:scale-90 transition-all"><i className="fa-solid fa-qrcode text-xl"></i></button></div>
          <button onClick={() => setActiveTab('PROMOTIONS')} className={`flex flex-col items-center gap-1 ${activeTab === 'PROMOTIONS' ? 'text-[#FF007F]' : 'opacity-50'}`}><i className="fa-solid fa-tags"></i><span className="text-[10px]">Promos</span></button>
          <button onClick={() => setActiveTab('MAP')} className={`flex flex-col items-center gap-1 ${activeTab === 'MAP' ? 'text-[#FF007F]' : 'opacity-50'}`}><i className="fa-solid fa-map-location-dot"></i><span className="text-[10px]">Mapa</span></button>
        </div>
      )}
    </div>
  );
};

export default App;

