import { Logo } from './constants';
import UserView from './components/UserView';
import MerchantView from './components/MerchantView';
import AdminView from './components/AdminView';
import MarketplaceView from './components/MarketplaceView';
import PromotionsView from './components/PromotionsView';
import MapView from './components/MapView';
import CashierView from './components/CashierView';
import LoginView from './components/LoginView';
import WompiReceipt from './components/WompiReceipt';
import { PiggyRepository } from './repositories/piggyRepository';

const App: React.FC = () => {
  const [role, setRole] = useState<AppRole>(AppRole.USER);
  const [isLogged, setIsLogged] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'HOME' | 'MARKETPLACE' | 'PROMOTIONS' | 'MAP'>('HOME');
  const [receipt, setReceipt] = useState<any>(null);

  // Firestore Live State
  const [user, setUser] = useState<UserAccount | null>(null);
  const [merchants, setMerchants] = useState<MerchantAccount[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);

  // Efecto para conectar los Listeners de Firebase
  useEffect(() => {
    let unsubscribeUser: () => void;
    let unsubscribeTxs: () => void;

    const startCloudSync = async () => {
      setIsLoading(true);
      try {
        // 1. Cargar comercios (datos más estáticos)
        const merchantList = await PiggyRepository.getMerchants();
        setMerchants(merchantList);

        // 2. Suscribirse al usuario real (cambia con pagos/recargas)
        unsubscribeUser = PiggyRepository.subscribeToUser('valen-001', (userData) => {
          setUser(userData);
          setIsLoading(false);
        });

        // 3. Suscribirse al feed de transacciones
        unsubscribeTxs = PiggyRepository.subscribeToTransactions((txList) => {
          setTransactions(txList);
        });

      } catch (err) {
        console.error("Cloud Sync Error:", err);
        setIsLoading(false);
      }
    };

    startCloudSync();

    // Limpiar conexiones al desmontar
    return () => {
      if (unsubscribeUser) unsubscribeUser();
      if (unsubscribeTxs) unsubscribeTxs();
    };
  }, []);

  const handleTopUp = async (amount: number, txResult: any) => {
    // Ya no necesitamos llamar a syncState(), Firebase lo hará solo por el listener
    await PiggyRepository.processTopUp(amount, txResult.id, txResult.reference, user?.id);
    setReceipt({
      transactionId: txResult.id,
      amount,
      reference: txResult.reference,
      date: new Date().toLocaleString(),
      type: 'RECARGA WALLET'
    });
  };

  if (!isLogged) return <LoginView onLogin={(r) => {setRole(r); setIsLogged(true);}} loginError={false} />;

  return (
    <div className="min-h-screen bg-white pt-8 overflow-x-hidden">
      {receipt && <WompiReceipt {...receipt} onClose={() => setReceipt(null)} />}

      {isLoading ? (
        <div className="flex flex-col items-center justify-center min-h-[80vh]">
          <div className="loader-dots flex gap-2 mb-4">
            <div className="w-4 h-4 bg-[#FF007F] rounded-full"></div>
            <div className="w-4 h-4 bg-[#1A1A40] rounded-full"></div>
          </div>
          <p className="text-[10px] font-black uppercase tracking-widest text-slate-300">Conectando a Piggy Real-Time...</p>
        </div>
      ) : (
        <>
          <div className="max-w-md md:max-w-4xl mx-auto px-4 flex justify-between items-center mb-8">
            <button onClick={() => setActiveTab('HOME')}><Logo /></button>
            <button onClick={() => setIsLogged(false)} className="text-slate-400"><i className="fa-solid fa-sign-out"></i></button>
          </div>

          <div className="animate-fadeIn">
            {role === AppRole.USER && user && (
              activeTab === 'HOME' ? <UserView user={user} onGoHome={() => setActiveTab('HOME')} onTopUp={handleTopUp} /> :
              activeTab === 'MARKETPLACE' ? <MarketplaceView products={[]} userBalance={user.balance} /> :
              activeTab === 'MAP' ? <MapView merchants={merchants} userBalance={user.balance} onViewStore={() => setActiveTab('MARKETPLACE')} /> :
              <PromotionsView promotions={[]} userBalance={user.balance} />
            )}
            {role === AppRole.MERCHANT && merchants.length > 0 && (
              <MerchantView 
                merchant={merchants[0]} 
                allMerchants={merchants} 
                onGoHome={() => setActiveTab('HOME')} 
                onMerchantPayUser={() => true}
                onSettlement={() => {}} 
              />
            )}
          </div>

          <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-[90%] max-w-sm bg-[#1A1A40] text-white rounded-3xl p-4 flex justify-between items-center shadow-2xl z-50">
            <button onClick={() => setActiveTab('HOME')} className={activeTab === 'HOME' ? 'text-[#FF007F]' : 'opacity-50'}><i className="fa-solid fa-house"></i></button>
            <button onClick={() => setActiveTab('MARKETPLACE')} className={activeTab === 'MARKETPLACE' ? 'text-[#FF007F]' : 'opacity-50'}><i className="fa-solid fa-store"></i></button>
            <div className="relative -top-10"><button className="w-14 h-14 bg-[#FF007F] rounded-full border-4 border-white"><i className="fa-solid fa-qrcode"></i></button></div>
            <button onClick={() => setActiveTab('PROMOTIONS')} className={activeTab === 'PROMOTIONS' ? 'text-[#FF007F]' : 'opacity-50'}><i className="fa-solid fa-tags"></i></button>
            <button onClick={() => setActiveTab('MAP')} className={activeTab === 'MAP' ? 'text-[#FF007F]' : 'opacity-50'}><i className="fa-solid fa-map-location-dot"></i></button>
          </div>
        </>
      )}
    </div>
  );
};

export default App;

import { 
  collection, 
  doc, 
  getDoc, 
  getDocs, 
  setDoc, 
  updateDoc, 
  query, 
  orderBy, 
  limit, 
  addDoc,
  onSnapshot,
  Timestamp
} from 'firebase/firestore';
import { db } from '../services/firebaseService';
import { UserAccount, MerchantAccount, Transaction } from '../types';

export class PiggyRepository {
  private static COLLECTIONS = {
    USERS: 'users',
    MERCHANTS: 'merchants',
    TRANSACTIONS: 'transactions'
  };

  // --- LISTENERS (Tiempo Real) ---

  /**
   * Escucha cambios en el usuario (saldo, nivel, meta)
   */
  static subscribeToUser(userId: string, callback: (user: UserAccount) => void) {
    const userRef = doc(db, this.COLLECTIONS.USERS, userId);
    return onSnapshot(userRef, (docSnap) => {
      if (docSnap.exists()) {
        callback(docSnap.data() as UserAccount);
      }
    });
  }

  /**
   * Escucha nuevas transacciones en tiempo real
   */
  static subscribeToTransactions(callback: (txs: Transaction[]) => void) {
    const txCol = collection(db, this.COLLECTIONS.TRANSACTIONS);
    const q = query(txCol, orderBy('timestamp', 'desc'), limit(30));

    return onSnapshot(q, (snapshot) => {
      const txs = snapshot.docs.map(doc => doc.data() as Transaction);
      callback(txs);
    });
  }

  // --- MÉTODOS ASÍNCRONOS ---

  // Fix for Error in file components/UserView.tsx: Property 'getTransactions' does not exist
  static async getTransactions(): Promise<Transaction[]> {
    const txCol = collection(db, this.COLLECTIONS.TRANSACTIONS);
    const q = query(txCol, orderBy('timestamp', 'desc'), limit(30));
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => doc.data() as Transaction);
  }

  static async getUser(userId: string = 'valen-001'): Promise<UserAccount> {
    const userRef = doc(db, this.COLLECTIONS.USERS, userId);
    const userSnap = await getDoc(userRef);
    if (userSnap.exists()) return userSnap.data() as UserAccount;

    const defaultUser: UserAccount = {
      id: userId, phone: '3001234567', balance: 45350, xp: 650, level: 2, 
      goalName: 'Tenis Nike Air', goalTarget: 70000, lastYield: 5
    };
    await setDoc(userRef, defaultUser);
    return defaultUser;
  }

  static async updateUser(user: UserAccount): Promise<void> {
    const userRef = doc(db, this.COLLECTIONS.USERS, user.id);
    await setDoc(userRef, user, { merge: true });
  }

  static async getMerchants(): Promise<MerchantAccount[]> {
    const merchantsCol = collection(db, this.COLLECTIONS.MERCHANTS);
    const snapshot = await getDocs(merchantsCol);
    return snapshot.docs.map(doc => doc.data() as MerchantAccount);
  }

  static async updateMerchant(merchant: MerchantAccount): Promise<void> {
    const merchantRef = doc(db, this.COLLECTIONS.MERCHANTS, merchant.id);
    await setDoc(merchantRef, merchant, { merge: true });
  }

  static async processTopUp(amount: number, txId: string, reference: string, userId: string = 'valen-001'): Promise<void> {
    const user = await this.getUser(userId);
    user.balance += amount;
    user.xp += 100;

    await this.updateUser(user);
    await this.addTransaction({
      id: txId,
      type: 'YIELD',
      amount: amount,
      description: 'Recarga Wompi Pay',
      timestamp: new Date().toISOString(),
      status: 'COMPLETADA'
    });
  }

  static async addTransaction(tx: Transaction): Promise<void> {
    const txCol = collection(db, this.COLLECTIONS.TRANSACTIONS);
    await addDoc(txCol, { ...tx, serverTimestamp: Timestamp.now() });
  }
}
